@dataclass
class PartParameter:
    """Professional product part parameter definition."""

    name: str = "Parameter"
    value: object = 0.0
    unit: str = ""
    expression: str = ""
    description: str = ""
    read_only: bool = False
    owner_id: str = ""
    group_id: str = ""
    metadata: ParameterMetadata = field(default_factory=ParameterMetadata)
    id: str = field(default_factory=lambda: str(uuid4()))

    def to_dict(self):
        """Return JSON-safe parameter data."""

        return {
            "id": self.id,
            "name": self.name,
            "value": self.value,
            "unit": self.unit,
            "expression": self.expression,
            "description": self.description,
            "read_only": self.read_only,
            "owner_id": self.owner_id,
            "group_id": self.group_id,
            "metadata": self.metadata.to_dict(),
        }

    @staticmethod
    def from_dict(data):
        """Create a part parameter from persisted data."""

        data = data or {}
        parameter_class = data.get("parameter_class", "")

        if parameter_class:
            return _parameter_from_data(data)

        return PartParameter(
            data.get("name", "Parameter"),
            data.get("value", 0.0),
            data.get("unit", ""),
            data.get("expression", ""),
            data.get("description", ""),
            bool(data.get("read_only", False)),
            data.get("owner_id", ""),
            data.get("group_id", ""),
            ParameterMetadata.from_dict(data.get("metadata", {})),
            data.get("id", str(uuid4())),
        )


class Parameter(PartParameter):
    """Professional parametric parameter metadata; no evaluation is performed."""

    type_name = "Parameter"
    is_3d = True
    is_product = True
    is_parametric_parameter = True

    def __init__(
        self,
        name="Parameter",
        value=0.0,
        parameter_type="Float",
        scope="Local",
        owner_id="",
        unit="",
        expression="",
        description="",
        read_only=False,
        group_id="",
        category_id="",
        metadata=None,
        id=None,
    ):

        super().__init__(
            name,
            value,
            unit,
            expression,
            description,
            read_only,
            owner_id,
            group_id,
            metadata or ParameterMetadata(source="Parametric"),
            id or str(uuid4()),
        )
        self.parameter_type = parameter_type
        self.scope = scope
        self.category_id = category_id
        self.binding_ids = []
        self.expression_id = ""
        self.object_reference_id = ""
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#42a5f5"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe parametric parameter metadata."""

        data = super().to_dict()
        data.update({
            "parameter_class": self.__class__.__name__,
            "parameter_type": self.parameter_type,
            "scope": self.scope,
            "category_id": self.category_id,
            "binding_ids": list(self.binding_ids),
            "expression_id": self.expression_id,
            "object_reference_id": self.object_reference_id,
            "visible": self.visible,
            "locked": self.locked,
            "selected": self.selected,
            "layer_name": self.layer_name,
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })
        return data

    def segments(self):
        """Return no drawable geometry for metadata-only parameters."""

        return []

    def points(self):
        """Return no drawable points for metadata-only parameters."""

        return []

    @staticmethod
    def from_dict(data):
        """Create a parametric parameter from persisted data."""

        return _parameter_from_data(data)


