class Expression:
    """Expression metadata record; expression text is stored but never executed."""

    type_name = "Expression"
    is_3d = True
    is_product = True
    is_expression = True

    def __init__(self, name="Expression", text="", unit="", context=None, flags=None):

        self.id = str(uuid4())
        self.name = name
        self.text = text
        self.unit = unit
        self.context = context or ExpressionContext(unit=unit)
        self.flags = flags or ExpressionFlags()
        self.validation_state = "Not Parsed"
        self.evaluation_state = "Not Evaluated"
        self.reference_ids = []
        self.binding_ids = []
        self.history_ids = []
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ffb74d"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe expression metadata."""

        return _product_marker_data(self, {
            "text": self.text,
            "unit": self.unit,
            "context": self.context.to_dict(),
            "flags": self.flags.to_dict(),
            "validation_state": self.validation_state,
            "evaluation_state": self.evaluation_state,
            "reference_ids": list(self.reference_ids),
            "binding_ids": list(self.binding_ids),
            "history_ids": list(self.history_ids),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create expression metadata."""

        data = data or {}
        item = Expression(
            data.get("name", "Expression"),
            data.get("text", ""),
            data.get("unit", ""),
            ExpressionContext.from_dict(data.get("context", {})),
            ExpressionFlags.from_dict(data.get("flags", {})),
        )
        item.id = data.get("id", str(uuid4()))
        item.validation_state = data.get("validation_state", "Not Parsed")
        item.evaluation_state = data.get("evaluation_state", "Not Evaluated")
        item.reference_ids = list(data.get("reference_ids", []))
        item.binding_ids = list(data.get("binding_ids", []))
        item.history_ids = list(data.get("history_ids", []))
        _restore_marker_state(item, data)
        item.display_color = data.get("display_color", "#ffb74d")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def segments(self):
        return []

    def points(self):
        return []


