class ExpressionBinding:
    """Binding metadata between parameters, expressions and existing product objects."""

    type_name = "ExpressionBinding"
    is_3d = True
    is_product = True
    is_expression_binding = True

    def __init__(self, name="Expression Binding", source_id="", target_id="", binding_type="ParameterToExpression", expression_id="", metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.source_id = source_id
        self.target_id = target_id
        self.binding_type = binding_type
        self.expression_id = expression_id
        self.metadata = metadata or ParameterMetadata(source="Parametric Binding")
        self.future_solver_reference_id = ""
        self.future_graph_reference_id = ""
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#26c6da"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe expression binding metadata."""

        return _product_marker_data(self, {
            "source_id": self.source_id,
            "target_id": self.target_id,
            "binding_type": self.binding_type,
            "expression_id": self.expression_id,
            "metadata": self.metadata.to_dict(),
            "future_solver_reference_id": self.future_solver_reference_id,
            "future_graph_reference_id": self.future_graph_reference_id,
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create expression binding metadata."""

        data = data or {}
        item = ExpressionBinding(
            data.get("name", "Expression Binding"),
            data.get("source_id", ""),
            data.get("target_id", ""),
            data.get("binding_type", "ParameterToExpression"),
            data.get("expression_id", ""),
            ParameterMetadata.from_dict(data.get("metadata", {})),
        )
        item.id = data.get("id", str(uuid4()))
        item.future_solver_reference_id = data.get("future_solver_reference_id", "")
        item.future_graph_reference_id = data.get("future_graph_reference_id", "")
        _restore_marker_state(item, data)
        item.display_color = data.get("display_color", "#26c6da")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def segments(self):
        return []

    def points(self):
        return []


