class Sketch:
    """Product sketch containing sketch-owned geometry, dimensions and constraints."""

    type_name = "Sketch"
    is_3d = True
    is_product = True
    is_sketch = True

    def __init__(self, name="Sketch", part_id="", plane_id="", metadata=None, location=None):

        self.id = str(uuid4())
        self.name = name
        self.part_id = part_id
        self.plane_id = plane_id
        self.metadata = metadata or SketchMetadata()
        self.location = location or Vector3()
        self.profile_ids = []
        self.geometry_ids = []
        self.constraint_ids = []
        self.dimension_ids = []
        self.active = False
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#26c6da"

    def to_dict(self):
        """Return JSON-safe sketch data."""

        return _product_marker_data(self, {
            "part_id": self.part_id,
            "plane_id": self.plane_id,
            "metadata": self.metadata.to_dict(),
            "location": _vector_to_data(self.location),
            "profile_ids": list(self.profile_ids),
            "geometry_ids": list(self.geometry_ids),
            "constraint_ids": list(self.constraint_ids),
            "dimension_ids": list(self.dimension_ids),
            "active": self.active,
            "display_color": self.display_color,
        })

    @staticmethod
    def from_dict(data):
        """Create a sketch from persisted data."""

        data = data or {}
        sketch = Sketch(
            data.get("name", "Sketch"),
            data.get("part_id", ""),
            data.get("plane_id", ""),
            SketchMetadata.from_dict(data.get("metadata", {})),
            _vector_from_data(data.get("location", {})),
        )
        _restore_product_marker(sketch, data)
        sketch.profile_ids = list(data.get("profile_ids", []))
        sketch.geometry_ids = list(data.get("geometry_ids", []))
        sketch.constraint_ids = list(data.get("constraint_ids", []))
        sketch.dimension_ids = list(data.get("dimension_ids", []))
        sketch.active = bool(data.get("active", False))
        sketch.display_color = data.get("display_color", "#26c6da")

        return sketch

    def points(self):
        """Return a stable sketch marker point."""

        return [self.location]

    def segments(self):
        """Return a lightweight sketch plane marker."""

        size = 0.35
        point = self.location

        return [
            (Vector3(point.x - size, point.y - size, point.z), Vector3(point.x + size, point.y - size, point.z)),
            (Vector3(point.x + size, point.y - size, point.z), Vector3(point.x + size, point.y + size, point.z)),
            (Vector3(point.x + size, point.y + size, point.z), Vector3(point.x - size, point.y + size, point.z)),
            (Vector3(point.x - size, point.y + size, point.z), Vector3(point.x - size, point.y - size, point.z)),
        ]


