class SketchGeometry:
    """Base sketch-owned geometry record; it never creates MeshEntity geometry."""

    type_name = "SketchGeometry"
    geometry_type = "Geometry"
    is_3d = True
    is_product = True
    is_sketch_geometry = True

    def __init__(self, name="Sketch Geometry", sketch_id="", points=None, construction=False):

        self.id = str(uuid4())
        self.name = name
        self.sketch_id = sketch_id
        self.points_data = list(points or [])
        self.construction = bool(construction)
        self.centerline = False
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#80deea" if self.construction else "#ffffff"

    def to_dict(self):
        """Return JSON-safe sketch geometry data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "geometry_type": self.geometry_type,
            "sketch_id": self.sketch_id,
            "points": [_vector_to_data(point) for point in self.points_data],
            "construction": self.construction,
            "centerline": self.centerline,
            "display_color": self.display_color,
        })

    @staticmethod
    def from_dict(data):
        """Create sketch geometry from persisted data."""

        return _sketch_geometry_from_data(data)

    def points(self):
        """Return display points for renderer overlays."""

        return list(self.points_data)

    def segments(self):
        """Return display segments for renderer overlays."""

        return [
            (self.points_data[index], self.points_data[index + 1])
            for index in range(max(0, len(self.points_data) - 1))
        ]


