class SketchPolyline(SketchGeometry):
    """Sketch-owned polyline foundation."""

    type_name = "SketchPolyline"
    geometry_type = "Polyline"

    def __init__(self, name="Sketch Polyline", sketch_id="", vertices=None, closed=False, construction=False):

        self.closed = bool(closed)
        super().__init__(name, sketch_id, vertices or [Vector3(), Vector3(1.0, 0.0, 0.0)], construction)

    def to_dict(self):
        """Return JSON-safe polyline data."""

        data = super().to_dict()
        data["closed"] = self.closed
        return data

    def segments(self):
        """Return display segments including the closing segment when needed."""

        segments = super().segments()
        if self.closed and len(self.points_data) > 2:
            segments.append((self.points_data[-1], self.points_data[0]))
        return segments


class SketchRectangle(SketchPolyline):
    """Sketch-owned rectangle represented by four sketch vertices."""

    type_name = "SketchRectangle"
    geometry_type = "Rectangle"

    def __init__(self, name="Sketch Rectangle", sketch_id="", corner1=None, corner2=None, construction=False):

        first = corner1 or Vector3()
        second = corner2 or Vector3(1.0, 1.0, 0.0)
        vertices = [
            first,
            Vector3(second.x, first.y, first.z),
            second,
            Vector3(first.x, second.y, first.z),
        ]
        super().__init__(name, sketch_id, vertices, True, construction)


