class ComponentManager:
    """Project-scoped component helper."""

    DEFAULT_CATEGORIES = (
        "Mechanical Parts",
        "Purchased Parts",
        "Custom Parts",
        "Standard Parts",
        "Reference Parts",
    )

    def __init__(self, manager):

        self.manager = manager

    def ensure_default_categories(self):
        """Create default component categories."""

        existing = {category.name for category in self.manager.component_categories}

        for name in self.DEFAULT_CATEGORIES:
            if name not in existing:
                self.manager.component_categories.append(ComponentCategory(name))

        self.manager.statistics()
        return self.manager.component_categories

    def add_item(self, item):
        """Add component metadata to the product manager."""

        if isinstance(item, ComponentCategory):
            collection = self.manager.component_categories
        elif isinstance(item, ComponentType):
            collection = self.manager.component_types
        elif isinstance(item, Component):
            collection = self.manager.components
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.manager.statistics()
        return item

    def components_for(self, part):
        """Return components assigned to a product part."""

        part_id = getattr(part, "id", part)

        return [
            component for component in self.manager.components
            if component.part_id == part_id
        ]

    def type_for(self, component):
        """Return the component type for a component."""

        return _find_by_id(self.manager.component_types, getattr(component, "component_type_id", ""))

    def category_for(self, item):
        """Return the component category for a component or type."""

        category_id = getattr(item, "category_id", "")

        if not category_id and isinstance(item, Component):
            component_type = self.type_for(item)
            category_id = getattr(component_type, "category_id", "")

        return _find_by_id(self.manager.component_categories, category_id)

    def _refresh_links(self, item):
        if not isinstance(item, Component):
            return

        part = self.manager.part_for(item.part_id)

        if part is not None and item.id not in part.component_ids:
            part.component_ids.append(item.id)


class ParameterManager:
    """Project-scoped Product Design parameter helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add parameter metadata to ProductManager."""

        if isinstance(item, PartParameter):
            collection = self.manager.parameters
        elif isinstance(item, ParameterGroup):
            collection = self.manager.parameter_groups
        elif isinstance(item, ParameterSet):
            collection = self.manager.parameter_sets
        elif isinstance(item, ParameterCategory):
            collection = self.manager.parameter_categories
        elif isinstance(item, Expression):
            collection = self.manager.expressions
        elif isinstance(item, ExpressionTree):
            collection = self.manager.expression_trees
        elif isinstance(item, ExpressionReference):
            collection = self.manager.expression_references
        elif isinstance(item, ExpressionBinding):
            collection = self.manager.expression_bindings
        elif isinstance(item, ExpressionContext):
            collection = self.manager.expression_contexts
        elif isinstance(item, ExpressionHistory):
            collection = self.manager.expression_histories
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def parameters_for(self, owner):
        """Return parameters assigned to a product part or parameter set."""

        owner_id = getattr(owner, "id", owner)
        parameter_ids = set(getattr(owner, "parameter_ids", []))

        if isinstance(owner, ParameterSet):
            parameter_ids.update(owner.parameter_ids)

        return [
            parameter for parameter in self.manager.parameters
            if parameter.owner_id == owner_id or parameter.id in parameter_ids
        ]

    def sets_for(self, part):
        """Return parameter sets assigned to a product part."""

        part_id = getattr(part, "id", part)
        set_ids = set(getattr(part, "parameter_set_ids", []))

        return [
            parameter_set for parameter_set in self.manager.parameter_sets
            if parameter_set.owner_id == part_id or parameter_set.id in set_ids
        ]

    def groups_for(self, owner):
        """Return parameter groups assigned to an owner."""

        owner_id = getattr(owner, "id", owner)

        return [
            group for group in self.manager.parameter_groups
            if group.owner_id == owner_id
        ]

    def create_parameter(self, name="Parameter", value=0.0, parameter_type="Float", owner=None, scope="Local", **kwargs):
        """Create parametric parameter metadata without evaluating it."""

        class_map = {
            "Global": GlobalParameter,
            "Local": LocalParameter,
            "Document": DocumentParameter,
            "Feature": FeatureParameter,
            "Configuration": ConfigurationParameter,
            "Reference": ReferenceParameter,
            "Computed": ComputedParameter,
        }
        parameter_class = class_map.get(scope, Parameter)
        parameter = parameter_class(
            name,
            value,
            parameter_type=parameter_type,
            owner_id=getattr(owner, "id", owner) or "",
            unit=kwargs.get("unit", ""),
            expression=kwargs.get("expression", ""),
            description=kwargs.get("description", ""),
            read_only=bool(kwargs.get("read_only", False)),
            group_id=getattr(kwargs.get("group"), "id", kwargs.get("group_id", "")) or "",
            category_id=getattr(kwargs.get("category"), "id", kwargs.get("category_id", "")) or "",
            metadata=kwargs.get("metadata"),
        )
        return self.add_item(parameter)

    def create_expression(self, name="Expression", text="", parameter=None, references=None, objects=None, unit="", **kwargs):
        """Create expression metadata only; no parsing or execution occurs."""

        context = ExpressionContext(
            kwargs.get("document_id", ""),
            getattr(parameter, "id", parameter) or "",
            kwargs.get("owner_id", ""),
            unit,
            [getattr(item, "id", item) for item in references or []],
            [getattr(item, "id", item) for item in objects or []],
            dict(kwargs.get("properties", {})),
        )
        expression = Expression(name, text, unit, context)
        expression.validation_state = kwargs.get("validation_state", "Not Parsed")
        expression.evaluation_state = kwargs.get("evaluation_state", "Not Evaluated")
        expression.reference_ids = context.referenced_parameter_ids + context.referenced_object_ids
        self.add_item(expression)

        target = self.parameter_for(parameter)
        if target is not None:
            target.expression_id = expression.id
            self.manager.dependency_manager.add_edge(target, expression, "ParameterExpressionReference")

        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, expression, "ExpressionParameterReference")
        for obj in objects or []:
            self.manager.dependency_manager.add_edge(obj, expression, "ExpressionObjectReference")

        return expression

    def bind_parameter(self, source, target, binding_type="ParameterToParameter", expression=None, name="Expression Binding"):
        """Store a parameter binding relationship without propagation."""

        binding = ExpressionBinding(
            name,
            getattr(source, "id", source) or "",
            getattr(target, "id", target) or "",
            binding_type,
            getattr(expression, "id", expression) or "",
        )
        self.add_item(binding)
        self.manager.dependency_manager.add_edge(source, target, binding_type)
        if expression is not None:
            self.manager.dependency_manager.add_edge(expression, binding, "ExpressionBindingReference")
        return binding

    def parameter_for(self, parameter):
        """Return a parameter by object, ID or name."""

        if isinstance(parameter, PartParameter):
            return parameter if parameter in self.manager.parameters else None
        return _find_by_id_or_name(self.manager.parameters, parameter)

    def expressions_for(self, parameter):
        """Return expressions assigned to a parameter."""

        parameter_id = getattr(parameter, "id", parameter)
        return [
            expression for expression in self.manager.expressions
            if expression.context.parameter_id == parameter_id or parameter_id in expression.context.referenced_parameter_ids
        ]

    def bindings_for(self, item):
        """Return bindings assigned to a parameter or object."""

        item_id = getattr(item, "id", item)
        return [
            binding for binding in self.manager.expression_bindings
            if binding.source_id == item_id or binding.target_id == item_id or binding.expression_id == item_id
        ]

    def visible_objects(self):
        """Return visible parameter and expression records for selection/rendering."""

        if not self.manager.visible:
            return []

        return [
            item for item in (
                self.manager.parameters +
                self.manager.parameter_categories +
                self.manager.expressions +
                self.manager.expression_bindings
            )
            if getattr(item, "visible", False)
        ]

    def statistics(self):
        """Return parameter statistics."""

        stats = ParameterStatistics(
            len(self.manager.parameters),
            len(self.manager.parameter_groups),
            len(self.manager.parameter_sets),
            len([parameter for parameter in self.manager.parameters if parameter.read_only]),
            len(self.manager.parameter_categories),
            len(self.manager.expressions),
            len(self.manager.expression_bindings),
            len([parameter for parameter in self.manager.parameters if getattr(parameter, "scope", "") == "Global"]),
            len([parameter for parameter in self.manager.parameters if getattr(parameter, "scope", "") == "Local"]),
            len([parameter for parameter in self.manager.parameters if getattr(parameter, "scope", "") == "Computed"]),
        )
        self.manager.parameter_statistics = stats
        self.manager.expression_statistics = ExpressionStatistics(
            len(self.manager.expressions),
            len(self.manager.expression_trees),
            len(self.manager.expression_references),
            len(self.manager.expression_bindings),
            len(self.manager.expression_contexts),
            len(self.manager.expression_histories),
        )

        return stats

    def _refresh_links(self, item):
        if isinstance(item, PartParameter):
            part = self.manager.part_for(item.owner_id)
            if part is not None and item.id not in part.parameter_ids:
                part.parameter_ids.append(item.id)
            group = _find_by_id(self.manager.parameter_groups, item.group_id)
            if group is not None and item.id not in group.parameter_ids:
                group.parameter_ids.append(item.id)
            category = _find_by_id(self.manager.parameter_categories, getattr(item, "category_id", ""))
            if category is not None and item.id not in category.parameter_ids:
                category.parameter_ids.append(item.id)
        elif isinstance(item, ParameterSet):
            part = self.manager.part_for(item.owner_id)
            if part is not None and item.id not in part.parameter_set_ids:
                part.parameter_set_ids.append(item.id)
        elif isinstance(item, ExpressionBinding):
            source = self.parameter_for(item.source_id)
            if source is not None and item.id not in getattr(source, "binding_ids", []):
                source.binding_ids.append(item.id)
            expression = _find_by_id(self.manager.expressions, item.expression_id)
            if expression is not None and item.id not in expression.binding_ids:
                expression.binding_ids.append(item.id)
        elif isinstance(item, ExpressionHistory):
            expression = _find_by_id(self.manager.expressions, item.expression_id)
            if expression is not None and item.id not in expression.history_ids:
                expression.history_ids.append(item.id)


class EngineeringMaterialManager:
    """Project-scoped engineering material helper using ProductManager storage."""

    DEFAULT_CATEGORIES = (
        ("Steel", "#90a4ae"),
        ("Aluminium", "#b0bec5"),
        ("Copper", "#ff8a65"),
        ("Brass", "#d4af37"),
        ("Titanium", "#cfd8dc"),
        ("Plastic", "#4dd0e1"),
        ("Wood", "#a1887f"),
        ("Composite", "#9575cd"),
        ("Glass", "#81d4fa"),
        ("Custom Material", "#b0bec5"),
    )

    def __init__(self, manager):

        self.manager = manager

    def ensure_default_categories(self):
        """Create default engineering material categories."""

        existing = {category.name for category in self.manager.material_categories}

        for name, color in self.DEFAULT_CATEGORIES:
            if name not in existing:
                self.manager.material_categories.append(MaterialCategory(name, color))

        self.statistics()
        return self.manager.material_categories

    def add_item(self, item):
        """Add engineering material metadata."""

        if isinstance(item, MaterialCategory):
            collection = self.manager.material_categories
        elif isinstance(item, MaterialGrade):
            collection = self.manager.material_grades
        elif isinstance(item, MaterialSpecification):
            collection = self.manager.material_specifications
        elif isinstance(item, EngineeringMaterial):
            collection = self.manager.engineering_materials
        else:
            return None

        if item not in collection:
            collection.append(item)

        self.statistics()
        return item

    def assign_material(self, part, material):
        """Assign an engineering material to a product part."""

        target = self.manager.part_for(part)
        material_item = self.material_for(material)

        if target is None or material_item is None:
            return None

        target.engineering_material_id = material_item.id
        target.metadata.material = material_item.name
        self.statistics()

        return material_item

    def material_for(self, material):
        """Return an engineering material by object, id or name."""

        if isinstance(material, EngineeringMaterial):
            return material if material in self.manager.engineering_materials else None

        return _find_by_id_or_name(self.manager.engineering_materials, material)

    def material_for_part(self, part):
        """Return the engineering material assigned to a product part."""

        material_id = getattr(part, "engineering_material_id", "")

        if not material_id:
            return None

        return self.material_for(material_id)

    def category_for(self, material):
        """Return a material category."""

        return _find_by_id(self.manager.material_categories, getattr(material, "category_id", ""))

    def statistics(self):
        """Return material statistics."""

        stats = MaterialStatistics(
            len(self.manager.engineering_materials),
            len(self.manager.material_categories),
            len(self.manager.material_grades),
            len(self.manager.material_specifications),
        )
        self.manager.material_statistics = stats

        return stats


class SketchManager:
    """Project-scoped sketch helper owned by ProductManager."""

    def __init__(self, manager):

        self.manager = manager

    def create_sketch(self, name="Sketch", part=None, plane=None, metadata=None):
        """Create and store a sketch for a product part."""

        part_id = getattr(part, "id", part) or ""
        plane_id = getattr(plane, "id", plane) or ""
        sketch = Sketch(name, part_id, plane_id, metadata)
        self.add_item(sketch)

        return sketch

    def add_item(self, item):
        """Add sketch metadata to ProductManager."""

        collection = self._collection_for(item)

        if collection is None:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def remove_item(self, item):
        """Remove sketch metadata from ProductManager."""

        collection = self._collection_for(item)

        if collection is None or item not in collection:
            return False

        collection.remove(item)
        self._unlink(item)
        self.statistics()

        return True

    def activate(self, sketch):
        """Activate one sketch and deactivate all other sketches."""

        target = self.sketch_for(sketch)

        if target is None:
            return None

        for item in self.manager.sketches:
            item.active = item is target

        self.manager.active_sketch_id = target.id
        return target

    def deactivate(self):
        """Deactivate the current sketch."""

        for item in self.manager.sketches:
            item.active = False

        self.manager.active_sketch_id = None

    def sketch_for(self, sketch):
        """Return a sketch by object, id or name."""

        if isinstance(sketch, Sketch):
            return sketch if sketch in self.manager.sketches else None

        return _find_by_id_or_name(self.manager.sketches, sketch)

    def sketches_for_part(self, part):
        """Return sketches assigned to a product part."""

        part_id = getattr(part, "id", part)

        return [
            sketch for sketch in self.manager.sketches
            if sketch.part_id == part_id
        ]

    def geometry_for(self, sketch):
        """Return geometry owned by a sketch."""

        sketch_id = getattr(sketch, "id", sketch)
        ids = set(getattr(sketch, "geometry_ids", []))

        return [
            item for item in self.manager.sketch_geometry
            if item.sketch_id == sketch_id or item.id in ids
        ]

    def constraints_for(self, sketch):
        """Return constraints owned by a sketch."""

        sketch_id = getattr(sketch, "id", sketch)
        ids = set(getattr(sketch, "constraint_ids", []))

        return [
            item for item in self.manager.sketch_constraints
            if item.sketch_id == sketch_id or item.id in ids
        ]

    def dimensions_for(self, sketch):
        """Return dimensions owned by a sketch."""

        sketch_id = getattr(sketch, "id", sketch)
        ids = set(getattr(sketch, "dimension_ids", []))

        return [
            item for item in self.manager.sketch_dimensions
            if item.sketch_id == sketch_id or item.id in ids
        ]

    def visible_objects(self):
        """Return sketch objects available for selection and rendering."""

        if not self.manager.visible:
            return []

        items = []
        items.extend([item for item in self.manager.sketches if item.visible])
        items.extend([item for item in self.manager.sketch_geometry if item.visible])
        items.extend([item for item in self.manager.sketch_constraints if item.visible and not item.suppressed])
        items.extend([item for item in self.manager.sketch_dimensions if item.visible])
        return items

    def statistics(self):
        """Return sketch statistics."""

        stats = SketchStatistics(
            len(self.manager.sketches),
            len(self.manager.sketch_profiles),
            len(self.manager.sketch_loops),
            len(self.manager.sketch_regions),
            len(self.manager.sketch_geometry),
            len([item for item in self.manager.sketch_geometry if getattr(item, "construction", False)]),
            len(self.manager.sketch_constraints),
            len(self.manager.sketch_dimensions),
        )
        self.manager.sketch_statistics = stats

        return stats

    def _collection_for(self, item):
        if isinstance(item, SketchPlane):
            return self.manager.sketch_planes
        if isinstance(item, Sketch):
            return self.manager.sketches
        if isinstance(item, SketchProfile):
            return self.manager.sketch_profiles
        if isinstance(item, SketchLoop):
            return self.manager.sketch_loops
        if isinstance(item, SketchRegion):
            return self.manager.sketch_regions
        if isinstance(item, SketchGeometry):
            return self.manager.sketch_geometry
        if isinstance(item, (ConstraintType, ConstraintGroup, Constraint)):
            return self.manager.sketch_constraint_items_for(item)
        if isinstance(item, (DimensionType, SketchDimension)):
            return self.manager.sketch_dimension_items_for(item)
        return None

    def _refresh_links(self, item):
        if isinstance(item, Sketch):
            part = self.manager.part_for(item.part_id)
            if part is not None and item.id not in part.sketch_ids:
                part.sketch_ids.append(item.id)
        elif isinstance(item, SketchGeometry):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id not in sketch.geometry_ids:
                sketch.geometry_ids.append(item.id)
        elif isinstance(item, SketchProfile):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id not in sketch.profile_ids:
                sketch.profile_ids.append(item.id)
        elif isinstance(item, Constraint):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id not in sketch.constraint_ids:
                sketch.constraint_ids.append(item.id)
        elif isinstance(item, SketchDimension):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id not in sketch.dimension_ids:
                sketch.dimension_ids.append(item.id)

    def _unlink(self, item):
        if isinstance(item, Sketch):
            part = self.manager.part_for(item.part_id)
            if part is not None and item.id in part.sketch_ids:
                part.sketch_ids.remove(item.id)
        elif isinstance(item, SketchGeometry):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id in sketch.geometry_ids:
                sketch.geometry_ids.remove(item.id)
        elif isinstance(item, SketchProfile):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id in sketch.profile_ids:
                sketch.profile_ids.remove(item.id)
        elif isinstance(item, Constraint):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id in sketch.constraint_ids:
                sketch.constraint_ids.remove(item.id)
        elif isinstance(item, SketchDimension):
            sketch = self.sketch_for(item.sketch_id)
            if sketch is not None and item.id in sketch.dimension_ids:
                sketch.dimension_ids.remove(item.id)


class ConstraintManager:
    """Sketch-scoped constraint helper; it does not replace the workspace constraint system."""

    DEFAULT_TYPES = (
        "Coincident",
        "Parallel",
        "Perpendicular",
        "Horizontal",
        "Vertical",
        "Equal",
        "Tangent",
        "Concentric",
        "Collinear",
        "Midpoint",
        "Symmetric",
        "Fixed",
    )

    def __init__(self, manager):

        self.manager = manager

    def ensure_default_types(self):
        """Create default sketch constraint type records."""

        existing = {item.name for item in self.manager.sketch_constraint_types}

        for name in self.DEFAULT_TYPES:
            if name not in existing:
                self.manager.sketch_constraint_types.append(ConstraintType(name))

        return self.statistics()

    def add_item(self, item):
        """Add a sketch constraint item."""

        if isinstance(item, ConstraintType):
            collection = self.manager.sketch_constraint_types
        elif isinstance(item, ConstraintGroup):
            collection = self.manager.sketch_constraint_groups
        elif isinstance(item, Constraint):
            collection = self.manager.sketch_constraints
        else:
            return None

        if item not in collection:
            collection.append(item)

        self.manager.sketch_manager._refresh_links(item)
        self.statistics()
        return item

    def constraints_for(self, sketch):
        """Return constraints owned by a sketch."""

        return self.manager.sketch_manager.constraints_for(sketch)

    def statistics(self):
        """Return constraint statistics."""

        stats = ConstraintStatistics(
            len(self.manager.sketch_constraints),
            len(self.manager.sketch_constraint_groups),
            len([item for item in self.manager.sketch_constraints if item.enabled]),
            len([item for item in self.manager.sketch_constraints if item.suppressed]),
        )
        self.manager.sketch_constraint_statistics = stats
        return stats


