class FeatureExecutionSession:
    """Feature framework execution session owned by the existing ParametricEngine."""

    type_name = "FeatureExecutionSession"
    is_3d = True
    is_product = True
    is_feature_execution_session = True

    def __init__(self, name="Feature Execution Session", engine_id="", context=None, state=None, metadata=None, diagnostics=None):

        self.id = str(uuid4())
        self.name = name
        self.engine_id = engine_id
        self.context = context or FeatureExecutionContext()
        self.state = state or FeatureExecutionState()
        self.metadata = metadata or FeatureExecutionMetadata()
        self.diagnostics = diagnostics or FeatureDiagnostics()
        self.history_ids = []
        self.evaluation_order = FeatureEvaluationOrder(self.id)
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ffa726"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe feature execution session."""

        return _product_marker_data(self, {
            "engine_id": self.engine_id,
            "context": self.context.to_dict(),
            "state": self.state.to_dict(),
            "metadata": self.metadata.to_dict(),
            "diagnostics": self.diagnostics.to_dict(),
            "history_ids": list(self.history_ids),
            "evaluation_order": self.evaluation_order.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    def segments(self):
        """Return no geometry; session is metadata-only."""

        return []

    def points(self):
        """Return no drawable points for metadata-only sessions."""

        return []

    @staticmethod
    def from_dict(data):
        """Create feature execution session from persisted data."""

        data = data or {}
        item = FeatureExecutionSession(
            data.get("name", "Feature Execution Session"),
            data.get("engine_id", ""),
            FeatureExecutionContext.from_dict(data.get("context", {})),
            FeatureExecutionState.from_dict(data.get("state", {})),
            FeatureExecutionMetadata.from_dict(data.get("metadata", {})),
            FeatureDiagnostics.from_dict(data.get("diagnostics", {})),
        )
        _restore_product_marker(item, data)
        item.history_ids = list(data.get("history_ids", []))
        item.evaluation_order = FeatureEvaluationOrder.from_dict(data.get("evaluation_order", {}))
        item.display_color = data.get("display_color", "#ffa726")
        item.location = _vector_from_data(data.get("location", {}))
        return item


class SolidFeature:
    """Base feature history item that updates existing MeshEntity geometry."""

    type_name = "SolidFeature"
    feature_type = "Feature"
    is_3d = True
    is_product = True
    is_feature = True

    def __init__(self, name="Feature", part_id="", definition=None, metadata=None, result=None):

        self.id = str(uuid4())
        self.name = name
        self.part_id = part_id
        self.definition = definition or FeatureDefinition()
        self.metadata = metadata or FeatureMetadata()
        self.result = result or FeatureResult()
        self.suppressed = False
        self.order = 0
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ffcc80"
        self.location = Vector3()
        self.execution_state = FeatureExecutionState()
        self.execution_metadata = FeatureExecutionMetadata()
        self.diagnostics = FeatureDiagnostics()

    def to_dict(self):
        """Return JSON-safe feature data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "feature_type": self.feature_type,
            "part_id": self.part_id,
            "definition": self.definition.to_dict(),
            "metadata": self.metadata.to_dict(),
            "result": self.result.to_dict(),
            "suppressed": self.suppressed,
            "order": self.order,
            "execution_state": self.execution_state.to_dict(),
            "execution_metadata": self.execution_metadata.to_dict(),
            "diagnostics": self.diagnostics.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a feature from persisted data."""

        return _feature_from_data(data)

    def points(self):
        """Return no standalone points; body MeshEntity owns geometry."""

        return [self.location]

    def segments(self):
        """Return no standalone segments; body MeshEntity owns geometry."""

        size = 0.2
        point = self.location
        return [
            (Vector3(point.x - size, point.y, point.z), Vector3(point.x + size, point.y, point.z)),
            (Vector3(point.x, point.y - size, point.z), Vector3(point.x, point.y + size, point.z)),
        ]


