class SurfaceFeature(SolidFeature):
    """Base surface feature that updates existing MeshEntity geometry."""

    type_name = "SurfaceFeature"
    feature_type = "Surface"
    is_surface_feature = True

    def __init__(self, name="Surface Feature", part_id="", definition=None, metadata=None, result=None, surface_definition=None, surface_result=None):

        super().__init__(name, part_id, definition, metadata, result)
        self.surface_definition = surface_definition or SurfaceFeatureDefinition()
        self.surface_result = surface_result or SurfaceFeatureResult(
            self.surface_definition.target_surface_ids[0] if self.surface_definition.target_surface_ids else "",
            getattr(self.result, "mesh_entity_id", ""),
        )
        self.display_color = "#4dd0e1"

    def to_dict(self):
        """Return JSON-safe surface feature data."""

        data = super().to_dict()
        data["surface_definition"] = self.surface_definition.to_dict()
        data["surface_result"] = self.surface_result.to_dict()
        return data


