class ProductCurve:
    """Base product curve reference; it never owns MeshEntity geometry."""

    type_name = "ProductCurve"
    curve_type = "Curve"
    is_3d = True
    is_product = True
    is_curve = True

    def __init__(self, name="Curve", part_id="", definition=None, metadata=None, location=None):

        self.id = str(uuid4())
        self.name = name
        self.part_id = part_id
        self.definition = definition or CurveDefinition(part_id=part_id)
        self.metadata = metadata or CurveMetadata(curve_type=self.curve_type)
        self.location = location or Vector3()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ce93d8"

    def to_dict(self):
        """Return JSON-safe curve data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "curve_type": self.curve_type,
            "part_id": self.part_id,
            "definition": self.definition.to_dict(),
            "metadata": self.metadata.to_dict(),
            "location": _vector_to_data(self.location),
            "display_color": self.display_color,
        })

    @staticmethod
    def from_dict(data):
        """Create a product curve from persisted data."""

        return _curve_from_data(data)

    def points(self):
        """Return marker points for selection and renderer overlays."""

        return list(self.definition.marker_points) or [self.location]

    def segments(self):
        """Return marker segments for renderer overlays."""

        points = self.points()
        if len(points) > 1:
            return list(zip(points[:-1], points[1:]))
        size = 0.25
        point = self.location
        return [
            (Vector3(point.x - size, point.y, point.z), Vector3(point.x + size, point.y, point.z)),
            (Vector3(point.x, point.y - size, point.z), Vector3(point.x, point.y + size, point.z)),
        ]


