    """Mechanical standard placeholder such as ISO, DIN or ANSI."""

    name: str = "ISO"
    description: str = ""
    properties: dict = field(default_factory=dict)
    id: str = field(default_factory=lambda: str(uuid4()))

    def to_dict(self):
        """Return JSON-safe mechanical standard data."""

        return dict(self.__dict__)

    @staticmethod
    def from_dict(data):
        """Create a mechanical standard from persisted data."""

        data = data or {}
        return MechanicalStandard(
            data.get("name", "ISO"),
            data.get("description", ""),
            dict(data.get("properties", {})),
            data.get("id", str(uuid4())),
        )


