class MechanicalLibrary:
    """Workspace-owned mechanical library metadata."""

    type_name = "MechanicalLibrary"
    is_3d = True
    is_product = True
    is_mechanical_library = True

    def __init__(self, name="Mechanical Library", metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.metadata = metadata or ProductMetadata()
        self.category_ids = []
        self.component_ids = []
        self.family_ids = []
        self.standard_ids = []
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#81d4fa"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe mechanical library data."""

        return _product_marker_data(self, {
            "metadata": self.metadata.to_dict(),
            "category_ids": list(self.category_ids),
            "component_ids": list(self.component_ids),
            "family_ids": list(self.family_ids),
            "standard_ids": list(self.standard_ids),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a mechanical library from persisted data."""

        data = data or {}
        library = MechanicalLibrary(
            data.get("name", "Mechanical Library"),
            ProductMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(library, data)
        library.category_ids = list(data.get("category_ids", []))
        library.component_ids = list(data.get("component_ids", []))
        library.family_ids = list(data.get("family_ids", []))
        library.standard_ids = list(data.get("standard_ids", []))
        library.display_color = data.get("display_color", "#81d4fa")
        library.location = _vector_from_data(data.get("location", {}))
        return library

    def points(self):
        """Return marker points for product overlay rendering."""

        return [self.location]

    def segments(self):
        """Return no standalone geometry."""

        return []


