class SheetMetalRule:
    """Sheet metal rule foundation for thickness, bend and relief settings."""

    type_name = "SheetMetalRule"
    is_3d = True
    is_product = True
    is_sheet_metal_rule = True

    def __init__(self, name="Sheet Metal Rule", material_id="", thickness=1.0, inside_radius=1.0, k_factor=None, metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.material_id = material_id
        self.thickness = float(thickness)
        self.inside_radius = float(inside_radius)
        self.k_factor = k_factor or KFactor()
        self.bend_allowance = BendAllowance()
        self.bend_deduction = BendDeduction()
        self.relief_rule = ReliefRule()
        self.gauge_id = ""
        self.metadata = metadata or RuleMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ffab91"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe sheet metal rule data."""

        return {
            "id": self.id,
            "name": self.name,
            "material_id": self.material_id,
            "thickness": self.thickness,
            "inside_radius": self.inside_radius,
            "k_factor": self.k_factor.to_dict(),
            "bend_allowance": self.bend_allowance.to_dict(),
            "bend_deduction": self.bend_deduction.to_dict(),
            "relief_rule": self.relief_rule.to_dict(),
            "gauge_id": self.gauge_id,
            "metadata": self.metadata.to_dict(),
            "visible": self.visible,
            "locked": self.locked,
            "selected": self.selected,
            "layer_name": self.layer_name,
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        }

    @staticmethod
    def from_dict(data):
        """Create a sheet metal rule from persisted data."""

        data = data or {}
        rule = SheetMetalRule(
            data.get("name", "Sheet Metal Rule"),
            data.get("material_id", ""),
            float(data.get("thickness", 1.0)),
            float(data.get("inside_radius", 1.0)),
            KFactor.from_dict(data.get("k_factor", {})),
            RuleMetadata.from_dict(data.get("metadata", {})),
        )
        rule.id = data.get("id", rule.id)
        rule.bend_allowance = BendAllowance.from_dict(data.get("bend_allowance", {}))
        rule.bend_deduction = BendDeduction.from_dict(data.get("bend_deduction", {}))
        rule.relief_rule = ReliefRule.from_dict(data.get("relief_rule", {}))
        rule.gauge_id = data.get("gauge_id", "")
        rule.visible = bool(data.get("visible", True))
        rule.locked = bool(data.get("locked", False))
        rule.selected = bool(data.get("selected", False))
        rule.layer_name = data.get("layer_name", "0")
        rule.display_color = data.get("display_color", "#ffab91")
        rule.location = _vector_from_data(data.get("location", {}))
        return rule

    def points(self):
        """Return marker points for product overlay rendering."""

        return [self.location]

    def segments(self):
        """Return no standalone geometry."""

        return []


