class ProductReport:
    """Generic product report metadata foundation."""

    type_name = "ProductReport"
    is_3d = True
    is_product = True
    is_product_report = True

    def __init__(self, name="Product Report", target_id="", source_ids=None, metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.target_id = target_id
        self.source_ids = list(source_ids or [])
        self.metadata = metadata or ReportMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#9575cd"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe product report data."""

        return _product_marker_data(self, {
            "class": self.type_name,
            "target_id": self.target_id,
            "source_ids": list(self.source_ids),
            "metadata": self.metadata.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create product report from persisted data."""

        data = data or {}
        report_type = data.get("class", data.get("type_name", data.get("report_class", "ProductReport")))
        cls = {
            "ValidationReport": ValidationReport,
            "AnalysisReport": AnalysisReport,
            "ProductionReport": ProductionReport,
            "ShopFloorDocument": ShopFloorDocument,
            "ReadinessReport": ReadinessReport,
        }.get(report_type, ProductReport)
        report = cls(
            data.get("name", report_type),
            data.get("target_id", ""),
            list(data.get("source_ids", [])),
            ReportMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(report, data)
        report.display_color = data.get("display_color", getattr(report, "display_color", "#9575cd"))
        report.location = _vector_from_data(data.get("location", {}))
        return report

    def points(self):
        """Return marker points for product overlay rendering."""

        return [self.location]

    def segments(self):
        """Return no standalone geometry."""

        return []


