class ManufacturingSetup:
    """CAM manufacturing setup referencing product and mesh data only."""

    type_name = "ManufacturingSetup"
    is_3d = True
    is_product = True
    is_cam_setup = True

    def __init__(self, name="Manufacturing Setup", job_id="", stock=None, wcs=None, fixture=None, origin=None, metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.job_id = job_id
        self.stock = stock or StockDefinition()
        self.work_coordinate_system = wcs or WorkCoordinateSystem()
        self.fixture = fixture or FixtureDefinition()
        self.origin = origin or OriginDefinition()
        self.metadata = metadata or SetupMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#4dd0e1"
        self.location = self.origin.position

    def to_dict(self):
        """Return JSON-safe manufacturing setup data."""

        return _product_marker_data(self, {
            "job_id": self.job_id,
            "stock": self.stock.to_dict(),
            "work_coordinate_system": self.work_coordinate_system.to_dict(),
            "fixture": self.fixture.to_dict(),
            "origin": self.origin.to_dict(),
            "metadata": self.metadata.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create manufacturing setup from persisted data."""

        data = data or {}
        setup = ManufacturingSetup(
            data.get("name", "Manufacturing Setup"),
            data.get("job_id", ""),
            StockDefinition.from_dict(data.get("stock", {})),
            WorkCoordinateSystem.from_dict(data.get("work_coordinate_system", {})),
            FixtureDefinition.from_dict(data.get("fixture", {})),
            OriginDefinition.from_dict(data.get("origin", {})),
            SetupMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(setup, data)
        setup.display_color = data.get("display_color", "#4dd0e1")
        setup.location = _vector_from_data(data.get("location", setup.origin.to_dict().get("position", {})))
        return setup

    def points(self):
        """Return setup marker points."""

        return [self.location]

    def segments(self):
        """Return stock marker segments as a small setup cross only."""

        point = self.location
        size = 0.4
        return [
            (Vector3(point.x - size, point.y, point.z), Vector3(point.x + size, point.y, point.z)),
            (Vector3(point.x, point.y - size, point.z), Vector3(point.x, point.y + size, point.z)),
        ]


CAMSetup = ManufacturingSetup


