class OperationDefinition:
    """CAM operation definition placeholder; no toolpath is generated."""

    type_name = "OperationDefinition"
    is_3d = True
    is_product = True
    is_cam_operation = True

    def __init__(self, name="CAM Operation", job_id="", setup_id="", operation_type="Facing", target_ids=None, parameters=None, metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.job_id = job_id
        self.setup_id = setup_id
        self.operation_type = operation_type
        self.target_ids = list(target_ids or [])
        self.parameters = parameters or OperationParameters()
        self.metadata = metadata or OperationMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#80deea"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe CAM operation data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "job_id": self.job_id,
            "setup_id": self.setup_id,
            "operation_type": self.operation_type,
            "target_ids": list(self.target_ids),
            "parameters": self.parameters.to_dict(),
            "metadata": self.metadata.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create operation definition from persisted data."""

        data = data or {}
        operation_class = _operation_class_from_name(data.get("class", "OperationDefinition"))
        if issubclass(operation_class, ThreeAxisOperation):
            return ThreeAxisOperation.from_dict(data)
        if issubclass(operation_class, RouterOperation):
            return RouterOperation.from_dict(data)
        if issubclass(operation_class, PlasmaOperation):
            return PlasmaOperation.from_dict(data)
        if issubclass(operation_class, LaserOperation):
            return LaserOperation.from_dict(data)
        operation = operation_class(
            data.get("name", "CAM Operation"),
            data.get("job_id", ""),
            data.get("setup_id", ""),
            data.get("operation_type", "Facing"),
            list(data.get("target_ids", [])),
            OperationParameters.from_dict(data.get("parameters", {})),
            OperationMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(operation, data)
        operation.display_color = data.get("display_color", "#80deea")
        operation.location = _vector_from_data(data.get("location", {}))
        return operation

    def points(self):
        """Return operation marker points."""

        return [self.location]

    def segments(self):
        """Return no toolpath segments."""

        return []


CAMOperation = OperationDefinition


