class ThreeAxisOperation(MachiningOperation):
    """Base 3-axis machining operation definition."""

    is_three_axis_operation = True

    def __init__(self, name="3 Axis Operation", job_id="", setup_id="", operation_type="Parallel", target_ids=None, parameters=None, metadata=None, strategy=None, three_axis_metadata=None):

        super().__init__(name, job_id, setup_id, operation_type, target_ids, parameters, metadata)
        self.strategy = strategy or ThreeAxisStrategy(operation_type)
        self.three_axis_metadata = three_axis_metadata or ThreeAxisMetadata()
        self.display_color = "#4fc3f7"

    def to_dict(self):
        """Return JSON-safe 3-axis operation data."""

        data = super().to_dict()
        data.update({
            "strategy": self.strategy.to_dict(),
            "three_axis_metadata": self.three_axis_metadata.to_dict(),
            "display_color": self.display_color,
        })
        return data

    @staticmethod
    def from_dict(data):
        """Create 3-axis operation from persisted data."""

        data = data or {}
        operation_class = _operation_class_from_name(data.get("class", "ThreeAxisOperation"))
        operation = operation_class(
            data.get("name", "3 Axis Operation"),
            data.get("job_id", ""),
            data.get("setup_id", ""),
            data.get("operation_type", "Parallel"),
            list(data.get("target_ids", [])),
            OperationParameters.from_dict(data.get("parameters", {})),
            OperationMetadata.from_dict(data.get("metadata", {})),
            ThreeAxisStrategy.from_dict(data.get("strategy", {})),
            ThreeAxisMetadata.from_dict(data.get("three_axis_metadata", {})),
        )
        _restore_product_marker(operation, data)
        operation.display_color = data.get("display_color", "#4fc3f7")
        operation.location = _vector_from_data(data.get("location", {}))
        return operation


