class LaserOperation(OperationDefinition):
    """Base laser operation definition; no toolpaths are generated."""

    is_laser_plasma_operation = True
    is_laser_operation = True

    def __init__(self, name="Laser Operation", job_id="", setup_id="", operation_type="Vector Cut", target_ids=None, parameters=None, metadata=None, laser_plasma_metadata=None):

        super().__init__(name, job_id, setup_id, operation_type, target_ids, parameters, metadata)
        self.laser_plasma_metadata = laser_plasma_metadata or LaserPlasmaMetadata("Laser")
        self.display_color = "#ff7043"

    def to_dict(self):
        """Return JSON-safe laser operation data."""

        data = super().to_dict()
        data.update({
            "laser_plasma_metadata": self.laser_plasma_metadata.to_dict(),
            "display_color": self.display_color,
        })
        return data

    @staticmethod
    def from_dict(data):
        """Create a laser/plasma operation from persisted data."""

        data = data or {}
        operation_class = _operation_class_from_name(data.get("class", "LaserOperation"))
        operation = operation_class(
            data.get("name", "Laser Operation"),
            data.get("job_id", ""),
            data.get("setup_id", ""),
            data.get("operation_type", "Vector Cut"),
            list(data.get("target_ids", [])),
            OperationParameters.from_dict(data.get("parameters", {})),
            OperationMetadata.from_dict(data.get("metadata", {})),
            LaserPlasmaMetadata.from_dict(data.get("laser_plasma_metadata", {})),
        )
        _restore_product_marker(operation, data)
        operation.display_color = data.get("display_color", getattr(operation, "display_color", "#ff7043"))
        operation.location = _vector_from_data(data.get("location", {}))
        return operation


class PlasmaOperation(OperationDefinition):
    """Base plasma operation definition; no toolpaths are generated."""

    is_laser_plasma_operation = True
    is_plasma_operation = True

    def __init__(self, name="Plasma Operation", job_id="", setup_id="", operation_type="Plasma Cut", target_ids=None, parameters=None, metadata=None, laser_plasma_metadata=None, kerf_compensation=None, cut_quality=None, torch_height_control=None):

        super().__init__(name, job_id, setup_id, operation_type, target_ids, parameters, metadata)
        self.laser_plasma_metadata = laser_plasma_metadata or LaserPlasmaMetadata("Plasma")
        self.kerf_compensation = kerf_compensation or KerfCompensation()
        self.cut_quality = cut_quality or CutQuality()
        self.torch_height_control = torch_height_control or TorchHeightControl()
        self.display_color = "#42a5f5"

    def to_dict(self):
        """Return JSON-safe plasma operation data."""

        data = super().to_dict()
        data.update({
            "laser_plasma_metadata": self.laser_plasma_metadata.to_dict(),
            "kerf_compensation": self.kerf_compensation.to_dict(),
            "cut_quality": self.cut_quality.to_dict(),
            "torch_height_control": self.torch_height_control.to_dict(),
            "display_color": self.display_color,
        })
        return data

    @staticmethod
    def from_dict(data):
        """Create a plasma operation from persisted data."""

        data = data or {}
        operation_class = _operation_class_from_name(data.get("class", "PlasmaOperation"))
        operation = operation_class(
            data.get("name", "Plasma Operation"),
            data.get("job_id", ""),
            data.get("setup_id", ""),
            data.get("operation_type", "Plasma Cut"),
            list(data.get("target_ids", [])),
            OperationParameters.from_dict(data.get("parameters", {})),
            OperationMetadata.from_dict(data.get("metadata", {})),
            LaserPlasmaMetadata.from_dict(data.get("laser_plasma_metadata", {})),
            KerfCompensation.from_dict(data.get("kerf_compensation", {})),
            CutQuality.from_dict(data.get("cut_quality", {})),
            TorchHeightControl.from_dict(data.get("torch_height_control", {})),
        )
        _restore_product_marker(operation, data)
        operation.display_color = data.get("display_color", "#42a5f5")
        operation.location = _vector_from_data(data.get("location", {}))
        return operation


