class RouterOperation(OperationDefinition):
    """Base router operation definition; no toolpaths are generated."""

    is_router_operation = True

    def __init__(self, name="Router Operation", job_id="", setup_id="", operation_type="Profile Cut", target_ids=None, parameters=None, metadata=None, router_metadata=None, router_profile=None):

        super().__init__(name, job_id, setup_id, operation_type, target_ids, parameters, metadata)
        self.router_metadata = router_metadata or RouterMetadata()
        self.router_profile = router_profile or RouterMetadataProfile()
        self.display_color = "#8bc34a"

    def to_dict(self):
        data = super().to_dict()
        data.update({
            "router_metadata": self.router_metadata.to_dict(),
            "router_profile": self.router_profile.to_dict(),
            "display_color": self.display_color,
        })
        return data

    @staticmethod
    def from_dict(data):
        data = data or {}
        operation_class = _operation_class_from_name(data.get("class", "RouterOperation"))
        operation = operation_class(
            data.get("name", "Router Operation"),
            data.get("job_id", ""),
            data.get("setup_id", ""),
            data.get("operation_type", "Profile Cut"),
            list(data.get("target_ids", [])),
            OperationParameters.from_dict(data.get("parameters", {})),
            OperationMetadata.from_dict(data.get("metadata", {})),
            RouterMetadata.from_dict(data.get("router_metadata", {})),
            RouterMetadataProfile.from_dict(data.get("router_profile", {})),
        )
        _restore_product_marker(operation, data)
        operation.display_color = data.get("display_color", "#8bc34a")
        operation.location = _vector_from_data(data.get("location", {}))
        return operation


