class ControllerProfile:
    """Machine controller profile metadata only; no output is generated."""

    type_name = "ControllerProfile"
    is_3d = True
    is_product = True
    is_controller_profile = True

    def __init__(self, name="Generic Controller", controller_type="GenericGCode", metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.controller_type = controller_type
        self.metadata = metadata or PostProcessorMetadata(controller_family=controller_type)
        self.enabled = True
        self.default = False
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#b39ddb"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe controller profile data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "controller_type": self.controller_type,
            "metadata": self.metadata.to_dict(),
            "enabled": self.enabled,
            "default": self.default,
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a controller profile from persisted data."""

        data = data or {}
        profile_class = _controller_profile_class_from_name(data.get("class", "ControllerProfile"))
        profile = profile_class(
            data.get("name", data.get("controller_type", "Generic Controller")),
            data.get("controller_version", ""),
            PostProcessorMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(profile, data)
        profile.controller_type = data.get("controller_type", getattr(profile, "controller_type", "GenericGCode"))
        profile.enabled = bool(data.get("enabled", True))
        profile.default = bool(data.get("default", False))
        profile.display_color = data.get("display_color", "#b39ddb")
        profile.location = _vector_from_data(data.get("location", {}))
        return profile

    def points(self):
        """Return marker points for renderer overlays."""

        return [self.location]

    def segments(self):
        """Return no generated output geometry."""

        return []


def _controller_profile_init(self, name, version, metadata, controller_type):
    ControllerProfile.__init__(
        self,
        name or controller_type,
        controller_type,
        metadata or PostProcessorMetadata(controller_family=controller_type, controller_version=version),
    )
    self.metadata.controller_family = controller_type
    if version:
        self.metadata.controller_version = version


