class MachineLibrary:
    """Machine library metadata owned by ProductManager."""

    type_name = "MachineLibrary"
    is_3d = True
    is_product = True
    is_machine_library = True

    def __init__(self, name="Machine Library", metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.metadata = metadata or MachineMetadata()
        self.category_ids = []
        self.machine_ids = []
        self.profile_ids = []
        self.favorite_machine_ids = []
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#26a69a"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe machine library data."""

        return _product_marker_data(self, {
            "metadata": self.metadata.to_dict(),
            "category_ids": list(self.category_ids),
            "machine_ids": list(self.machine_ids),
            "profile_ids": list(self.profile_ids),
            "favorite_machine_ids": list(self.favorite_machine_ids),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a machine library from persisted data."""

        data = data or {}
        item = MachineLibrary(data.get("name", "Machine Library"), MachineMetadata.from_dict(data.get("metadata", {})))
        _restore_product_marker(item, data)
        item.category_ids = list(data.get("category_ids", []))
        item.machine_ids = list(data.get("machine_ids", []))
        item.profile_ids = list(data.get("profile_ids", []))
        item.favorite_machine_ids = list(data.get("favorite_machine_ids", []))
        item.display_color = data.get("display_color", "#26a69a")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def points(self):
        return [self.location]

    def segments(self):
        return []


class MachineDefinition:
    """Machine definition metadata; it never owns geometry or executes code."""

    type_name = "MachineDefinition"
    is_3d = True
    is_product = True
    is_machine_definition = True

    def __init__(self, name="Machine", machine_type="Generic", library_id="", category="", metadata=None, capabilities=None):

        self.id = str(uuid4())
        self.name = name
        self.machine_type = machine_type
        self.library_id = library_id
        self.category = category
        self.metadata = metadata or MachineMetadata(machine_category=machine_type)
        self.capabilities = capabilities or MachineCapabilities()
        self.profile_ids = []
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#4db6ac"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe machine definition data."""

        return _product_marker_data(self, {
            "class": self.__class__.__name__,
            "machine_type": self.machine_type,
            "library_id": self.library_id,
            "category": self.category,
            "metadata": self.metadata.to_dict(),
            "capabilities": self.capabilities.to_dict(),
            "profile_ids": list(self.profile_ids),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a machine definition from persisted data."""

        data = data or {}
        machine_class = _machine_class_from_name(data.get("class", "MachineDefinition"))
        if issubclass(machine_class, PrinterProfile):
            return PrinterProfile.from_dict(data)
        item = MachineDefinition(
            data.get("name", "Machine"),
            data.get("machine_type", "Generic"),
            data.get("library_id", ""),
            data.get("category", ""),
            MachineMetadata.from_dict(data.get("metadata", {})),
            MachineCapabilities.from_dict(data.get("capabilities", {})),
        )
        item.__class__ = machine_class
        _restore_product_marker(item, data)
        item.profile_ids = list(data.get("profile_ids", []))
        item.display_color = data.get("display_color", "#4db6ac")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def points(self):
        return [self.location]

    def segments(self):
        return []


