    is_product = True
    is_machine_profile = True

    def __init__(self, name="Machine Profile", machine_id="", cam_job_id="", post_processor_id="", controller_profile_id="", tool_library_id="", setup_id="", enabled=True, assignment=None, profile_reference=None, limit_reference=None, controller_reference=None, fixture_reference=None, validation=None, metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.machine_id = machine_id
        self.cam_job_id = cam_job_id
        self.post_processor_id = post_processor_id
        self.controller_profile_id = controller_profile_id
        self.tool_library_id = tool_library_id
        self.setup_id = setup_id
        self.enabled = bool(enabled)
        self.assignment = assignment or MachineAssignment(cam_job_id, machine_id, self.id, True)
        self.profile_reference = profile_reference or MachineProfileReference(machine_id, controller_profile_id, cam_job_id, [])
        self.limit_reference = limit_reference or MachineLimitReference(machine_id)
        self.controller_reference = controller_reference or ControllerReference(controller_profile_id, post_processor_id)
        self.fixture_reference = fixture_reference or FixtureReference(setup_id)
        self.validation = validation or MachineValidationMetadata()
        self.metadata = metadata or MachineMetadata(machine_category="Machine Profile")
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#80cbc4"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe machine profile data."""

        return _product_marker_data(self, {
            "machine_id": self.machine_id,
            "cam_job_id": self.cam_job_id,
            "post_processor_id": self.post_processor_id,
            "controller_profile_id": self.controller_profile_id,
            "tool_library_id": self.tool_library_id,
            "setup_id": self.setup_id,
            "enabled": self.enabled,
            "assignment": self.assignment.to_dict(),
            "profile_reference": self.profile_reference.to_dict(),
            "limit_reference": self.limit_reference.to_dict(),
            "controller_reference": self.controller_reference.to_dict(),
            "fixture_reference": self.fixture_reference.to_dict(),
            "validation": self.validation.to_dict(),
            "metadata": self.metadata.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a machine profile from persisted data."""

        data = data or {}
        item = MachineProfile(
            data.get("name", "Machine Profile"),
            data.get("machine_id", ""),
            data.get("cam_job_id", ""),
            data.get("post_processor_id", ""),
            data.get("controller_profile_id", ""),
            data.get("tool_library_id", ""),
            data.get("setup_id", ""),
            bool(data.get("enabled", True)),
            MachineAssignment.from_dict(data.get("assignment", {})),
            MachineProfileReference.from_dict(data.get("profile_reference", {})),
            MachineLimitReference.from_dict(data.get("limit_reference", {})),
            ControllerReference.from_dict(data.get("controller_reference", {})),
            FixtureReference.from_dict(data.get("fixture_reference", {})),
            MachineValidationMetadata.from_dict(data.get("validation", {})),
            MachineMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(item, data)
        item.display_color = data.get("display_color", "#80cbc4")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def points(self):
        return [self.location]

    def segments(self):
        return []


