class SimulationProfile:
    """Reusable manufacturing simulation profile metadata."""

    type_name = "SimulationProfile"
    is_3d = True
    is_product = True
    is_simulation_profile = True

    def __init__(self, name="Simulation Profile", metadata=None, validation=None):
        self.id = str(uuid4())
        self.name = name
        self.metadata = metadata or SimulationMetadata()
        self.validation = validation or SimulationValidation()
        self.collision = CollisionMetadata()
        self.machine_motion = MachineMotionMetadata()
        self.tool_motion = ToolMotionMetadata()
        self.head_motion = HeadMotionMetadata()
        self.stock_removal = StockRemovalMetadata()
        self.layer_simulation = LayerSimulationMetadata()
        self.travel = TravelMetadata()
        self.fixture = FixtureMetadata()
        self.safety = SafetyMetadata()
        self.estimate = SimulationEstimate()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ff7043"
        self.location = Vector3()

    def to_dict(self):
        return _product_marker_data(self, {
            "metadata": self.metadata.to_dict(),
            "validation": self.validation.to_dict(),
            "collision": self.collision.to_dict(),
            "machine_motion": self.machine_motion.to_dict(),
            "tool_motion": self.tool_motion.to_dict(),
            "head_motion": self.head_motion.to_dict(),
            "stock_removal": self.stock_removal.to_dict(),
            "layer_simulation": self.layer_simulation.to_dict(),
            "travel": self.travel.to_dict(),
            "fixture": self.fixture.to_dict(),
            "safety": self.safety.to_dict(),
            "estimate": self.estimate.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        data = data or {}
        item = SimulationProfile(data.get("name", "Simulation Profile"), SimulationMetadata.from_dict(data.get("metadata", {})), SimulationValidation.from_dict(data.get("validation", {})))
        _restore_product_marker(item, data)
        item.collision = CollisionMetadata.from_dict(data.get("collision", {}))
        item.machine_motion = MachineMotionMetadata.from_dict(data.get("machine_motion", {}))
        item.tool_motion = ToolMotionMetadata.from_dict(data.get("tool_motion", {}))
        item.head_motion = HeadMotionMetadata.from_dict(data.get("head_motion", {}))
        item.stock_removal = StockRemovalMetadata.from_dict(data.get("stock_removal", {}))
        item.layer_simulation = LayerSimulationMetadata.from_dict(data.get("layer_simulation", {}))
        item.travel = TravelMetadata.from_dict(data.get("travel", {}))
        item.fixture = FixtureMetadata.from_dict(data.get("fixture", {}))
        item.safety = SafetyMetadata.from_dict(data.get("safety", {}))
        item.estimate = SimulationEstimate.from_dict(data.get("estimate", {}))
        item.display_color = data.get("display_color", "#ff7043")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def points(self):
        return [self.location]

    def segments(self):
        return []


class SimulationJob:
    """Manufacturing simulation job metadata."""

    type_name = "SimulationJob"
    is_3d = True
    is_product = True
    is_simulation_job = True

    def __init__(self, name="Simulation Job", cam_job_id="", slice_job_id="", profile_id="", metadata=None, result=None):
        self.id = str(uuid4())
        self.name = name
        self.cam_job_id = cam_job_id
        self.slice_job_id = slice_job_id
        self.profile_id = profile_id
        self.enabled = True
        self.metadata = metadata or SimulationMetadata()
        self.result = result or SimulationResult()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#ff8a65"
        self.location = Vector3()

    def to_dict(self):
        return _product_marker_data(self, {
            "cam_job_id": self.cam_job_id,
            "slice_job_id": self.slice_job_id,
            "profile_id": self.profile_id,
            "enabled": self.enabled,
            "metadata": self.metadata.to_dict(),
            "result": self.result.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        data = data or {}
        item = SimulationJob(
            data.get("name", "Simulation Job"),
            data.get("cam_job_id", ""),
            data.get("slice_job_id", ""),
            data.get("profile_id", ""),
            SimulationMetadata.from_dict(data.get("metadata", {})),
            SimulationResult.from_dict(data.get("result", {})),
        )
        _restore_product_marker(item, data)
        item.enabled = bool(data.get("enabled", True))
        item.display_color = data.get("display_color", "#ff8a65")
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def points(self):
        return [self.location]

    def segments(self):
        return []


