class ManufacturingRecord:
    """Reusable selectable manufacturing metadata record."""

    type_name = "ManufacturingRecord"
    is_3d = True
    is_product = True
    is_manufacturing_record = True

    def __init__(self, name="Manufacturing Record", metadata=None):
        self.id = str(uuid4())
        self.name = name
        self.metadata = metadata or ManufacturingJobMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#26a69a"
        self.location = Vector3()

    def _extra_data(self):
        return {}

    def to_dict(self):
        data = {
            "class": self.type_name,
            "metadata": self.metadata.to_dict() if hasattr(self.metadata, "to_dict") else dict(getattr(self, "metadata", {}) or {}),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        }
        data.update(self._extra_data())
        return _product_marker_data(self, data)

    @classmethod
    def from_dict(cls, data):
        data = data or {}
        item = cls(data.get("name", cls.__name__.replace("_", " ")))
        _restore_product_marker(item, data)
        item._restore_extra_data(data)
        item.display_color = data.get("display_color", getattr(item, "display_color", "#26a69a"))
        item.location = _vector_from_data(data.get("location", {}))
        return item

    def _restore_extra_data(self, data):
        metadata = data.get("metadata", {})
        self.metadata = ManufacturingJobMetadata.from_dict(metadata)

    def points(self):
        return [self.location]

    def segments(self):
        return []


