class SolidBody:
    """Product body reference that uses an existing MeshEntity as geometry owner."""

    type_name = "SolidBody"
    is_3d = True
    is_product = True
    is_body = True

    def __init__(self, name="Solid Body", part_id="", mesh_entity_id="", metadata=None):

        self.id = str(uuid4())
        self.name = name
        self.part_id = part_id
        self.mesh_entity_id = mesh_entity_id
        self.feature_ids = []
        self.metadata = metadata or BodyMetadata()
        self.visible = True
        self.locked = False
        self.selected = False
        self.hovered = False
        self.layer_name = "0"
        self.display_color = "#a5d6a7"
        self.location = Vector3()

    def to_dict(self):
        """Return JSON-safe solid body data."""

        return _product_marker_data(self, {
            "part_id": self.part_id,
            "mesh_entity_id": self.mesh_entity_id,
            "feature_ids": list(self.feature_ids),
            "metadata": self.metadata.to_dict(),
            "display_color": self.display_color,
            "location": _vector_to_data(self.location),
        })

    @staticmethod
    def from_dict(data):
        """Create a solid body from persisted data."""

        data = data or {}
        body = SolidBody(
            data.get("name", "Solid Body"),
            data.get("part_id", ""),
            data.get("mesh_entity_id", ""),
            BodyMetadata.from_dict(data.get("metadata", {})),
        )
        _restore_product_marker(body, data)
        body.feature_ids = list(data.get("feature_ids", []))
        body.display_color = data.get("display_color", "#a5d6a7")
        body.location = _vector_from_data(data.get("location", {}))
        return body

    def points(self):
        """Return a metadata marker; MeshEntity owns body geometry."""

        return [self.location]

    def segments(self):
        """Return a metadata marker; MeshEntity owns body geometry."""

        size = 0.3
        point = self.location
        return [
            (Vector3(point.x - size, point.y - size, point.z), Vector3(point.x + size, point.y - size, point.z)),
            (Vector3(point.x + size, point.y - size, point.z), Vector3(point.x + size, point.y + size, point.z)),
            (Vector3(point.x + size, point.y + size, point.z), Vector3(point.x - size, point.y + size, point.z)),
            (Vector3(point.x - size, point.y + size, point.z), Vector3(point.x - size, point.y - size, point.z)),
        ]


