class AssemblyManager:
    """Project-scoped helper for assembly documents, assemblies and component instances."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add assembly document, assembly or component metadata."""

        if isinstance(item, AssemblyDocument):
            collection = self.manager.assembly_documents
        elif isinstance(item, Assembly):
            collection = self.manager.assemblies
        elif isinstance(item, AssemblyComponent):
            collection = self.manager.assembly_components
        elif isinstance(item, ComponentOccurrence):
            collection = self.manager.component_occurrences
        elif isinstance(item, AssemblyInstance):
            collection = self.manager.assembly_instances
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_document(self, name="Assembly Document", settings=None, metadata=None):
        """Create and store an assembly document."""

        document = AssemblyDocument(name, metadata, settings)
        self.add_item(document)
        self.manager.active_assembly_document_id = document.id
        return document

    def create_assembly(self, document=None, name="Assembly", metadata=None, settings=None):
        """Create and store an assembly in an assembly document."""

        document_id = getattr(document, "id", document) or self.manager.active_assembly_document_id
        assembly = Assembly(name, document_id, metadata, settings)
        self.add_item(assembly)
        self.open_assembly(assembly)
        return assembly

    def insert_part(self, assembly, part, name=None):
        """Insert an existing ProductPart as an assembly component."""

        target = self.assembly_for(assembly)
        part_id = getattr(part, "id", part) or ""
        component = AssemblyComponent(name or getattr(part, "name", "Assembly Component"), getattr(target, "id", ""), part_id)
        self.add_item(component)
        self.manager.dependency_manager.add_edge(part, component, "AssemblyPartReference")
        return component

    def insert_subassembly(self, assembly, subassembly, name=None):
        """Insert an existing Assembly as a subassembly component."""

        target = self.assembly_for(assembly)
        subassembly_id = getattr(subassembly, "id", subassembly) or ""
        component = AssemblyComponent(name or getattr(subassembly, "name", "Subassembly"), getattr(target, "id", ""), subassembly_id=subassembly_id)
        self.add_item(component)
        self.manager.dependency_manager.add_edge(subassembly, component, "SubassemblyReference")
        return component

    def create_instance(self, assembly, component, name=None, position=None, rotation=None):
        """Create a component instance transform; no geometry is duplicated."""

        target = self.assembly_for(assembly)
        component_id = getattr(component, "id", component) or ""
        instance = AssemblyInstance(name or "Assembly Instance", getattr(target, "id", ""), component_id, position=position, rotation=rotation)
        self.add_item(instance)
        self.manager.dependency_manager.add_edge(component, instance, "ComponentInstance")
        return instance

    def create_occurrence(self, assembly, component, name=None, position=None):
        """Create a component occurrence for a concrete assembly instance."""

        target = self.assembly_for(assembly)
        component_id = getattr(component, "id", component) or ""
        occurrence = ComponentOccurrence(name or "Component Occurrence", getattr(target, "id", ""), component_id, position=position)
        self.add_item(occurrence)
        self.manager.dependency_manager.add_edge(component, occurrence, "ComponentOccurrence")
        return occurrence

    def rename(self, assembly, name):
        """Rename an assembly."""

        target = self.assembly_for(assembly)
        if target is not None:
            target.name = str(name or target.name)
        return target

    def delete_assembly(self, assembly):
        """Delete an assembly metadata item."""

        target = self.assembly_for(assembly)
        if target is not None:
            return self.manager.remove_object(target)
        return False

    def open_assembly(self, assembly):
        """Set the active assembly."""

        target = self.assembly_for(assembly)
        if target is None:
            return None

        for item in self.manager.assemblies:
            item.active = item is target
        self.manager.active_assembly_id = target.id
        return target

    def assembly_for(self, assembly):
        """Return an assembly by object, ID or name."""

        if isinstance(assembly, Assembly):
            return assembly if assembly in self.manager.assemblies else None

        return _find_by_id_or_name(self.manager.assemblies, assembly)

    def assemblies_for_document(self, document):
        """Return assemblies assigned to a document."""

        document_id = getattr(document, "id", document)
        return [assembly for assembly in self.manager.assemblies if assembly.document_id == document_id]

    def components_for_assembly(self, assembly):
        """Return components assigned to an assembly."""

        assembly_id = getattr(assembly, "id", assembly)
        return [component for component in self.manager.assembly_components if component.assembly_id == assembly_id]

    def instances_for_assembly(self, assembly):
        """Return instances assigned to an assembly."""

        assembly_id = getattr(assembly, "id", assembly)
        return [
            instance for instance in self.manager.assembly_instances + self.manager.component_occurrences
            if instance.assembly_id == assembly_id
        ]

    def visible_objects(self):
        """Return visible assembly metadata for selection and highlighting."""

        if not self.manager.visible:
            return []

        return (
            [assembly for assembly in self.manager.assemblies if assembly.visible] +
            [component for component in self.manager.assembly_components if component.visible] +
            [instance for instance in self.manager.assembly_instances if instance.visible] +
            [occurrence for occurrence in self.manager.component_occurrences if occurrence.visible]
        )

    def statistics(self):
        """Return assembly statistics."""

        stats = AssemblyStatistics(
            len(self.manager.assembly_documents),
            len(self.manager.assemblies),
            len([assembly for assembly in self.manager.assemblies if assembly.active]),
            len(self.manager.assembly_components),
            len(self.manager.assembly_instances) + len(self.manager.component_occurrences),
        )
        self.manager.assembly_statistics = stats
        self.manager.occurrence_manager.statistics()
        return stats

    def _refresh_links(self, item):
        if isinstance(item, Assembly):
            document = _find_by_id_or_name(self.manager.assembly_documents, item.document_id)
            if document is not None and item.id not in document.assembly_ids:
                document.assembly_ids.append(item.id)
        elif isinstance(item, AssemblyComponent):
            assembly = self.assembly_for(item.assembly_id)
            if assembly is not None and item.id not in assembly.component_ids:
                assembly.component_ids.append(item.id)
        elif isinstance(item, (AssemblyInstance, ComponentOccurrence)):
            assembly = self.assembly_for(item.assembly_id)
            if assembly is not None and item.id not in assembly.instance_ids:
                assembly.instance_ids.append(item.id)
            component = _find_by_id_or_name(self.manager.assembly_components, item.component_id)
            if component is not None and item.id not in component.instance_ids:
                component.instance_ids.append(item.id)


class OccurrenceManager:
    """Project-scoped occurrence statistics helper."""

    def __init__(self, manager):

        self.manager = manager

    def statistics(self):
        """Return occurrence statistics."""

        items = self.manager.assembly_instances + self.manager.component_occurrences
        stats = OccurrenceStatistics(
            len(self.manager.assembly_components),
            len(self.manager.assembly_instances),
            len(self.manager.component_occurrences),
            len([item for item in items if item.suppressed]),
            len([item for item in items if item.locked]),
        )
        self.manager.occurrence_statistics = stats
        return stats


class MateManager:
    """Project-scoped helper for assembly mate relationships; no solving is performed."""

    MATE_TYPES = {
        "Coincident", "Concentric", "Distance", "Angle", "Parallel",
        "Perpendicular", "Tangent", "Lock", "Limit", "Gear", "Cam",
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add mate or mate group metadata."""

        if isinstance(item, Mate):
            collection = self.manager.mates
        elif isinstance(item, MateGroup):
            collection = self.manager.mate_groups
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_mate(self, assembly, mate_type, entity_a, entity_b, distance=0.0, angle=0.0, name=None):
        """Create a stored mate relationship without solving."""

        assembly_id = getattr(assembly, "id", assembly) or ""
        definition = MateDefinition(
            mate_type if mate_type in self.MATE_TYPES else "Coincident",
            getattr(entity_a, "id", entity_a) or "",
            getattr(entity_b, "id", entity_b) or "",
            distance=distance,
            angle=angle,
        )
        mate = Mate(name or definition.mate_type, assembly_id, definition, MateMetadata())
        self.add_item(mate)
        self.manager.dependency_manager.add_edge(entity_a, mate, "MateReference")
        self.manager.dependency_manager.add_edge(entity_b, mate, "MateReference")
        return mate

    def mates_for_assembly(self, assembly):
        """Return mates assigned to an assembly."""

        assembly_id = getattr(assembly, "id", assembly)
        return [mate for mate in self.manager.mates if mate.assembly_id == assembly_id]

    def visible_objects(self):
        """Return visible mates for highlighting."""

        if not self.manager.visible:
            return []

        return [mate for mate in self.manager.mates if mate.visible]

    def statistics(self):
        """Return mate statistics."""

        stats = MateStatistics(
            len(self.manager.mates),
            len(self.manager.mate_groups),
            len([mate for mate in self.manager.mates if mate.enabled]),
            len([mate for mate in self.manager.mates if not mate.enabled]),
        )
        self.manager.mate_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, Mate):
            assembly = self.manager.assembly_manager.assembly_for(item.assembly_id)
            if assembly is not None and item.id not in assembly.mate_ids:
                assembly.mate_ids.append(item.id)
        elif isinstance(item, MateGroup):
            for mate_id in item.mate_ids:
                mate = _find_by_id_or_name(self.manager.mates, mate_id)
                if mate is not None:
                    self._refresh_links(mate)


class ExplodedViewManager:
    """Project-scoped helper for exploded view transform metadata."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add exploded view or exploded step metadata."""

        if isinstance(item, ExplodedView):
            collection = self.manager.exploded_views
        elif isinstance(item, ExplodedStep):
            collection = self.manager.exploded_steps
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_view(self, assembly, name="Exploded View", metadata=None):
        """Create an exploded view."""

        assembly_id = getattr(assembly, "id", assembly) or ""
        view = ExplodedView(name, assembly_id, metadata)
        self.add_item(view)
        self.manager.dependency_manager.add_edge(assembly, view, "ExplodedView")
        return view

    def add_step(self, view, instance, offset=None, rotation=None):
        """Add a transform-only exploded step."""

        view_id = getattr(view, "id", view) or ""
        step = ExplodedStep(
            view_id,
            getattr(instance, "id", instance) or "",
            len([item for item in self.manager.exploded_steps if item.exploded_view_id == view_id]),
            offset or Vector3(),
            rotation or Vector3(),
        )
        self.add_item(step)
        self.manager.dependency_manager.add_edge(instance, view, "ExplodedStep")
        return step

    def views_for_assembly(self, assembly):
        """Return exploded views assigned to an assembly."""

        assembly_id = getattr(assembly, "id", assembly)
        return [view for view in self.manager.exploded_views if view.assembly_id == assembly_id]

    def steps_for_view(self, view):
        """Return ordered steps for an exploded view."""

        view_id = getattr(view, "id", view)
        return sorted(
            [step for step in self.manager.exploded_steps if step.exploded_view_id == view_id],
            key=lambda item: item.order,
        )

    def visible_objects(self):
        """Return visible exploded views for highlighting."""

        if not self.manager.visible:
            return []

        return [view for view in self.manager.exploded_views if view.visible]

    def statistics(self):
        """Return exploded view statistics."""

        stats = ExplodedStatistics(
            len(self.manager.exploded_views),
            len(self.manager.exploded_steps),
            len([view for view in self.manager.exploded_views if view.active]),
        )
        self.manager.exploded_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, ExplodedView):
            assembly = self.manager.assembly_manager.assembly_for(item.assembly_id)
            if assembly is not None and item.id not in assembly.exploded_view_ids:
                assembly.exploded_view_ids.append(item.id)
        elif isinstance(item, ExplodedStep):
            view = _find_by_id_or_name(self.manager.exploded_views, item.exploded_view_id)
            if view is not None and item.id not in view.step_ids:
                view.step_ids.append(item.id)


class ConfigurationManager:
    """Project-scoped helper for assembly configurations."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add assembly configuration metadata."""

        if not isinstance(item, AssemblyConfiguration):
            return None

        if item not in self.manager.assembly_configurations:
            self.manager.assembly_configurations.append(item)

        assembly = self.manager.assembly_manager.assembly_for(item.assembly_id)
        if assembly is not None and item.id not in assembly.configuration_ids:
            assembly.configuration_ids.append(item.id)

        self.statistics()
        return item

    def create_configuration(self, assembly, name="Default", suppression_states=None, visibility_states=None):
        """Create an assembly configuration."""

        assembly_id = getattr(assembly, "id", assembly) or ""
        configuration = AssemblyConfiguration(name, assembly_id)
        configuration.suppression_states = dict(suppression_states or {})
        configuration.visibility_states = dict(visibility_states or {})
        self.add_item(configuration)
        self.manager.dependency_manager.add_edge(assembly, configuration, "AssemblyConfiguration")
        return configuration

    def set_active(self, configuration):
        """Set active assembly configuration."""

        target = _find_by_id_or_name(self.manager.assembly_configurations, getattr(configuration, "id", configuration))
        if target is None:
            return None

        for item in self.manager.assembly_configurations:
            if item.assembly_id == target.assembly_id:
                item.active = item is target
        assembly = self.manager.assembly_manager.assembly_for(target.assembly_id)
        if assembly is not None:
            assembly.settings.active_configuration_id = target.id
        self.statistics()
        return target

    def configurations_for_assembly(self, assembly):
        """Return configurations assigned to an assembly."""

        assembly_id = getattr(assembly, "id", assembly)
        return [item for item in self.manager.assembly_configurations if item.assembly_id == assembly_id]

    def statistics(self):
        """Return configuration statistics."""

        stats = ConfigurationStatistics(
            len(self.manager.assembly_configurations),
            len([item for item in self.manager.assembly_configurations if item.active]),
            sum(len(item.suppression_states) for item in self.manager.assembly_configurations),
            sum(len(item.visibility_states) for item in self.manager.assembly_configurations),
        )
        self.manager.configuration_statistics = stats
        return stats


class MechanicalLibraryManager:
    """Project-scoped helper for mechanical library metadata."""

    DEFAULT_CATEGORIES = [
        "Fasteners", "Bolts", "Nuts", "Washers", "Screws", "Pins",
        "Bearings", "Bushings", "Keys", "Retaining Rings", "Springs",
        "Gears", "Pulleys", "Belts", "Chains", "Sprockets", "Shafts",
        "Couplings", "Standard Hardware",
    ]

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add mechanical library metadata."""

        if isinstance(item, MechanicalLibrary):
            collection = self.manager.mechanical_libraries
        elif isinstance(item, MechanicalCategory):
            collection = self.manager.mechanical_library_categories
        elif isinstance(item, MechanicalComponent):
            collection = self.manager.mechanical_library_components
        elif isinstance(item, MechanicalFamily):
            collection = self.manager.mechanical_families
        elif isinstance(item, MechanicalStandard):
            collection = self.manager.mechanical_standards
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_library(self, name="Mechanical Library", metadata=None):
        """Create a mechanical library."""

        library = MechanicalLibrary(name, metadata)
        self.add_item(library)
        return library

    def create_category(self, library, name="Fasteners", metadata=None):
        """Create a mechanical category in a library."""

        category = MechanicalCategory(name, getattr(library, "id", library) or "", metadata)
        self.add_item(category)
        return category

    def create_family(self, library, category, name="Mechanical Family", metadata=None):
        """Create a mechanical family."""

        family = MechanicalFamily(
            name,
            getattr(library, "id", library) or "",
            getattr(category, "id", category) or "",
            metadata,
        )
        self.add_item(family)
        return family

    def create_standard(self, name="ISO", description=""):
        """Create a standard placeholder."""

        standard = MechanicalStandard(name, description)
        self.add_item(standard)
        return standard

    def create_component(self, library, category, family, product_part, name=None, standard=None, metadata=None):
        """Create a mechanical component referencing an existing ProductPart."""

        component = MechanicalComponent(
            name or getattr(product_part, "name", "Mechanical Component"),
            getattr(library, "id", library) or "",
            getattr(category, "id", category) or "",
            getattr(family, "id", family) or "",
            getattr(product_part, "id", product_part) or "",
            getattr(standard, "id", standard) or "",
            metadata,
        )
        self.add_item(component)
        self.manager.dependency_manager.add_edge(product_part, component, "MechanicalLibraryReference")
        return component

    def components_for_part(self, part):
        """Return mechanical components referencing a ProductPart."""

        part_id = getattr(part, "id", part)
        return [component for component in self.manager.mechanical_library_components if component.product_part_id == part_id]

    def components_for_library(self, library):
        """Return components assigned to a mechanical library."""

        library_id = getattr(library, "id", library)
        return [component for component in self.manager.mechanical_library_components if component.library_id == library_id]

    def visible_objects(self):
        """Return visible mechanical library objects for product rendering."""

        if not self.manager.visible:
            return []

        return (
            [item for item in self.manager.mechanical_libraries if item.visible] +
            [item for item in self.manager.mechanical_library_categories if item.visible] +
            [item for item in self.manager.mechanical_families if item.visible] +
            [item for item in self.manager.mechanical_library_components if item.visible]
        )

    def statistics(self):
        """Return mechanical library statistics."""

        stats = MechanicalStatistics(
            len(self.manager.mechanical_libraries),
            len(self.manager.mechanical_library_categories),
            len(self.manager.mechanical_library_components),
            len(self.manager.mechanical_families),
            len(self.manager.mechanical_standards),
            len([item for item in self.manager.mechanical_library_components if item.product_part_id]),
        )
        self.manager.mechanical_library_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, MechanicalCategory):
            library = _find_by_id_or_name(self.manager.mechanical_libraries, item.library_id)
            if library is not None and item.id not in library.category_ids:
                library.category_ids.append(item.id)
        elif isinstance(item, MechanicalFamily):
            library = _find_by_id_or_name(self.manager.mechanical_libraries, item.library_id)
            category = _find_by_id_or_name(self.manager.mechanical_library_categories, item.category_id)
            if library is not None and item.id not in library.family_ids:
                library.family_ids.append(item.id)
            if category is not None and item.id not in category.family_ids:
                category.family_ids.append(item.id)
        elif isinstance(item, MechanicalComponent):
            library = _find_by_id_or_name(self.manager.mechanical_libraries, item.library_id)
            category = _find_by_id_or_name(self.manager.mechanical_library_categories, item.category_id)
            family = _find_by_id_or_name(self.manager.mechanical_families, item.family_id)
            if library is not None and item.id not in library.component_ids:
                library.component_ids.append(item.id)
            if category is not None and item.id not in category.component_ids:
                category.component_ids.append(item.id)
            if family is not None and item.id not in family.component_ids:
                family.component_ids.append(item.id)
        elif isinstance(item, MechanicalStandard):
            for library in self.manager.mechanical_libraries:
                if item.id not in library.standard_ids:
                    library.standard_ids.append(item.id)


class SheetMetalManager:
    """Project-scoped helper for sheet metal part and flat-pattern metadata."""

    OPERATIONS = {
        "Convert to Sheet Metal", "Base Flange", "Edge Flange", "Bend",
        "Hem", "Jog", "Corner Relief", "Rip", "Unfold", "Flat Pattern",
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add sheet metal metadata."""

        if isinstance(item, SheetMetalPart):
            collection = self.manager.sheet_metal_parts
        elif isinstance(item, SheetMetalBody):
            collection = self.manager.sheet_metal_bodies
        elif isinstance(item, FlatPattern):
            collection = self.manager.flat_patterns
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def convert_part(self, product_part, rule=None, name=None):
        """Create a sheet metal part reference for an existing ProductPart."""

        part = SheetMetalPart(name or getattr(product_part, "name", "Sheet Metal Part"), getattr(product_part, "id", product_part) or "")
        part.rule_id = getattr(rule, "id", rule) or ""
        self.add_item(part)
        self.manager.dependency_manager.add_edge(product_part, part, "SheetMetalPartReference")
        if rule:
            self.manager.dependency_manager.add_edge(rule, part, "SheetMetalRuleReference")
        return part

    def create_body(self, sheet_metal_part, product_part, mesh_entity_id="", body=None, operation="Base Flange", name="Sheet Metal Body"):
        """Create sheet metal body metadata referencing existing geometry."""

        body_item = SheetMetalBody(
            name,
            getattr(sheet_metal_part, "id", sheet_metal_part) or "",
            getattr(product_part, "id", product_part) or "",
            mesh_entity_id or getattr(product_part, "mesh_entity_id", ""),
            getattr(body, "id", body) or "",
            SheetMetalMetadata(operation=operation),
        )
        self.add_item(body_item)
        self.manager.dependency_manager.add_edge(product_part, body_item, "SheetMetalBodyReference")
        if body:
            self.manager.dependency_manager.add_edge(body, body_item, "SheetMetalBodySource")
        return body_item

    def create_flat_pattern(self, sheet_metal_part, body=None, name="Flat Pattern"):
        """Create flat pattern metadata without generating geometry."""

        pattern = FlatPattern(
            name,
            getattr(sheet_metal_part, "id", sheet_metal_part) or "",
            getattr(body, "id", body) or "",
        )
        self.add_item(pattern)
        self.manager.dependency_manager.add_edge(body or sheet_metal_part, pattern, "FlatPatternReference")
        return pattern

    def parts_for_product_part(self, product_part):
        """Return sheet metal part records for a ProductPart."""

        part_id = getattr(product_part, "id", product_part)
        return [item for item in self.manager.sheet_metal_parts if item.product_part_id == part_id]

    def bodies_for_sheet_metal_part(self, sheet_metal_part):
        """Return sheet metal bodies for a sheet metal part."""

        part_id = getattr(sheet_metal_part, "id", sheet_metal_part)
        return [item for item in self.manager.sheet_metal_bodies if item.sheet_metal_part_id == part_id]

    def flat_patterns_for_sheet_metal_part(self, sheet_metal_part):
        """Return flat pattern metadata for a sheet metal part."""

        part_id = getattr(sheet_metal_part, "id", sheet_metal_part)
        return [item for item in self.manager.flat_patterns if item.sheet_metal_part_id == part_id]

    def visible_objects(self):
        """Return visible sheet metal objects for product rendering."""

        if not self.manager.visible:
            return []

        return (
            [item for item in self.manager.sheet_metal_parts if item.visible] +
            [item for item in self.manager.sheet_metal_bodies if item.visible] +
            [item for item in self.manager.flat_patterns if item.visible]
        )

    def statistics(self):
        """Return sheet metal statistics."""

        stats = SheetMetalStatistics(
            len(self.manager.sheet_metal_parts),
            len(self.manager.sheet_metal_bodies),
            len(self.manager.flat_patterns),
            len([item for item in self.manager.sheet_metal_bodies if item.metadata.operation in self.OPERATIONS]),
        )
        self.manager.sheet_metal_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, SheetMetalBody):
            part = _find_by_id_or_name(self.manager.sheet_metal_parts, item.sheet_metal_part_id)
            if part is not None and item.id not in part.body_ids:
                part.body_ids.append(item.id)
        elif isinstance(item, FlatPattern):
            part = _find_by_id_or_name(self.manager.sheet_metal_parts, item.sheet_metal_part_id)
            if part is not None:
                part.flat_pattern_id = item.id


