class ValidationManager:
    """Project-scoped product validation helper; stores rules and results only."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add validation session, category, rule or result."""

        if isinstance(item, ValidationSession):
            collection = self.manager.validation_sessions
        elif isinstance(item, ValidationCategory):
            collection = self.manager.validation_categories
        elif isinstance(item, ValidationRule):
            collection = self.manager.validation_rules
        elif isinstance(item, ValidationResult):
            collection = self.manager.validation_results
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_session(self, name="Validation Session", targets=None):
        """Create a validation session for existing product targets."""

        session = ValidationSession(name, [getattr(target, "id", target) for target in targets or []])
        self.add_item(session)
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, session, "ValidationTarget")
        return session

    def create_category(self, name="General", description=""):
        """Create a validation category."""

        category = ValidationCategory(name, description)
        self.add_item(category)
        return category

    def create_rule(self, name="Validation Rule", category=None, rule_type="General", severity="Info"):
        """Create a validation rule."""

        rule = ValidationRule(name, getattr(category, "id", category) or "", rule_type, severity)
        self.add_item(rule)
        return rule

    def run_validation(self, session, rules=None, targets=None):
        """Store validation results without performing simulation."""

        target_session = self.session_for(session)
        if target_session is None:
            return []

        active_rules = list(rules or self.manager.validation_rules)
        active_targets = list(targets or target_session.target_ids)
        results = []

        for rule in active_rules:
            rule_id = getattr(rule, "id", rule)
            if rule_id not in target_session.rule_ids:
                target_session.rule_ids.append(rule_id)
            for target in active_targets:
                target_id = getattr(target, "id", target)
                result = ValidationResult(
                    f"{getattr(rule, 'name', 'Validation Rule')} Result",
                    target_session.id,
                    rule_id,
                    target_id,
                    "Passed",
                    "Stored validation foundation result",
                    getattr(rule, "severity", "Info"),
                )
                self.add_item(result)
                self.manager.dependency_manager.add_edge(rule, result, "ValidationRuleResult")
                self.manager.dependency_manager.add_edge(target, result, "ValidationTargetResult")
                results.append(result)

        target_session.history.append(f"Run {len(results)} result(s)")
        target_session.metadata.status = "Completed"
        self.statistics()
        return results

    def session_for(self, session):
        """Return a validation session by object, ID or name."""

        if isinstance(session, ValidationSession):
            return session if session in self.manager.validation_sessions else None
        return _find_by_id_or_name(self.manager.validation_sessions, session)

    def results_for_session(self, session):
        """Return validation results for a session."""

        session_id = getattr(session, "id", session)
        return [result for result in self.manager.validation_results if result.session_id == session_id]

    def filter_results(self, status=None, severity=None):
        """Filter stored validation results."""

        return [
            result for result in self.manager.validation_results
            if (status is None or result.status == status) and (severity is None or result.severity == severity)
        ]

    def visible_objects(self):
        """Return visible validation objects for product rendering."""

        if not self.manager.visible:
            return []
        return (
            [item for item in self.manager.validation_sessions if item.visible] +
            [item for item in self.manager.validation_rules if item.visible] +
            [item for item in self.manager.validation_results if item.visible]
        )

    def statistics(self):
        """Return validation statistics."""

        stats = ValidationStatistics(
            len(self.manager.validation_sessions),
            len(self.manager.validation_rules),
            len(self.manager.validation_results),
            len([item for item in self.manager.validation_results if item.status == "Passed"]),
            len([item for item in self.manager.validation_results if item.status == "Failed"]),
            len([item for item in self.manager.validation_results if item.status == "Warning"]),
        )
        self.manager.product_validation_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, ValidationResult):
            session = self.session_for(item.session_id)
            if session is not None and item.id not in session.result_ids:
                session.result_ids.append(item.id)
            if session is not None and item.rule_id and item.rule_id not in session.rule_ids:
                session.rule_ids.append(item.rule_id)


class AnalysisManager:
    """Project-scoped product analysis metadata helper; no engineering solver is performed."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add product analysis result metadata."""

        if not isinstance(item, AnalysisResult):
            return None
        if item not in self.manager.analysis_results:
            self.manager.analysis_results.append(item)
        self.statistics()
        return item

    def create_analysis(self, target, name="Analysis Result", mass=0.0, volume=0.0, surface_area=0.0, material_usage=None):
        """Create a stored analysis result referencing an existing product target."""

        mass_properties = MassProperties(mass=mass, volume=volume)
        physical = PhysicalProperties(mass=mass, volume=volume, surface_area=surface_area)
        manufacturing = ManufacturingProperties(material_usage=dict(material_usage or {}))
        result = AnalysisResult(
            name,
            getattr(target, "id", target) or "",
            AnalysisMetadata("Physical", "Stored"),
            mass_properties,
            physical,
            manufacturing,
        )
        self.add_item(result)
        self.manager.dependency_manager.add_edge(target, result, "AnalysisReference")
        return result

    def results_for(self, target):
        """Return analysis results for a target."""

        target_id = getattr(target, "id", target)
        return [result for result in self.manager.analysis_results if result.target_id == target_id]

    def visible_objects(self):
        """Return visible analysis results for product rendering."""

        if not self.manager.visible:
            return []
        return [item for item in self.manager.analysis_results if item.visible]

    def statistics(self):
        """Return analysis statistics."""

        stats = AnalysisStatistics(
            len(self.manager.analysis_results),
            len([item for item in self.manager.analysis_results if item.mass_properties is not None]),
            len([item for item in self.manager.analysis_results if item.physical_properties is not None]),
            len([item for item in self.manager.analysis_results if item.manufacturing_properties is not None]),
        )
        self.manager.analysis_statistics = stats
        return stats


class ManufacturingValidationManager:
    """Project-scoped manufacturability metadata helper; no CAM or simulation is performed."""

    RULE_TYPES = {
        "Minimum Wall Thickness", "Draft Angle", "Undercut", "Sharp Edge Detection",
        "Small Feature Detection", "Hole Validation", "Thread Placeholder",
        "Tolerance Validation", "Material Compatibility", "Sheet Metal Rule Validation",
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add manufacturing readiness rule, report, profile or result."""

        if isinstance(item, ManufacturingRule):
            collection = self.manager.manufacturing_rules
        elif isinstance(item, ManufacturingReport):
            collection = self.manager.manufacturing_reports
        elif isinstance(item, ValidationProfile):
            collection = self.manager.manufacturing_validation_profiles
        elif isinstance(item, ManufacturingValidationResult):
            collection = self.manager.manufacturing_validation_results
        else:
            return None
        if item not in collection:
            collection.append(item)
        self.statistics()
        return item

    def create_profile(self, name="Manufacturing Validation Profile", references=None, status="Not Checked", properties=None):
        """Create manufacturing validation profile metadata."""

        profile = ValidationProfile(
            name,
            [getattr(item, "id", item) for item in references or []],
            ValidationMetadata(status=status, properties=properties or {}),
        )
        self.add_item(profile)
        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, profile, "ManufacturingValidationProfileReference")
        return profile

    def create_result(self, profile=None, job=None, readiness="Not Checked", issues=None, name="Manufacturing Validation Result"):
        """Create manufacturing validation result metadata only."""

        result = ManufacturingValidationResult(
            name,
            getattr(profile, "id", profile) or "",
            getattr(job, "id", job) or "",
            readiness,
            issues or [],
            ValidationMetadata(status=readiness),
        )
        self.add_item(result)
        for reference, relation in (
            (profile, "ManufacturingValidationProfileResult"),
            (job, "ManufacturingValidationJobReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, result, relation)
        return result

    def create_rule(self, name="Manufacturing Rule", rule_type="Minimum Wall Thickness", threshold=0.0, severity="Warning"):
        """Create a manufacturing readiness rule."""

        rule = ManufacturingRule(
            name,
            rule_type if rule_type in self.RULE_TYPES else "Minimum Wall Thickness",
            threshold,
            severity,
        )
        self.add_item(rule)
        return rule

    def create_report(self, target, rules=None, issues=None, name="Manufacturing Report"):
        """Create a manufacturing readiness report."""

        report = ManufacturingReport(
            name,
            getattr(target, "id", target) or "",
            [getattr(rule, "id", rule) for rule in rules or []],
            [getattr(issue, "id", issue) for issue in issues or []],
            ManufacturingMetadata(process="Manufacturing Readiness"),
        )
        self.add_item(report)
        self.manager.dependency_manager.add_edge(target, report, "ManufacturingReadinessReference")
        for rule in rules or []:
            self.manager.dependency_manager.add_edge(rule, report, "ManufacturingRuleReference")
        return report

    def reports_for(self, target):
        """Return manufacturing reports for a target."""

        target_id = getattr(target, "id", target)
        return [report for report in self.manager.manufacturing_reports if report.target_id == target_id]

    def visible_objects(self):
        """Return visible manufacturing report objects."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.manufacturing_reports +
                self.manager.manufacturing_validation_profiles +
                self.manager.manufacturing_validation_results
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return manufacturing readiness statistics."""

        stats = ManufacturingStatistics(
            len(self.manager.manufacturing_rules),
            len(self.manager.manufacturing_reports),
            len([rule for rule in self.manager.manufacturing_rules if rule.severity == "Warning"]),
            len([rule for rule in self.manager.manufacturing_rules if rule.severity in ("Error", "Failure")]),
        )
        self.manager.manufacturing_statistics = stats
        self.manager.manufacturing_job_validation_statistics = ValidationStatistics(
            0,
            len(self.manager.manufacturing_validation_profiles),
            len(self.manager.manufacturing_validation_results),
            len([result for result in self.manager.manufacturing_validation_results if result.readiness == "Ready"]),
            len([
                result for result in self.manager.manufacturing_validation_results
                for issue in result.issues
                if issue.severity in ("Error", "Failure")
            ]),
            len([
                result for result in self.manager.manufacturing_validation_results
                for issue in result.issues
                if issue.severity == "Warning"
            ]),
        )
        return stats


class ProductReportManager:
    """Project-scoped product report metadata helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add validation, analysis or generic product report metadata."""

        if not isinstance(item, ProductReport):
            return None
        if item not in self.manager.product_reports:
            self.manager.product_reports.append(item)
        self.statistics()
        return item

    def create_validation_report(self, target, sources=None, name="Validation Report"):
        """Create validation report metadata."""

        report = ValidationReport(name, getattr(target, "id", target) or "", [getattr(item, "id", item) for item in sources or []])
        self.add_item(report)
        self.manager.dependency_manager.add_edge(target, report, "ValidationReportReference")
        return report

    def create_analysis_report(self, target, sources=None, name="Analysis Report"):
        """Create analysis report metadata."""

        report = AnalysisReport(name, getattr(target, "id", target) or "", [getattr(item, "id", item) for item in sources or []])
        self.add_item(report)
        self.manager.dependency_manager.add_edge(target, report, "AnalysisReportReference")
        return report

    def reports_for(self, target):
        """Return product reports for a target."""

        target_id = getattr(target, "id", target)
        return [report for report in self.manager.product_reports if report.target_id == target_id]

    def visible_objects(self):
        """Return visible product reports."""

        if not self.manager.visible:
            return []
        return [item for item in self.manager.product_reports if item.visible]

    def statistics(self):
        """Return product report statistics."""

        stats = ReportStatistics(
            len(self.manager.product_reports),
            len([item for item in self.manager.product_reports if isinstance(item, ValidationReport)]),
            len(self.manager.manufacturing_reports),
            len([item for item in self.manager.product_reports if isinstance(item, AnalysisReport)]),
        )
        self.manager.product_report_statistics = stats
        return stats


class CAMManager:
    """Project-scoped CAM document and job foundation helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add CAM document, job, setup or operation metadata."""

        if isinstance(item, CAMDocument):
            collection = self.manager.cam_documents
            self.manager.active_cam_document_id = item.id
        elif isinstance(item, CAMJob):
            collection = self.manager.cam_jobs
            if item.active:
                self.activate_job(item)
        elif isinstance(item, ManufacturingSetup):
            collection = self.manager.cam_setups
        elif isinstance(item, OperationDefinition):
            collection = self.manager.cam_operations
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        self.manager.manufacturing_setup_manager.statistics()
        self.manager.operation_manager.statistics()
        return item

    def create_document(self, name="CAM Document", metadata=None):
        """Create a CAM document inside the existing product workspace."""

        document = CAMDocument(name, metadata)
        return self.add_item(document)

    def create_job(self, document=None, name="CAM Job", targets=None, metadata=None):
        """Create a CAM job that references existing product and mesh data."""

        document = self.document_for(document) or self.active_document()
        job = CAMJob(
            name,
            getattr(document, "id", "") or "",
            [getattr(target, "id", target) for target in targets or []],
            metadata,
        )
        self.add_item(job)
        self.activate_job(job)

        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, job, "CAMJobReference")

        return job

    def document_for(self, document):
        """Return a CAM document by object, id or name."""

        if isinstance(document, CAMDocument):
            return document if document in self.manager.cam_documents else None

        return _find_by_id_or_name(self.manager.cam_documents, document)

    def job_for(self, job):
        """Return a CAM job by object, id or name."""

        if isinstance(job, CAMJob):
            return job if job in self.manager.cam_jobs else None

        return _find_by_id_or_name(self.manager.cam_jobs, job)

    def active_document(self):
        """Return the active CAM document."""

        return (
            self.document_for(self.manager.active_cam_document_id) or
            (self.manager.cam_documents[-1] if self.manager.cam_documents else None)
        )

    def active_job(self):
        """Return the active CAM job."""

        return (
            self.job_for(self.manager.active_cam_job_id) or
            next((job for job in self.manager.cam_jobs if job.active), None)
        )

    def rename_job(self, job, name):
        """Rename a CAM job without changing its references."""

        target = self.job_for(job)
        if target is not None:
            target.name = name
        return target

    def delete_job(self, job):
        """Delete a CAM job through ProductManager unlinking."""

        target = self.job_for(job)
        return self.manager.remove_object(target) if target is not None else False

    def activate_job(self, job):
        """Activate one CAM job and deactivate sibling jobs."""

        target = self.job_for(job) or job
        if target is None:
            return None

        for item in self.manager.cam_jobs:
            item.active = item is target or item.id == getattr(target, "id", target)

        self.manager.active_cam_job_id = getattr(target, "id", None)

        document = self.document_for(getattr(target, "document_id", ""))
        if document is not None:
            self.manager.active_cam_document_id = document.id
            document.active_job_id = target.id

        return target

    def jobs_for_document(self, document):
        """Return CAM jobs assigned to a CAM document."""

        document_id = getattr(document, "id", document)
        return [job for job in self.manager.cam_jobs if job.document_id == document_id]

    def setups_for_job(self, job):
        """Return manufacturing setups assigned to a CAM job."""

        return self.manager.manufacturing_setup_manager.setups_for_job(job)

    def operations_for_job(self, job):
        """Return operation definitions assigned to a CAM job."""

        return self.manager.operation_manager.operations_for_job(job)

    def visible_objects(self):
        """Return visible CAM metadata for selection and highlighting."""

        if not self.manager.visible:
            return []

        return [
            item for item in (
                self.manager.cam_documents +
                self.manager.cam_jobs +
                self.manager.cam_setups +
                self.manager.cam_operations
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return CAM job statistics."""

        stats = CAMStatistics(
            len(self.manager.cam_documents),
            len(self.manager.cam_jobs),
            len([job for job in self.manager.cam_jobs if job.active]),
            len(self.manager.cam_setups),
            len(self.manager.cam_operations),
        )
        self.manager.cam_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, CAMJob):
            document = self.document_for(item.document_id)
            if document is not None and item.id not in document.job_ids:
                document.job_ids.append(item.id)
        elif isinstance(item, ManufacturingSetup):
            job = self.job_for(item.job_id)
            if job is not None and item.id not in job.setup_ids:
                job.setup_ids.append(item.id)
        elif isinstance(item, OperationDefinition):
            job = self.job_for(item.job_id)
            if job is not None and item.id not in job.operation_ids:
                job.operation_ids.append(item.id)


class ManufacturingSetupManager:
    """Project-scoped CAM manufacturing setup foundation helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add a manufacturing setup through the CAM manager."""

        if not isinstance(item, ManufacturingSetup):
            return None
        return self.manager.cam_manager.add_item(item)

    def create_setup(self, job, targets=None, stock_type="Box", material=None, name="Setup"):
        """Create a manufacturing setup that references existing geometry only."""

        target_ids = [getattr(target, "id", target) for target in targets or []]
        material_id = getattr(material, "id", material) or ""
        stock = StockDefinition(stock_type, target_ids, material_id=material_id)
        setup = ManufacturingSetup(name, getattr(job, "id", job) or "", stock)
        self.add_item(setup)

        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, setup, "CAMSetupReference")
        if material:
            self.manager.dependency_manager.add_edge(material, setup, "CAMMaterialReference")

        return setup

    def setup_for(self, setup):
        """Return a manufacturing setup by object, id or name."""

        if isinstance(setup, ManufacturingSetup):
            return setup if setup in self.manager.cam_setups else None

        return _find_by_id_or_name(self.manager.cam_setups, setup)

    def setups_for_job(self, job):
        """Return setups assigned to a CAM job."""

        job_id = getattr(job, "id", job)
        return [setup for setup in self.manager.cam_setups if setup.job_id == job_id]

    def statistics(self):
        """Return manufacturing setup statistics."""

        stock_types = {}
        fixtures = 0

        for setup in self.manager.cam_setups:
            stock_type = getattr(getattr(setup, "stock", None), "stock_type", "Box")
            stock_types[stock_type] = stock_types.get(stock_type, 0) + 1
            if getattr(getattr(setup, "fixture", None), "reference_ids", []):
                fixtures += 1

        stats = SetupStatistics(
            len(self.manager.cam_setups),
            stock_types.get("Box", 0),
            stock_types.get("Cylinder", 0),
            fixtures,
        )
        self.manager.setup_statistics = stats
        return stats


class OperationManager:
    """Project-scoped CAM operation definition helper."""

    OPERATION_TYPES = {
        "Facing", "Pocket", "Contour", "Drill", "Adaptive", "Parallel",
        "Waterline", "Laser", "Plasma", "Router", "3D Printing",
        "Slot", "Adaptive Clearing", "Rest Machining", "Peck Drill",
        "Bore", "CounterBore", "CounterSink", "Tap", "Thread Mill",
        "Scallop", "Pencil", "Horizontal", "Vertical",
        "Rest Machining 3 Axis", "Morph", "Flow", "Projection",
        "Vector Cut", "Vector Engrave", "Raster Engrave", "Raster Fill",
        "Image Engrave", "Score", "Mark", "Plasma Cut", "Pierce",
        "Lead In", "Lead Out",
        "Profile Cut", "Inside Profile", "Outside Profile", "Centerline",
        "Pocket Router", "V-Carve", "Engrave Router", "Chamfer Router",
        "Surfacing", "Adaptive Router",
    }
    OPERATION_CLASSES = {
        "Facing": FacingOperation,
        "Pocket": PocketOperation,
        "Contour": ContourOperation,
        "Slot": SlotOperation,
        "Adaptive": AdaptiveClearingOperation,
        "Adaptive Clearing": AdaptiveClearingOperation,
        "Rest Machining": RestMachiningOperation,
        "Drill": DrillOperation,
        "Peck Drill": PeckDrillOperation,
        "Bore": BoreOperation,
        "CounterBore": CounterBoreOperation,
        "CounterSink": CounterSinkOperation,
        "Tap": TapOperation,
        "Thread Mill": ThreadMillOperation,
        "Parallel": ParallelOperation,
        "Waterline": WaterlineOperation,
        "Scallop": ScallopOperation,
        "Pencil": PencilOperation,
        "Horizontal": HorizontalOperation,
        "Vertical": VerticalOperation,
        "Rest Machining 3 Axis": RestMachining3AxisOperation,
        "Morph": MorphOperation,
        "Flow": FlowOperation,
        "Projection": ProjectionOperation,
        "Vector Cut": VectorCutOperation,
        "Vector Engrave": VectorEngraveOperation,
        "Raster Engrave": RasterEngraveOperation,
        "Raster Fill": RasterFillOperation,
        "Image Engrave": ImageEngraveOperation,
        "Score": ScoreOperation,
        "Mark": MarkOperation,
        "Plasma Cut": PlasmaCutOperation,
        "Pierce": PierceOperation,
        "Lead In": LeadInOperation,
        "Lead Out": LeadOutOperation,
        "Profile Cut": ProfileCutOperation,
        "Inside Profile": InsideProfileOperation,
        "Outside Profile": OutsideProfileOperation,
        "Centerline": CenterlineOperation,
        "Pocket Router": PocketRouterOperation,
        "V-Carve": VCarveOperation,
        "Engrave Router": EngraveRouterOperation,
        "Chamfer Router": ChamferRouterOperation,
        "Surfacing": SurfacingOperation,
        "Adaptive Router": AdaptiveRouterOperation,
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add an operation definition through the CAM manager."""

        if not isinstance(item, OperationDefinition):
            return None
        return self.manager.cam_manager.add_item(item)

    def create_operation(self, job, setup=None, operation_type="Facing", targets=None, name=None, parameters=None, tool=None, feed_speed_profile=None, group="", order=None):
        """Create an operation definition only; no toolpaths are generated."""

        if operation_type not in self.OPERATION_TYPES:
            operation_type = "Facing"

        operation_class = self.OPERATION_CLASSES.get(operation_type, OperationDefinition)
        parameters = parameters or OperationParameters()
        if tool is not None:
            parameters.tool_id = getattr(tool, "id", tool) or ""
        if feed_speed_profile is not None:
            parameters.feed_speed_profile_id = getattr(feed_speed_profile, "id", feed_speed_profile) or ""

        metadata = OperationMetadata(
            group=group,
            order=int(order) if order is not None else len(self.operations_for_job(job)),
        )

        operation = operation_class(
            name or f"{operation_type} Operation",
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            operation_type,
            [getattr(target, "id", target) for target in targets or []],
            parameters,
            metadata,
        )
        self.add_item(operation)

        if setup is not None:
            self.manager.dependency_manager.add_edge(setup, operation, "CAMOperationSetupReference")
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, operation, "CAMOperationReference")
        if tool is not None:
            self.manager.dependency_manager.add_edge(tool, operation, "CAMOperationToolReference")
        if feed_speed_profile is not None:
            self.manager.dependency_manager.add_edge(feed_speed_profile, operation, "CAMOperationFeedSpeedReference")

        return operation

    def create_milling_operation(self, job, setup=None, operation_type="Facing", targets=None, name=None, tool=None, feed_speed_profile=None, **kwargs):
        """Create a 2.5-axis milling operation definition only."""

        parameters = OperationParameters(
            tool_id=getattr(tool, "id", tool) or "",
            feed_speed_profile_id=getattr(feed_speed_profile, "id", feed_speed_profile) or "",
            depth=float(kwargs.get("depth", 0.0)),
            step_down=float(kwargs.get("step_down", 0.0)),
            stepover=float(kwargs.get("stepover", kwargs.get("step_over", 0.0))),
            finish_pass=bool(kwargs.get("finish_pass", False)),
            rough_pass=bool(kwargs.get("rough_pass", True)),
            allowance=float(kwargs.get("allowance", 0.0)),
            lead_in_placeholder=bool(kwargs.get("lead_in_placeholder", True)),
            lead_out_placeholder=bool(kwargs.get("lead_out_placeholder", True)),
            ramp_placeholder=bool(kwargs.get("ramp_placeholder", True)),
            helix_placeholder=bool(kwargs.get("helix_placeholder", True)),
        )
        return self.create_operation(
            job,
            setup,
            operation_type,
            targets,
            name,
            parameters,
            tool,
            feed_speed_profile,
            kwargs.get("group", ""),
            kwargs.get("order"),
        )

    def create_hole_operation(self, job, setup=None, operation_type="Drill", targets=None, name=None, tool=None, feed_speed_profile=None, **kwargs):
        """Create a 2.5-axis hole operation definition only."""

        parameters = OperationParameters(
            tool_id=getattr(tool, "id", tool) or "",
            feed_speed_profile_id=getattr(feed_speed_profile, "id", feed_speed_profile) or "",
            hole_depth=float(kwargs.get("hole_depth", kwargs.get("depth", 0.0))),
            retract_height=float(kwargs.get("retract_height", 0.0)),
            peck_depth=float(kwargs.get("peck_depth", 0.0)),
            coolant_placeholder=bool(kwargs.get("coolant_placeholder", True)),
            cycle_type=kwargs.get("cycle_type", operation_type),
        )
        return self.create_operation(
            job,
            setup,
            operation_type,
            targets,
            name,
            parameters,
            tool,
            feed_speed_profile,
            kwargs.get("group", ""),
            kwargs.get("order"),
        )

    def create_3_axis_operation(self, job, setup=None, operation_type="Parallel", targets=None, name=None, tool=None, feed_speed_profile=None, surface_selection=None, machining_region=None, boundaries=None, **kwargs):
        """Create a 3-axis operation definition only; no toolpaths are generated."""

        if operation_type not in self.OPERATION_TYPES:
            operation_type = "Parallel"

        operation_class = self.OPERATION_CLASSES.get(operation_type, ThreeAxisOperation)
        tool_id = getattr(tool, "id", tool) or ""
        feed_id = getattr(feed_speed_profile, "id", feed_speed_profile) or ""
        parameters = OperationParameters(
            tool_id=tool_id,
            feed_speed_profile_id=feed_id,
            step_down=float(kwargs.get("stepdown", kwargs.get("step_down", 0.0))),
            stepover=float(kwargs.get("stepover", kwargs.get("step_over", 0.0))),
            allowance=float(kwargs.get("allowance", 0.0)),
        )
        metadata = OperationMetadata(
            group=kwargs.get("group", ""),
            order=int(kwargs.get("order")) if kwargs.get("order") is not None else len(self.operations_for_job(job)),
            properties=dict(kwargs.get("properties", {})),
        )
        strategy = ThreeAxisStrategy(
            operation_type,
            float(kwargs.get("tolerance", 0.01)),
            parameters.stepover,
            parameters.step_down,
            float(kwargs.get("maximum_cusp_height", kwargs.get("cusp_height", 0.0))),
            kwargs.get("boundary_mode", "Contact"),
            kwargs.get("cut_direction", "One Way"),
            bool(kwargs.get("climb", True)),
            bool(kwargs.get("conventional", False)),
            tool_id,
            feed_id,
            dict(kwargs.get("strategy_properties", {})),
        )
        three_axis_metadata = ThreeAxisMetadata(
            kwargs.get("strategy_group", kwargs.get("group", "")),
            getattr(surface_selection, "id", surface_selection) or "",
            getattr(machining_region, "id", machining_region) or "",
            [getattr(boundary, "id", boundary) for boundary in boundaries or []],
            dict(kwargs.get("three_axis_properties", {})),
        )
        operation = operation_class(
            name or f"{operation_type} Operation",
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            operation_type,
            [getattr(target, "id", target) for target in targets or []],
            parameters,
            metadata,
            strategy,
            three_axis_metadata,
        )
        self.add_item(operation)

        if setup is not None:
            self.manager.dependency_manager.add_edge(setup, operation, "ThreeAxisSetupReference")
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, operation, "ThreeAxisOperationReference")
        if tool is not None:
            self.manager.dependency_manager.add_edge(tool, operation, "ThreeAxisToolReference")
        if feed_speed_profile is not None:
            self.manager.dependency_manager.add_edge(feed_speed_profile, operation, "ThreeAxisFeedSpeedReference")
        if surface_selection is not None:
            self.manager.dependency_manager.add_edge(surface_selection, operation, "ThreeAxisSurfaceSelectionReference")
        if machining_region is not None:
            self.manager.dependency_manager.add_edge(machining_region, operation, "ThreeAxisMachiningRegionReference")
        for boundary in boundaries or []:
            self.manager.dependency_manager.add_edge(boundary, operation, "ThreeAxisBoundaryReference")

        self.statistics()
        return operation

    def create_laser_operation(self, job, setup=None, operation_type="Vector Cut", targets=None, name=None, tool=None, material_profile=None, cutting_profile=None, power_profile=None, feed_speed_profile=None, **kwargs):
        """Create a laser operation definition only; no toolpaths are generated."""

        if operation_type not in self.OPERATION_TYPES:
            operation_type = "Vector Cut"

        operation_class = self.OPERATION_CLASSES.get(operation_type, VectorCutOperation)
        tool_id = getattr(tool, "id", tool) or ""
        profile_id = getattr(feed_speed_profile, "id", feed_speed_profile) or ""
        material_profile_id = getattr(material_profile, "id", material_profile) or ""
        cutting_profile_id = getattr(cutting_profile, "id", cutting_profile) or ""
        power_profile_id = getattr(power_profile, "id", power_profile) or ""
        parameters = OperationParameters(
            tool_id=tool_id,
            feed_speed_profile_id=profile_id,
            depth=float(kwargs.get("depth", 0.0)),
        )
        parameters.properties = dict(getattr(parameters, "properties", {}))
        parameters.properties.update({
            "laser_power": float(kwargs.get("laser_power", 0.0)),
            "minimum_power": float(kwargs.get("minimum_power", 0.0)),
            "maximum_power": float(kwargs.get("maximum_power", 0.0)),
            "cut_speed": float(kwargs.get("cut_speed", 0.0)),
            "travel_speed": float(kwargs.get("travel_speed", 0.0)),
            "pass_count": int(kwargs.get("pass_count", 1)),
            "focus_offset": float(kwargs.get("focus_offset", 0.0)),
            "air_assist_placeholder": bool(kwargs.get("air_assist_placeholder", True)),
        })
        metadata = OperationMetadata(
            group=kwargs.get("group", ""),
            order=int(kwargs.get("order")) if kwargs.get("order") is not None else len(self.operations_for_job(job)),
            properties=dict(kwargs.get("properties", {})),
        )
        laser_metadata = LaserPlasmaMetadata(
            "Laser",
            material_profile_id,
            cutting_profile_id,
            power_profile_id,
            "",
            "",
            kwargs.get("group", ""),
            bool(kwargs.get("multi_head_placeholder", True)),
            dict(kwargs.get("laser_properties", {})),
        )
        operation = operation_class(
            name or f"{operation_type} Operation",
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            operation_type,
            [getattr(target, "id", target) for target in targets or []],
            parameters,
            metadata,
            laser_metadata,
        )
        self.add_item(operation)
        self._store_laser_plasma_dependencies(operation, setup, targets, tool, feed_speed_profile, material_profile, cutting_profile, power_profile)
        self.statistics()
        return operation

    def create_plasma_operation(self, job, setup=None, operation_type="Plasma Cut", targets=None, name=None, tool=None, material_profile=None, cutting_profile=None, feed_speed_profile=None, gas_profile=None, cooling_profile=None, **kwargs):
        """Create a plasma operation definition only; no toolpaths are generated."""

        if operation_type not in self.OPERATION_TYPES:
            operation_type = "Plasma Cut"

        operation_class = self.OPERATION_CLASSES.get(operation_type, PlasmaCutOperation)
        tool_id = getattr(tool, "id", tool) or ""
        profile_id = getattr(feed_speed_profile, "id", feed_speed_profile) or ""
        material_profile_id = getattr(material_profile, "id", material_profile) or ""
        cutting_profile_id = getattr(cutting_profile, "id", cutting_profile) or ""
        gas_profile_id = getattr(gas_profile, "id", gas_profile) or ""
        cooling_profile_id = getattr(cooling_profile, "id", cooling_profile) or ""
        parameters = OperationParameters(
            tool_id=tool_id,
            feed_speed_profile_id=profile_id,
        )
        parameters.properties = dict(getattr(parameters, "properties", {}))
        parameters.properties.update({
            "pierce_height": float(kwargs.get("pierce_height", 0.0)),
            "cut_height": float(kwargs.get("cut_height", 0.0)),
            "kerf_width": float(kwargs.get("kerf_width", 0.0)),
            "pierce_delay": float(kwargs.get("pierce_delay", 0.0)),
            "lead_radius": float(kwargs.get("lead_radius", 0.0)),
            "lead_angle": float(kwargs.get("lead_angle", 0.0)),
            "cut_direction": kwargs.get("cut_direction", "Climb"),
        })
        metadata = OperationMetadata(
            group=kwargs.get("group", ""),
            order=int(kwargs.get("order")) if kwargs.get("order") is not None else len(self.operations_for_job(job)),
            properties=dict(kwargs.get("properties", {})),
        )
        plasma_metadata = LaserPlasmaMetadata(
            "Plasma",
            material_profile_id,
            cutting_profile_id,
            "",
            gas_profile_id,
            cooling_profile_id,
            kwargs.get("group", ""),
            bool(kwargs.get("multi_head_placeholder", True)),
            dict(kwargs.get("plasma_properties", {})),
        )
        kerf = KerfCompensation(float(kwargs.get("kerf_width", 0.0)), kwargs.get("kerf_side", "Center"), bool(kwargs.get("kerf_enabled", True)))
        quality = CutQuality(kwargs.get("cut_quality", "Standard"), float(kwargs.get("quality_tolerance", 0.0)), bool(kwargs.get("dross_placeholder", True)))
        torch = TorchHeightControl(
            bool(kwargs.get("torch_height_control_placeholder", False)),
            float(kwargs.get("pierce_height", 0.0)),
            float(kwargs.get("cut_height", 0.0)),
        )
        operation = operation_class(
            name or f"{operation_type} Operation",
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            operation_type,
            [getattr(target, "id", target) for target in targets or []],
            parameters,
            metadata,
            plasma_metadata,
            kerf,
            quality,
            torch,
        )
        self.add_item(operation)
        self._store_laser_plasma_dependencies(operation, setup, targets, tool, feed_speed_profile, material_profile, cutting_profile, gas_profile, cooling_profile)
        self.statistics()
        return operation

    def _store_laser_plasma_dependencies(self, operation, setup=None, targets=None, tool=None, feed_speed_profile=None, *profiles):
        """Store relationship metadata only for laser/plasma operations."""

        if setup is not None:
            self.manager.dependency_manager.add_edge(setup, operation, "LaserPlasmaSetupReference")
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, operation, "LaserPlasmaOperationReference")
        if tool is not None:
            self.manager.dependency_manager.add_edge(tool, operation, "LaserPlasmaToolReference")
        if feed_speed_profile is not None:
            self.manager.dependency_manager.add_edge(feed_speed_profile, operation, "LaserPlasmaFeedSpeedReference")
        for profile in profiles:
            if profile is not None:
                self.manager.dependency_manager.add_edge(profile, operation, "LaserPlasmaProfileReference")

    def create_router_operation(self, job, setup=None, operation_type="Profile Cut", targets=None, name=None, tool=None, tool_preset=None, feed_speed_profile=None, router_profile=None, fixtures=None, clamp_avoidance_regions=None, material_profile=None, **kwargs):
        """Create a CNC router operation definition only; no toolpaths are generated."""

        if operation_type not in self.OPERATION_TYPES:
            operation_type = "Profile Cut"

        operation_class = self.OPERATION_CLASSES.get(operation_type, ProfileCutOperation)
        tool_id = getattr(tool, "id", tool) or ""
        preset_id = getattr(tool_preset, "id", tool_preset) or ""
        feed_id = getattr(feed_speed_profile, "id", feed_speed_profile) or ""
        parameters = OperationParameters(
            tool_id=tool_id,
            tool_preset_id=preset_id,
            feed_speed_profile_id=feed_id,
            depth=float(kwargs.get("cut_depth", kwargs.get("depth", 0.0))),
            step_down=float(kwargs.get("step_down", 0.0)),
            stepover=float(kwargs.get("step_over", kwargs.get("stepover", 0.0))),
            rough_pass=bool(kwargs.get("rough_pass", True)),
            finish_pass=bool(kwargs.get("finish_pass", False)),
        )
        parameters.properties = dict(getattr(parameters, "properties", {}))
        parameters.properties.update({
            "cut_depth": float(kwargs.get("cut_depth", kwargs.get("depth", 0.0))),
            "multiple_passes": bool(kwargs.get("multiple_passes", True)),
            "pass_count": int(kwargs.get("pass_count", 1)),
            "conventional": bool(kwargs.get("conventional", False)),
            "climb": bool(kwargs.get("climb", True)),
            "material_direction_placeholder": kwargs.get("material_direction_placeholder", ""),
        })
        metadata = OperationMetadata(
            group=kwargs.get("group", ""),
            order=int(kwargs.get("order")) if kwargs.get("order") is not None else len(self.operations_for_job(job)),
            properties=dict(kwargs.get("properties", {})),
        )
        profile = router_profile or RouterMetadataProfile(
            name=f"{operation_type} Router Profile",
            safe_height=SafeHeight(float(kwargs.get("safe_height", 0.0))),
            clearance_height=ClearanceHeight(float(kwargs.get("clearance_height", 0.0))),
            retract_height=RetractHeight(float(kwargs.get("retract_height", 0.0))),
            lead_in=LeadInMetadata(
                bool(kwargs.get("lead_in_enabled", True)),
                float(kwargs.get("lead_radius", 0.0)),
                float(kwargs.get("lead_angle", 0.0)),
                kwargs.get("lead_style", "Line"),
            ),
            lead_out=LeadOutMetadata(
                bool(kwargs.get("lead_out_enabled", True)),
                float(kwargs.get("lead_out_radius", kwargs.get("lead_radius", 0.0))),
                float(kwargs.get("lead_out_angle", kwargs.get("lead_angle", 0.0))),
                kwargs.get("lead_out_style", "Line"),
            ),
            ramp=RampStrategy(kwargs.get("ramp_strategy", "Linear"), float(kwargs.get("ramp_angle", 0.0)), float(kwargs.get("ramp_length", 0.0))),
            plunge=PlungeStrategy(kwargs.get("plunge_strategy", "Direct"), float(kwargs.get("plunge_feed_rate", 0.0))),
            tabs=TabDefinition(bool(kwargs.get("tabs_enabled", False)), float(kwargs.get("tab_width", 0.0)), float(kwargs.get("tab_height", 0.0)), int(kwargs.get("tab_count", 0))),
            bridges=BridgeDefinition(bool(kwargs.get("bridges_enabled", False)), float(kwargs.get("bridge_width", 0.0)), float(kwargs.get("bridge_height", 0.0)), int(kwargs.get("bridge_count", 0))),
            onion_skin=OnionSkinDefinition(bool(kwargs.get("onion_skin_enabled", False)), float(kwargs.get("onion_skin_thickness", 0.0))),
            dust_collection_id=getattr(kwargs.get("dust_collection_profile"), "id", kwargs.get("dust_collection_profile", "")) or "",
            properties=dict(kwargs.get("router_profile_properties", {})),
        )
        router_metadata = RouterMetadata(
            getattr(kwargs.get("router_job"), "id", kwargs.get("router_job", "")) or "",
            getattr(material_profile, "id", material_profile) or "",
            [getattr(fixture, "id", fixture) for fixture in fixtures or []],
            [getattr(region, "id", region) for region in clamp_avoidance_regions or []],
            kwargs.get("material_direction_placeholder", ""),
            bool(kwargs.get("multi_spindle_placeholder", True)),
            dict(kwargs.get("router_properties", {})),
        )
        operation = operation_class(
            name or f"{operation_type} Operation",
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            operation_type,
            [getattr(target, "id", target) for target in targets or []],
            parameters,
            metadata,
            router_metadata,
            profile,
        )
        self.add_item(operation)
        self._store_router_dependencies(operation, setup, targets, tool, tool_preset, feed_speed_profile, material_profile, fixtures, clamp_avoidance_regions)
        self.statistics()
        return operation

    def _store_router_dependencies(self, operation, setup=None, targets=None, tool=None, tool_preset=None, feed_speed_profile=None, material_profile=None, fixtures=None, clamp_avoidance_regions=None):
        """Store relationship metadata only for router operations."""

        if setup is not None:
            self.manager.dependency_manager.add_edge(setup, operation, "RouterSetupReference")
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, operation, "RouterOperationReference")
        if tool is not None:
            self.manager.dependency_manager.add_edge(tool, operation, "RouterToolReference")
        if tool_preset is not None:
            self.manager.dependency_manager.add_edge(tool_preset, operation, "RouterToolPresetReference")
        if feed_speed_profile is not None:
            self.manager.dependency_manager.add_edge(feed_speed_profile, operation, "RouterFeedSpeedReference")
        if material_profile is not None:
            self.manager.dependency_manager.add_edge(material_profile, operation, "RouterMaterialProfileReference")
        for fixture in fixtures or []:
            self.manager.dependency_manager.add_edge(fixture, operation, "RouterFixtureReference")
        for region in clamp_avoidance_regions or []:
            self.manager.dependency_manager.add_edge(region, operation, "RouterClampAvoidanceReference")

    def set_enabled(self, operation, enabled=True):
        """Enable or disable an operation definition."""

        target = self.operation_for(operation)
        if target is not None:
            target.metadata.enabled = bool(enabled)
        return target

    def rename_operation(self, operation, name):
        """Rename an operation definition."""

        target = self.operation_for(operation)
        if target is not None:
            target.name = name
        return target

    def set_group(self, operation, group):
        """Assign an operation grouping label."""

        target = self.operation_for(operation)
        if target is not None:
            target.metadata.group = group
        return target

    def operation_for(self, operation):
        """Return an operation definition by object, id or name."""

        if isinstance(operation, OperationDefinition):
            return operation if operation in self.manager.cam_operations else None

        return _find_by_id_or_name(self.manager.cam_operations, operation)

    def operations_for_job(self, job):
        """Return operation definitions assigned to a CAM job."""

        job_id = getattr(job, "id", job)
        return sorted(
            [operation for operation in self.manager.cam_operations if operation.job_id == job_id],
            key=lambda operation: getattr(getattr(operation, "metadata", None), "order", 0),
        )

    def operations_for_setup(self, setup):
        """Return operation definitions assigned to a setup."""

        setup_id = getattr(setup, "id", setup)
        return [operation for operation in self.manager.cam_operations if operation.setup_id == setup_id]

    def statistics(self):
        """Return operation definition statistics."""

        by_type = {}
        milling_types = {"Facing", "Pocket", "Contour", "Slot", "Adaptive Clearing", "Rest Machining"}
        hole_types = {"Drill", "Peck Drill", "Bore", "CounterBore", "CounterSink", "Tap", "Thread Mill"}
        three_axis_operations = [
            operation for operation in self.manager.cam_operations
            if getattr(operation, "is_three_axis_operation", False)
        ]
        laser_operations = [
            operation for operation in self.manager.cam_operations
            if getattr(operation, "is_laser_operation", False)
        ]
        plasma_operations = [
            operation for operation in self.manager.cam_operations
            if getattr(operation, "is_plasma_operation", False)
        ]
        router_operations = [
            operation for operation in self.manager.cam_operations
            if getattr(operation, "is_router_operation", False)
        ]

        for operation in self.manager.cam_operations:
            by_type[operation.operation_type] = by_type.get(operation.operation_type, 0) + 1

        stats = OperationStatistics(
            len(self.manager.cam_operations),
            len(self.manager.cam_operations),
            by_type.get("Laser", 0),
            by_type.get("Plasma", 0),
            by_type.get("Router", 0),
            by_type.get("3D Printing", 0),
            len([operation for operation in self.manager.cam_operations if operation.operation_type in milling_types]),
            len([operation for operation in self.manager.cam_operations if operation.operation_type in hole_types]),
            len([operation for operation in self.manager.cam_operations if not operation.metadata.enabled]),
        )
        self.manager.operation_statistics = stats
        self.manager.three_axis_statistics = ThreeAxisStatistics(
            len(three_axis_operations),
            len([operation for operation in three_axis_operations if getattr(operation, "strategy", None) is not None]),
            len([operation for operation in three_axis_operations if not getattr(getattr(operation, "metadata", None), "enabled", True)]),
            len(self.manager.three_axis_surface_selections) + len(self.manager.three_axis_machining_regions),
            len(self.manager.three_axis_boundaries),
        )
        self.manager.laser_plasma_statistics = LaserPlasmaStatistics(
            len(self.manager.laser_jobs),
            len(self.manager.plasma_jobs),
            len(laser_operations),
            len(plasma_operations),
            len(self.manager.material_profiles),
            len(self.manager.cutting_profiles),
            len([
                operation for operation in laser_operations + plasma_operations
                if not getattr(getattr(operation, "metadata", None), "enabled", True)
            ]),
        )
        self.manager.router_statistics = RouterStatistics(
            len(self.manager.router_jobs),
            len(router_operations),
            len(self.manager.router_fixtures),
            len(self.manager.clamp_avoidance_regions),
            len(self.manager.router_metadata_profiles),
            len([
                operation for operation in router_operations
                if not getattr(getattr(operation, "metadata", None), "enabled", True)
            ]),
        )
        return stats


class ThreeAxisOperationManager:
    """Project-scoped 3-axis CAM operation and machining-region helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add 3-axis surface machining metadata."""

        if isinstance(item, MachiningRegion):
            collection = self.manager.three_axis_machining_regions
        elif isinstance(item, SurfaceSelection):
            collection = self.manager.three_axis_surface_selections
        elif isinstance(item, MachiningBoundary):
            collection = self.manager.three_axis_boundaries
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_dependencies(item)
        self.statistics()
        return item

    def create_operation(self, job, setup=None, operation_type="Parallel", targets=None, name=None, tool=None, feed_speed_profile=None, surface_selection=None, machining_region=None, boundaries=None, **kwargs):
        """Create a 3-axis CAM operation through the existing OperationManager."""

        return self.manager.operation_manager.create_3_axis_operation(
            job,
            setup,
            operation_type,
            targets,
            name,
            tool,
            feed_speed_profile,
            surface_selection,
            machining_region,
            boundaries,
            **kwargs,
        )

    def create_surface_selection(self, part=None, surface_bodies=None, bodies=None, mesh_entities=None, face_ids=None, name="Surface Selection", metadata=None):
        """Create selected-surface metadata referencing existing product geometry only."""

        item = SurfaceSelection(
            name,
            getattr(part, "id", part) or "",
            [getattr(surface, "id", surface) for surface in surface_bodies or []],
            [getattr(body, "id", body) for body in bodies or []],
            [getattr(mesh, "id", getattr(mesh, "name", mesh)) for mesh in mesh_entities or []],
            list(face_ids or []),
            metadata,
        )
        return self.add_item(item)

    def create_machining_region(self, part=None, surface_bodies=None, bodies=None, mesh_entities=None, face_ids=None, name="Machining Region", metadata=None):
        """Create a machining-region definition referencing existing product geometry only."""

        item = MachiningRegion(
            name,
            getattr(part, "id", part) or "",
            [getattr(surface, "id", surface) for surface in surface_bodies or []],
            [getattr(body, "id", body) for body in bodies or []],
            [getattr(mesh, "id", getattr(mesh, "name", mesh)) for mesh in mesh_entities or []],
            list(face_ids or []),
            metadata,
        )
        return self.add_item(item)

    def create_boundary(self, part=None, boundary_type="Containment", curves=None, references=None, name=None, metadata=None):
        """Create a machining boundary or avoid region from existing references only."""

        boundary_class = ContainmentBoundary if boundary_type == "Containment" else AvoidRegion if boundary_type == "Avoid" else MachiningBoundary
        if boundary_class is MachiningBoundary:
            item = boundary_class(
                name or "Machining Boundary",
                boundary_type,
                getattr(part, "id", part) or "",
                [getattr(curve, "id", curve) for curve in curves or []],
                [getattr(reference, "id", reference) for reference in references or []],
                metadata,
            )
        else:
            item = boundary_class(
                name or boundary_class.__name__,
                getattr(part, "id", part) or "",
                [getattr(curve, "id", curve) for curve in curves or []],
                [getattr(reference, "id", reference) for reference in references or []],
                metadata,
            )
        return self.add_item(item)

    def visible_objects(self):
        """Return visible 3-axis CAM metadata for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.three_axis_surface_selections +
                self.manager.three_axis_machining_regions +
                self.manager.three_axis_boundaries
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return 3-axis surface and boundary statistics."""

        stats = BoundaryStatistics(
            len(self.manager.three_axis_surface_selections),
            len(self.manager.three_axis_machining_regions),
            len(self.manager.three_axis_boundaries),
            len([boundary for boundary in self.manager.three_axis_boundaries if boundary.boundary_type == "Containment"]),
            len([boundary for boundary in self.manager.three_axis_boundaries if boundary.boundary_type == "Avoid"]),
        )
        self.manager.boundary_statistics = stats
        self.manager.operation_manager.statistics()
        return stats

    def _refresh_dependencies(self, item):
        part = self.manager.part_for(getattr(item, "part_id", ""))
        if part is not None:
            self.manager.dependency_manager.add_edge(part, item, "ThreeAxisPartReference")

        if isinstance(item, SurfaceSelection):
            for surface_id in item.surface_body_ids:
                surface = _find_by_id_or_name(self.manager.surface_bodies, surface_id)
                if surface is not None:
                    self.manager.dependency_manager.add_edge(surface, item, "ThreeAxisSurfaceReference")
            for body_id in item.body_ids:
                body = _find_by_id_or_name(self.manager.bodies, body_id)
                if body is not None:
                    self.manager.dependency_manager.add_edge(body, item, "ThreeAxisBodyReference")
        elif isinstance(item, MachiningBoundary):
            for curve_id in item.curve_ids:
                curve = _find_by_id_or_name(self.manager.curves, curve_id)
                if curve is not None:
                    self.manager.dependency_manager.add_edge(curve, item, "ThreeAxisBoundaryCurveReference")
            for reference_id in item.reference_ids:
                reference = _find_by_id_or_name(self.manager.reference_geometry, reference_id)
                if reference is not None:
                    self.manager.dependency_manager.add_edge(reference, item, "ThreeAxisBoundaryReferenceGeometry")


class LaserPlasmaManager:
    """Project-scoped laser and plasma manufacturing foundation helper."""

    MATERIAL_TYPES = {
        "Wood", "Acrylic", "MDF", "Plywood", "Paper", "Leather", "Cardboard",
        "Steel", "Stainless Steel", "Aluminium", "Brass",
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add laser/plasma metadata through the workspace-owned ProductManager."""

        if isinstance(item, PlasmaJob):
            collection = self.manager.plasma_jobs
        elif isinstance(item, LaserJob):
            collection = self.manager.laser_jobs
        elif isinstance(item, MaterialProfile):
            collection = self.manager.material_profiles
        elif isinstance(item, CuttingProfile):
            collection = self.manager.cutting_profiles
        elif isinstance(item, PowerProfile):
            collection = self.manager.power_profiles
        elif isinstance(item, GasProfile):
            collection = self.manager.gas_profiles
        elif isinstance(item, CoolingProfile):
            collection = self.manager.cooling_profiles
        elif isinstance(item, (LaserOperation, PlasmaOperation)):
            self.manager.cam_manager.add_item(item)
            self._refresh_operation_links(item)
            self.statistics()
            return item
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_laser_job(self, cam_job, name="Laser Job", metadata=None):
        """Create a laser job that references an existing CAMJob."""

        job = LaserJob(name, getattr(cam_job, "id", cam_job) or "", metadata)
        self.add_item(job)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, job, "LaserJobCAMReference")
        return job

    def create_plasma_job(self, cam_job, name="Plasma Job", metadata=None):
        """Create a plasma job that references an existing CAMJob."""

        job = PlasmaJob(name, getattr(cam_job, "id", cam_job) or "", metadata)
        self.add_item(job)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, job, "PlasmaJobCAMReference")
        return job

    def create_material_profile(self, name="Material Profile", material_type="Wood", thickness=0.0, description="", supplier_id="", properties=None):
        """Create a laser/plasma material profile as metadata only."""

        if material_type not in self.MATERIAL_TYPES:
            material_type = "Wood"
        return self.add_item(MaterialProfile(name, material_type, thickness, description, supplier_id, properties or {}))

    def create_cutting_profile(self, material_profile=None, name="Cutting Profile", **kwargs):
        """Create cutting metadata for laser/plasma manufacturing."""

        profile = CuttingProfile(
            name,
            getattr(material_profile, "id", material_profile) or "",
            float(kwargs.get("cut_speed", 0.0)),
            float(kwargs.get("travel_speed", 0.0)),
            int(kwargs.get("pass_count", 1)),
            float(kwargs.get("focus_offset", 0.0)),
            bool(kwargs.get("air_assist_placeholder", True)),
            float(kwargs.get("pierce_height", 0.0)),
            float(kwargs.get("cut_height", 0.0)),
            float(kwargs.get("kerf_width", 0.0)),
            float(kwargs.get("pierce_delay", 0.0)),
            dict(kwargs.get("properties", {})),
        )
        self.add_item(profile)
        if material_profile is not None:
            self.manager.dependency_manager.add_edge(material_profile, profile, "CuttingProfileMaterialReference")
        return profile

    def create_power_profile(self, name="Power Profile", minimum_power=0.0, maximum_power=0.0, laser_power=0.0, properties=None):
        """Create a laser power profile."""

        return self.add_item(PowerProfile(name, minimum_power, maximum_power, laser_power, properties or {}))

    def create_gas_profile(self, name="Gas Profile", gas_type="", pressure=0.0, properties=None):
        """Create a gas profile placeholder."""

        return self.add_item(GasProfile(name, gas_type, pressure, properties or {}))

    def create_cooling_profile(self, name="Cooling Profile", cooling_type="", properties=None):
        """Create a cooling profile placeholder."""

        return self.add_item(CoolingProfile(name, cooling_type, properties or {}))

    def create_laser_operation(self, laser_job, setup=None, operation_type="Vector Cut", targets=None, name=None, tool=None, material_profile=None, cutting_profile=None, power_profile=None, feed_speed_profile=None, **kwargs):
        """Create a laser operation through the existing OperationManager."""

        operation = self.manager.operation_manager.create_laser_operation(
            getattr(laser_job, "cam_job_id", laser_job),
            setup,
            operation_type,
            targets,
            name,
            tool,
            material_profile,
            cutting_profile,
            power_profile,
            feed_speed_profile,
            **kwargs,
        )
        job = self.laser_job_for(laser_job)
        if job is not None and operation.id not in job.operation_ids:
            job.operation_ids.append(operation.id)
        if job is not None:
            self.manager.dependency_manager.add_edge(job, operation, "LaserJobOperationReference")
        self.statistics()
        return operation

    def create_plasma_operation(self, plasma_job, setup=None, operation_type="Plasma Cut", targets=None, name=None, tool=None, material_profile=None, cutting_profile=None, feed_speed_profile=None, gas_profile=None, cooling_profile=None, **kwargs):
        """Create a plasma operation through the existing OperationManager."""

        operation = self.manager.operation_manager.create_plasma_operation(
            getattr(plasma_job, "cam_job_id", plasma_job),
            setup,
            operation_type,
            targets,
            name,
            tool,
            material_profile,
            cutting_profile,
            feed_speed_profile,
            gas_profile,
            cooling_profile,
            **kwargs,
        )
        job = self.plasma_job_for(plasma_job)
        if job is not None and operation.id not in job.operation_ids:
            job.operation_ids.append(operation.id)
        if job is not None:
            self.manager.dependency_manager.add_edge(job, operation, "PlasmaJobOperationReference")
        self.statistics()
        return operation

    def laser_job_for(self, job):
        """Return a laser job by object, id or name."""

        if isinstance(job, LaserJob):
            return job if job in self.manager.laser_jobs else None
        return _find_by_id_or_name(self.manager.laser_jobs, job)

    def plasma_job_for(self, job):
        """Return a plasma job by object, id or name."""

        if isinstance(job, PlasmaJob):
            return job if job in self.manager.plasma_jobs else None
        return _find_by_id_or_name(self.manager.plasma_jobs, job)

    def visible_objects(self):
        """Return visible laser/plasma metadata for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.laser_jobs +
                self.manager.plasma_jobs +
                self.manager.material_profiles +
                self.manager.cutting_profiles +
                self.manager.power_profiles
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return laser/plasma statistics."""

        laser_operations = [operation for operation in self.manager.cam_operations if getattr(operation, "is_laser_operation", False)]
        plasma_operations = [operation for operation in self.manager.cam_operations if getattr(operation, "is_plasma_operation", False)]
        stats = LaserPlasmaStatistics(
            len(self.manager.laser_jobs),
            len(self.manager.plasma_jobs),
            len(laser_operations),
            len(plasma_operations),
            len(self.manager.material_profiles),
            len(self.manager.cutting_profiles),
            len([
                operation for operation in laser_operations + plasma_operations
                if not getattr(getattr(operation, "metadata", None), "enabled", True)
            ]),
        )
        self.manager.laser_plasma_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, LaserJob):
            cam_job = self.manager.cam_manager.job_for(item.cam_job_id)
            if cam_job is not None:
                self.manager.dependency_manager.add_edge(cam_job, item, "LaserJobCAMReference")
        elif isinstance(item, PlasmaJob):
            cam_job = self.manager.cam_manager.job_for(item.cam_job_id)
            if cam_job is not None:
                self.manager.dependency_manager.add_edge(cam_job, item, "PlasmaJobCAMReference")
        elif isinstance(item, CuttingProfile):
            material = _find_by_id_or_name(self.manager.material_profiles, item.material_profile_id)
            if material is not None:
                self.manager.dependency_manager.add_edge(material, item, "CuttingProfileMaterialReference")

    def _refresh_operation_links(self, item):
        job_lists = self.manager.laser_jobs if getattr(item, "is_laser_operation", False) else self.manager.plasma_jobs
        for job in job_lists:
            if job.cam_job_id == item.job_id and item.id not in job.operation_ids:
                job.operation_ids.append(item.id)


class RouterManager:
    """Project-scoped CNC router foundation helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add router metadata through the workspace-owned ProductManager."""

        if isinstance(item, RouterJob):
            collection = self.manager.router_jobs
        elif isinstance(item, ClampAvoidanceRegion):
            collection = self.manager.clamp_avoidance_regions
        elif isinstance(item, RouterFixtureDefinition):
            collection = self.manager.router_fixtures
        elif isinstance(item, RouterMetadataProfile):
            collection = self.manager.router_metadata_profiles
        elif isinstance(item, DustCollectionProfile):
            collection = self.manager.dust_collection_profiles
        elif isinstance(item, RouterOperation):
            self.manager.cam_manager.add_item(item)
            self._refresh_operation_links(item)
            self.statistics()
            return item
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_router_job(self, cam_job, name="Router Job", metadata=None):
        """Create a router job that references an existing CAMJob."""

        job = RouterJob(name, getattr(cam_job, "id", cam_job) or "", metadata)
        self.add_item(job)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, job, "RouterJobCAMReference")
        return job

    def create_fixture(self, name="Router Fixture", references=None, metadata=None):
        """Create router fixture reference metadata."""

        fixture = RouterFixtureDefinition(
            name,
            [getattr(reference, "id", reference) for reference in references or []],
            metadata or {},
        )
        self.add_item(fixture)
        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, fixture, "RouterFixtureReference")
        return fixture

    def create_clamp_avoidance_region(self, name="Clamp Avoidance Region", references=None, metadata=None):
        """Create clamp avoidance metadata."""

        region = ClampAvoidanceRegion(
            name,
            [getattr(reference, "id", reference) for reference in references or []],
            metadata or {},
        )
        self.add_item(region)
        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, region, "RouterClampReference")
        return region

    def create_dust_collection_profile(self, name="Dust Collection Profile", enabled=True, properties=None):
        """Create dust collection placeholder metadata."""

        return self.add_item(DustCollectionProfile(name, enabled, properties or {}))

    def create_metadata_profile(self, name="Router Metadata Profile", **kwargs):
        """Create reusable router operation metadata."""

        profile = RouterMetadataProfile(
            name=name,
            safe_height=SafeHeight(float(kwargs.get("safe_height", 0.0))),
            clearance_height=ClearanceHeight(float(kwargs.get("clearance_height", 0.0))),
            retract_height=RetractHeight(float(kwargs.get("retract_height", 0.0))),
            lead_in=LeadInMetadata(bool(kwargs.get("lead_in_enabled", True)), float(kwargs.get("lead_radius", 0.0)), float(kwargs.get("lead_angle", 0.0)), kwargs.get("lead_style", "Line")),
            lead_out=LeadOutMetadata(bool(kwargs.get("lead_out_enabled", True)), float(kwargs.get("lead_out_radius", kwargs.get("lead_radius", 0.0))), float(kwargs.get("lead_out_angle", kwargs.get("lead_angle", 0.0))), kwargs.get("lead_out_style", "Line")),
            ramp=RampStrategy(kwargs.get("ramp_strategy", "Linear"), float(kwargs.get("ramp_angle", 0.0)), float(kwargs.get("ramp_length", 0.0))),
            plunge=PlungeStrategy(kwargs.get("plunge_strategy", "Direct"), float(kwargs.get("plunge_feed_rate", 0.0))),
            tabs=TabDefinition(bool(kwargs.get("tabs_enabled", False)), float(kwargs.get("tab_width", 0.0)), float(kwargs.get("tab_height", 0.0)), int(kwargs.get("tab_count", 0))),
            bridges=BridgeDefinition(bool(kwargs.get("bridges_enabled", False)), float(kwargs.get("bridge_width", 0.0)), float(kwargs.get("bridge_height", 0.0)), int(kwargs.get("bridge_count", 0))),
            onion_skin=OnionSkinDefinition(bool(kwargs.get("onion_skin_enabled", False)), float(kwargs.get("onion_skin_thickness", 0.0))),
            dust_collection_id=getattr(kwargs.get("dust_collection_profile"), "id", kwargs.get("dust_collection_profile", "")) or "",
            properties=dict(kwargs.get("properties", {})),
        )
        self.add_item(profile)
        dust = kwargs.get("dust_collection_profile")
        if dust is not None:
            self.manager.dependency_manager.add_edge(dust, profile, "RouterDustCollectionReference")
        return profile

    def create_operation(self, router_job, setup=None, operation_type="Profile Cut", targets=None, name=None, tool=None, tool_preset=None, feed_speed_profile=None, router_profile=None, fixtures=None, clamp_avoidance_regions=None, material_profile=None, **kwargs):
        """Create a router operation through the existing OperationManager."""

        kwargs["router_job"] = router_job
        operation = self.manager.operation_manager.create_router_operation(
            getattr(router_job, "cam_job_id", router_job),
            setup,
            operation_type,
            targets,
            name,
            tool,
            tool_preset,
            feed_speed_profile,
            router_profile,
            fixtures,
            clamp_avoidance_regions,
            material_profile,
            **kwargs,
        )
        job = self.router_job_for(router_job)
        if job is not None and operation.id not in job.operation_ids:
            job.operation_ids.append(operation.id)
        if job is not None:
            self.manager.dependency_manager.add_edge(job, operation, "RouterJobOperationReference")
        self.statistics()
        return operation

    def router_job_for(self, job):
        """Return a router job by object, id or name."""

        if isinstance(job, RouterJob):
            return job if job in self.manager.router_jobs else None
        return _find_by_id_or_name(self.manager.router_jobs, job)

    def visible_objects(self):
        """Return visible router metadata for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.router_jobs +
                self.manager.router_fixtures +
                self.manager.clamp_avoidance_regions +
                self.manager.router_metadata_profiles +
                self.manager.dust_collection_profiles
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return router statistics."""

        router_operations = [operation for operation in self.manager.cam_operations if getattr(operation, "is_router_operation", False)]
        stats = RouterStatistics(
            len(self.manager.router_jobs),
            len(router_operations),
            len(self.manager.router_fixtures),
            len(self.manager.clamp_avoidance_regions),
            len(self.manager.router_metadata_profiles),
            len([
                operation for operation in router_operations
                if not getattr(getattr(operation, "metadata", None), "enabled", True)
            ]),
        )
        self.manager.router_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, RouterJob):
            cam_job = self.manager.cam_manager.job_for(item.cam_job_id)
            if cam_job is not None:
                self.manager.dependency_manager.add_edge(cam_job, item, "RouterJobCAMReference")

    def _refresh_operation_links(self, item):
        for job in self.manager.router_jobs:
            if job.cam_job_id == item.job_id and item.id not in job.operation_ids:
                job.operation_ids.append(item.id)


class PostProcessorManager:
    """Project-scoped post processor foundation helper; metadata only."""

    CONTROLLER_CLASSES = {
        "GRBL": GRBL,
        "Marlin": Marlin,
        "Klipper": Klipper,
        "LinuxCNC": LinuxCNC,
        "Fanuc": Fanuc,
        "Haas": Haas,
        "Mach3": Mach3,
        "Mach4": Mach4,
        "Smoothieware": Smoothieware,
        "Duet": Duet,
        "Masso": Masso,
        "GenericGCode": GenericGCode,
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add post processor metadata through the workspace-owned ProductManager."""

        if isinstance(item, PostProcessor):
            collection = self.manager.post_processors
        elif isinstance(item, PostProcessorProfile):
            collection = self.manager.post_processor_profiles
        elif isinstance(item, ControllerProfile):
            collection = self.manager.controller_profiles
        elif isinstance(item, OutputConfiguration):
            collection = self.manager.output_configurations
        elif isinstance(item, OutputTemplate):
            collection = self.manager.output_templates
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_controller_profile(self, controller_type="GenericGCode", name=None, controller_version="", **kwargs):
        """Create a controller profile placeholder."""

        profile_class = self.CONTROLLER_CLASSES.get(controller_type, GenericGCode)
        metadata = PostProcessorMetadata(
            description=kwargs.get("description", ""),
            controller_family=controller_type,
            controller_version=controller_version,
            supported_g_codes=list(kwargs.get("supported_g_codes", [])),
            supported_m_codes=list(kwargs.get("supported_m_codes", [])),
            units=kwargs.get("units", "mm"),
            coordinate_mode=kwargs.get("coordinate_mode", "Absolute"),
            arc_support=bool(kwargs.get("arc_support", True)),
            feed_mode=kwargs.get("feed_mode", "Units per Minute"),
            spindle_support=bool(kwargs.get("spindle_support", True)),
            laser_mode_placeholder=bool(kwargs.get("laser_mode_placeholder", False)),
            plasma_mode_placeholder=bool(kwargs.get("plasma_mode_placeholder", False)),
            additive_mode_placeholder=bool(kwargs.get("additive_mode_placeholder", False)),
            properties=dict(kwargs.get("properties", {})),
        )
        profile = profile_class(name or controller_type, controller_version, metadata)
        self.add_item(profile)
        return profile

    def create_output_configuration(self, name="Output Configuration", program_name="", **kwargs):
        """Create output configuration metadata only."""

        config = OutputConfiguration(
            name,
            program_name,
            ProgramHeader(list(kwargs.get("header_lines", [])), bool(kwargs.get("include_program_name", True))),
            ProgramFooter(list(kwargs.get("footer_lines", [])), bool(kwargs.get("include_end_block", True))),
            CoordinateConfiguration(
                kwargs.get("units", "mm"),
                kwargs.get("coordinate_mode", "Absolute"),
                kwargs.get("work_offset", "G54"),
                kwargs.get("safe_start_block", ""),
                kwargs.get("safe_end_block", ""),
            ),
            ToolChangeConfiguration(
                kwargs.get("tool_change_policy", "Manual"),
                bool(kwargs.get("optional_stop", False)),
                bool(kwargs.get("preload_next_tool", False)),
            ),
            CoolantConfiguration(
                bool(kwargs.get("flood_coolant", False)),
                bool(kwargs.get("mist_coolant", False)),
                bool(kwargs.get("air_coolant", False)),
            ),
            SpindleConfiguration(
                kwargs.get("spindle_start", "M3"),
                kwargs.get("spindle_stop", "M5"),
                bool(kwargs.get("supports_spindle_speed", True)),
            ),
            OutputMetadata(
                kwargs.get("comment_style", "Parentheses"),
                bool(kwargs.get("line_numbering_placeholder", False)),
                kwargs.get("file_extension", ".nc"),
                dict(kwargs.get("properties", {})),
            ),
        )
        self.add_item(config)
        return config

    def create_output_template(self, name="Output Template", template_type="Generic", content="", properties=None):
        """Create output template metadata only."""

        template = OutputTemplate(name, template_type, content, properties or {})
        self.add_item(template)
        return template

    def create_post_processor(self, name="Post Processor", controller_profile=None, output_configuration=None, metadata=None, default=False):
        """Create a post processor metadata record."""

        post = PostProcessor(
            name,
            getattr(controller_profile, "id", controller_profile) or "",
            getattr(output_configuration, "id", output_configuration) or "",
            metadata,
        )
        post.default = bool(default)
        self.add_item(post)
        if controller_profile is not None:
            self.manager.dependency_manager.add_edge(controller_profile, post, "PostControllerReference")
        if output_configuration is not None:
            self.manager.dependency_manager.add_edge(output_configuration, post, "PostOutputConfigurationReference")
        return post

    def create_profile(self, post_processor, cam_job=None, controller_profile=None, output_configuration=None, output_templates=None, name="Post Processor Profile", enabled=True, **kwargs):
        """Create machine/profile assignment metadata for an existing CAMJob."""

        post = self.post_processor_for(post_processor)
        controller_id = getattr(controller_profile, "id", controller_profile) or getattr(post, "controller_profile_id", "")
        cam_job_id = getattr(cam_job, "id", cam_job) or ""
        template_ids = [getattr(template, "id", template) for template in output_templates or []]
        config_id = getattr(output_configuration, "id", output_configuration) or getattr(post, "output_configuration_id", "")
        settings = PostProcessSettings(
            config_id,
            template_ids,
            ControllerCapabilities(
                bool(kwargs.get("supports_arcs", True)),
                bool(kwargs.get("supports_canned_cycles", True)),
                bool(kwargs.get("supports_tool_changes", True)),
                bool(kwargs.get("supports_laser_mode", False)),
                bool(kwargs.get("supports_plasma_mode", False)),
                bool(kwargs.get("supports_additive_mode", False)),
                dict(kwargs.get("capability_properties", {})),
            ),
            MachineLimitsReference(
                [getattr(item, "id", item) for item in kwargs.get("axis_limits", [])],
                [getattr(item, "id", item) for item in kwargs.get("travel_limits", [])],
                dict(kwargs.get("limit_properties", {})),
            ),
            OutputValidationMetadata(
                kwargs.get("validation_status", "Not Run"),
                int(kwargs.get("warning_count", 0)),
                int(kwargs.get("error_count", 0)),
                list(kwargs.get("messages", [])),
            ),
            dict(kwargs.get("settings_properties", {})),
        )
        machine_reference = MachineProfileReference(
            getattr(kwargs.get("machine"), "id", kwargs.get("machine", "")) or "",
            controller_id,
            cam_job_id,
            [getattr(operation, "id", operation) for operation in kwargs.get("operations", [])],
        )
        profile = PostProcessorProfile(
            name,
            getattr(post, "id", post_processor) or "",
            controller_id,
            cam_job_id,
            enabled,
            settings,
            machine_reference,
            kwargs.get("metadata"),
        )
        self.add_item(profile)
        for reference, relation in (
            (post, "PostProcessorProfileReference"),
            (cam_job, "PostCAMJobReference"),
            (controller_profile, "PostControllerProfileReference"),
            (output_configuration, "PostOutputConfigurationReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, profile, relation)
        for template in output_templates or []:
            self.manager.dependency_manager.add_edge(template, profile, "PostOutputTemplateReference")
        for operation in kwargs.get("operations", []):
            self.manager.dependency_manager.add_edge(operation, profile, "PostOperationReference")
        self.statistics()
        return profile

    def set_default(self, post_processor):
        """Set the default post processor metadata record."""

        target = self.post_processor_for(post_processor)
        if target is None:
            return None
        for post in self.manager.post_processors:
            post.default = False
        target.default = True
        self.statistics()
        return target

    def set_enabled(self, profile, enabled=True):
        """Enable or disable a post processor profile."""

        target = self.profile_for(profile)
        if target is not None:
            target.enabled = bool(enabled)
        self.statistics()
        return target

    def post_processor_for(self, post):
        """Return a post processor by object, id or name."""

        if isinstance(post, PostProcessor):
            return post if post in self.manager.post_processors else None
        return _find_by_id_or_name(self.manager.post_processors, post)

    def profile_for(self, profile):
        """Return a post processor profile by object, id or name."""

        if isinstance(profile, PostProcessorProfile):
            return profile if profile in self.manager.post_processor_profiles else None
        return _find_by_id_or_name(self.manager.post_processor_profiles, profile)

    def profiles_for_post_processor(self, post):
        """Return profiles assigned to a post processor."""

        post_id = getattr(post, "id", post)
        return [profile for profile in self.manager.post_processor_profiles if profile.post_processor_id == post_id]

    def visible_objects(self):
        """Return visible post processor metadata for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.post_processors +
                self.manager.post_processor_profiles +
                self.manager.controller_profiles +
                self.manager.output_configurations +
                self.manager.output_templates
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return post processor statistics."""

        stats = PostProcessorStatistics(
            len(self.manager.post_processors),
            len(self.manager.post_processor_profiles),
            len(self.manager.controller_profiles),
            len(self.manager.output_configurations),
            len(self.manager.output_templates),
            len([profile for profile in self.manager.post_processor_profiles if profile.enabled]),
            len([post for post in self.manager.post_processors if post.default]),
        )
        self.manager.post_processor_statistics = stats
        self.manager.output_statistics = OutputStatistics(
            len(self.manager.output_configurations),
            len(self.manager.output_templates),
            sum(profile.settings.validation.warning_count for profile in self.manager.post_processor_profiles),
            sum(profile.settings.validation.error_count for profile in self.manager.post_processor_profiles),
        )
        return stats

    def _refresh_links(self, item):
        if isinstance(item, PostProcessorProfile):
            post = self.post_processor_for(item.post_processor_id)
            if post is not None and item.id not in post.profile_ids:
                post.profile_ids.append(item.id)
        elif isinstance(item, PostProcessor):
            if item.default:
                self.set_default(item)


class MachineLibraryManager:
    """Project-scoped machine library foundation helper; metadata only."""

    MACHINE_CLASSES = {
        "CNC": CNCMachine,
        "CNCMachine": CNCMachine,
        "Router": RouterMachine,
        "RouterMachine": RouterMachine,
        "Laser": LaserMachine,
        "LaserMachine": LaserMachine,
        "Plasma": PlasmaMachine,
        "PlasmaMachine": PlasmaMachine,
        "Printer": PrinterMachine,
        "PrinterMachine": PrinterMachine,
        "FDM": FDMPrinterProfile,
        "FDMPrinterProfile": FDMPrinterProfile,
        "SLA": SLAPrinterProfile,
        "SLAPrinterProfile": SLAPrinterProfile,
        "SLS": SLSPrinterProfile,
        "SLSPrinterProfile": SLSPrinterProfile,
        "DLP": DLPPrinterProfile,
        "DLPPrinterProfile": DLPPrinterProfile,
        "BinderJet": BinderJetProfile,
        "BinderJetProfile": BinderJetProfile,
        "MetalAM": MetalAMProfile,
        "MetalAMProfile": MetalAMProfile,
        "Generic": GenericMachine,
        "GenericMachine": GenericMachine,
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add machine library metadata through the workspace-owned ProductManager."""

        if isinstance(item, MachineLibrary):
            collection = self.manager.machine_libraries
        elif isinstance(item, MachineDefinition):
            collection = self.manager.machine_definitions
        elif isinstance(item, MachineProfile):
            collection = self.manager.machine_profiles
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_library(self, name="Machine Library", metadata=None):
        """Create a machine library metadata record."""

        return self.add_item(MachineLibrary(name, metadata))

    def create_machine(self, machine_class=GenericMachine, library=None, name=None, category="", metadata=None, capabilities=None, **kwargs):
        """Create a machine definition without geometry ownership."""

        if isinstance(machine_class, str):
            machine_class = self.MACHINE_CLASSES.get(machine_class, GenericMachine)
        if not issubclass(machine_class, MachineDefinition):
            machine_class = GenericMachine

        library_id = getattr(library, "id", library) or ""
        metadata = metadata or MachineMetadata(
            manufacturer=kwargs.get("manufacturer", ""),
            model=kwargs.get("model", ""),
            serial_placeholder=kwargs.get("serial_placeholder", ""),
            firmware=kwargs.get("firmware", ""),
            machine_category=category or getattr(machine_class(), "machine_type", "Generic"),
            supported_operations=list(kwargs.get("supported_operations", [])),
            supported_controller=kwargs.get("supported_controller", ""),
            description=kwargs.get("description", ""),
            favorite=bool(kwargs.get("favorite", False)),
            properties=dict(kwargs.get("properties", {})),
        )
        machine = machine_class(name or machine_class.__name__, library_id, category or metadata.machine_category, metadata, capabilities or MachineCapabilities())
        self.add_item(machine)
        if library is not None:
            self.manager.dependency_manager.add_edge(library, machine, "MachineLibraryReference")
        return machine

    def create_profile(self, machine, cam_job=None, post_processor=None, controller_profile=None, tool_library=None, setup=None, name="Machine Profile", enabled=True, operations=None, fixtures=None, **kwargs):
        """Create machine assignment metadata for existing CAM records."""

        target_machine = self.machine_for(machine)
        machine_id = getattr(target_machine, "id", machine) or ""
        cam_job_id = getattr(cam_job, "id", cam_job) or ""
        post_id = getattr(post_processor, "id", post_processor) or ""
        controller_id = getattr(controller_profile, "id", controller_profile) or getattr(post_processor, "controller_profile_id", "")
        tool_library_id = getattr(tool_library, "id", tool_library) or ""
        setup_id = getattr(setup, "id", setup) or ""
        operation_ids = [getattr(operation, "id", operation) for operation in operations or []]
        fixture_ids = [getattr(fixture, "id", fixture) for fixture in fixtures or []]
        profile = MachineProfile(
            name,
            machine_id,
            cam_job_id,
            post_id,
            controller_id,
            tool_library_id,
            setup_id,
            enabled,
            MachineAssignment(cam_job_id, machine_id, "", bool(enabled), dict(kwargs.get("assignment_properties", {}))),
            MachineProfileReference(machine_id, controller_id, cam_job_id, operation_ids),
            MachineLimitReference(machine_id, kwargs.get("capability_id", ""), list(kwargs.get("limit_ids", [])), dict(kwargs.get("limit_properties", {}))),
            ControllerReference(controller_id, post_id, kwargs.get("controller_name", ""), dict(kwargs.get("controller_properties", {}))),
            FixtureReference(setup_id, fixture_ids, dict(kwargs.get("fixture_properties", {}))),
            MachineValidationMetadata(
                kwargs.get("validation_status", "Not Run"),
                int(kwargs.get("warning_count", 0)),
                int(kwargs.get("error_count", 0)),
                list(kwargs.get("messages", [])),
                dict(kwargs.get("validation_properties", {})),
            ),
            kwargs.get("metadata"),
        )
        profile.assignment.machine_profile_id = profile.id
        self.add_item(profile)

        for reference, relation in (
            (target_machine or machine, "MachineProfileMachineReference"),
            (cam_job, "MachineCAMJobReference"),
            (post_processor, "MachinePostProcessorReference"),
            (controller_profile, "MachineControllerReference"),
            (tool_library, "MachineToolLibraryReference"),
            (setup, "MachineSetupReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, profile, relation)
        for operation in operations or []:
            self.manager.dependency_manager.add_edge(operation, profile, "MachineOperationReference")
        for fixture in fixtures or []:
            self.manager.dependency_manager.add_edge(fixture, profile, "MachineFixtureReference")
        self.statistics()
        return profile

    def library_for(self, library):
        """Return a machine library by object, id or name."""

        if isinstance(library, MachineLibrary):
            return library if library in self.manager.machine_libraries else None
        return _find_by_id_or_name(self.manager.machine_libraries, library)

    def machine_for(self, machine):
        """Return a machine definition by object, id or name."""

        if isinstance(machine, MachineDefinition):
            return machine if machine in self.manager.machine_definitions else None
        return _find_by_id_or_name(self.manager.machine_definitions, machine)

    def profile_for(self, profile):
        """Return a machine profile by object, id or name."""

        if isinstance(profile, MachineProfile):
            return profile if profile in self.manager.machine_profiles else None
        return _find_by_id_or_name(self.manager.machine_profiles, profile)

    def machines_for_library(self, library):
        """Return machines assigned to a library."""

        library_id = getattr(library, "id", library)
        return [machine for machine in self.manager.machine_definitions if machine.library_id == library_id]

    def profiles_for_machine(self, machine):
        """Return profiles assigned to a machine."""

        machine_id = getattr(machine, "id", machine)
        return [profile for profile in self.manager.machine_profiles if profile.machine_id == machine_id]

    def profiles_for_cam_job(self, cam_job):
        """Return machine profiles assigned to a CAM job."""

        job_id = getattr(cam_job, "id", cam_job)
        return [profile for profile in self.manager.machine_profiles if profile.cam_job_id == job_id]

    def search_machines(self, text):
        """Search machine definitions by metadata."""

        query = str(text or "").lower()
        if not query:
            return list(self.manager.machine_definitions)

        def matches(machine):
            metadata = getattr(machine, "metadata", MachineMetadata())
            values = [
                machine.name,
                machine.machine_type,
                machine.category,
                metadata.manufacturer,
                metadata.model,
                metadata.firmware,
                metadata.supported_controller,
            ] + list(metadata.supported_operations)
            return any(query in str(value).lower() for value in values)

        return [machine for machine in self.manager.machine_definitions if matches(machine)]

    def visible_objects(self):
        """Return visible machine library records for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.machine_libraries +
                self.manager.machine_definitions +
                self.manager.machine_profiles
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return machine library statistics."""

        categories = {machine.category for machine in self.manager.machine_definitions if machine.category}
        favorites = [
            machine for machine in self.manager.machine_definitions
            if getattr(getattr(machine, "metadata", None), "favorite", False)
        ]
        assignments = [profile for profile in self.manager.machine_profiles if profile.cam_job_id]
        stats = MachineStatistics(
            len(self.manager.machine_libraries),
            len(self.manager.machine_definitions),
            len(self.manager.machine_profiles),
            len(categories),
            len(favorites),
            len(assignments),
            len([profile for profile in self.manager.machine_profiles if profile.enabled]),
        )
        self.manager.machine_statistics = stats
        self.manager.capability_statistics = CapabilityStatistics(
            len([machine for machine in self.manager.machine_definitions if machine.capabilities.work_envelope]),
            len([machine for machine in self.manager.machine_definitions if machine.capabilities.axis_configuration]),
            len([machine for machine in self.manager.machine_definitions if machine.capabilities.travel_limits]),
            len([
                machine for machine in self.manager.machine_definitions
                if machine.capabilities.tool_changer_configuration.tool_slots
                or machine.capabilities.tool_changer_configuration.automatic_tool_changer_placeholder
            ]),
            len([
                machine for machine in self.manager.machine_definitions
                if machine.capabilities.rotary_axis_configuration.fourth_axis_placeholder
                or machine.capabilities.rotary_axis_configuration.fifth_axis_placeholder
            ]),
        )
        return stats

    def _refresh_links(self, item):
        if isinstance(item, MachineDefinition):
            library = self.library_for(item.library_id)
            if library is not None and item.id not in library.machine_ids:
                library.machine_ids.append(item.id)
            if library is not None and item.metadata.favorite and item.id not in library.favorite_machine_ids:
                library.favorite_machine_ids.append(item.id)
        elif isinstance(item, MachineProfile):
            machine = self.machine_for(item.machine_id)
            if machine is not None and item.id not in machine.profile_ids:
                machine.profile_ids.append(item.id)
            library = self.library_for(getattr(machine, "library_id", ""))
            if library is not None and item.id not in library.profile_ids:
                library.profile_ids.append(item.id)


class SlicerManager:
    """Project-scoped additive manufacturing slicer metadata helper."""

    PRINTER_CLASSES = {
        "FDM": FDMPrinterProfile,
        "SLA": SLAPrinterProfile,
        "SLS": SLSPrinterProfile,
        "DLP": DLPPrinterProfile,
        "BinderJet": BinderJetProfile,
        "MetalAM": MetalAMProfile,
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add slicer metadata through ProductManager."""

        if isinstance(item, SliceJob):
            collection = self.manager.slice_jobs
        elif isinstance(item, SliceOperation):
            collection = self.manager.slice_operations
        elif isinstance(item, SliceProfile):
            collection = self.manager.slice_profiles
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_printer_profile(self, printer_type="FDM", library=None, name=None, metadata=None, capabilities=None, printer_metadata=None):
        """Create a printer profile through MachineLibraryManager."""

        profile_class = self.PRINTER_CLASSES.get(printer_type, FDMPrinterProfile)
        printer = profile_class(
            name or f"{printer_type} Printer Profile",
            getattr(library, "id", library) or "",
            printer_type,
            metadata,
            capabilities,
            printer_metadata,
        )
        self.manager.machine_library_manager.add_item(printer)
        if library is not None:
            self.manager.dependency_manager.add_edge(library, printer, "SlicerPrinterLibraryReference")
        self.statistics()
        return printer

    def create_profile(self, name="Slice Profile", machine_profile=None, material_profile=None, post_processor_profile=None, **kwargs):
        """Create print and layer metadata for future slicing."""

        print_profile = PrintProfile(
            MaterialProfileReference(
                getattr(material_profile, "id", material_profile) or "",
                getattr(kwargs.get("engineering_material"), "id", kwargs.get("engineering_material", "")) or "",
                kwargs.get("spool_id_placeholder", ""),
                kwargs.get("resin_batch_placeholder", ""),
                dict(kwargs.get("material_properties", {})),
            ),
            QualityProfile(kwargs.get("quality_name", "Standard"), kwargs.get("quality_level", "Standard")),
            LayerProfile(float(kwargs.get("layer_height", 0.2)), float(kwargs.get("first_layer_height", 0.2)), bool(kwargs.get("adaptive_layers_placeholder", False))),
            InfillProfile(float(kwargs.get("infill_percentage", 20.0)), kwargs.get("infill_pattern_placeholder", "Grid")),
            SupportProfile(bool(kwargs.get("support_enabled", False)), float(kwargs.get("support_density", 0.0)), kwargs.get("support_style_placeholder", "None")),
            AdhesionProfile(bool(kwargs.get("brim", False)), bool(kwargs.get("skirt", True)), bool(kwargs.get("raft", False))),
            CoolingProfile(
                "Print Cooling",
                "Additive",
                {
                    "enabled": bool(kwargs.get("cooling_enabled", True)),
                    "fan_speed": float(kwargs.get("fan_speed", 0.0)),
                    "minimum_layer_time_placeholder": bool(kwargs.get("minimum_layer_time_placeholder", False)),
                },
            ),
            RetractionProfile(bool(kwargs.get("retraction_enabled", True)), float(kwargs.get("retraction_distance", 0.0)), float(kwargs.get("retraction_speed", 0.0)), float(kwargs.get("pressure_advance_placeholder", 0.0)), float(kwargs.get("linear_advance_placeholder", 0.0))),
            SeamProfile(kwargs.get("seam_position_placeholder", "Nearest")),
            ShellProfile(int(kwargs.get("perimeters", 2)), int(kwargs.get("top_layers", 4)), int(kwargs.get("bottom_layers", 4))),
            IroningProfile(bool(kwargs.get("ironing_placeholder", False))),
            BridgeProfile(float(kwargs.get("bridge_speed", 0.0)), float(kwargs.get("bridge_flow_placeholder", 0.0))),
            float(kwargs.get("print_speed", 60.0)),
            float(kwargs.get("travel_speed", 120.0)),
            float(kwargs.get("acceleration_placeholder", 0.0)),
            float(kwargs.get("jerk_placeholder", 0.0)),
            dict(kwargs.get("profile_properties", {})),
        )
        layer_definition = LayerDefinition(
            int(kwargs.get("layer_count", 0)),
            EstimatedPrintTime(float(kwargs.get("estimated_time_seconds", 0.0))),
            MaterialUsage(float(kwargs.get("estimated_material_volume", 0.0)), float(kwargs.get("estimated_material_length", 0.0))),
            FilamentEstimate(float(kwargs.get("filament_length", 0.0)), float(kwargs.get("filament_weight", 0.0)), float(kwargs.get("filament_diameter", 1.75))),
            ResinEstimate(float(kwargs.get("resin_volume", 0.0)), float(kwargs.get("resin_weight", 0.0))),
            WeightEstimate(float(kwargs.get("estimated_weight", 0.0))),
            [getattr(reference, "id", reference) for reference in kwargs.get("preview_references", [])],
            dict(kwargs.get("layer_properties", {})),
        )
        profile = SliceProfile(
            name,
            getattr(machine_profile, "id", machine_profile) or "",
            print_profile,
            layer_definition,
            getattr(post_processor_profile, "id", post_processor_profile) or "",
            SliceMetadata(
                kwargs.get("description", ""),
                kwargs.get("technology", "FDM"),
                kwargs.get("status", "Not Sliced"),
                bool(kwargs.get("enabled", True)),
                bool(kwargs.get("background_slicing_placeholder", False)),
                dict(kwargs.get("metadata_properties", {})),
            ),
        )
        self.add_item(profile)
        for reference, relation in (
            (machine_profile, "SliceMachineReference"),
            (material_profile, "SliceMaterialReference"),
            (post_processor_profile, "SlicePostProcessorReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, profile, relation)
        self.statistics()
        return profile

    def create_job(self, cam_job, profile=None, name="Slice Job", metadata=None, enabled=True):
        """Create a slice job that references an existing CAMJob only."""

        job = SliceJob(
            name,
            getattr(cam_job, "id", cam_job) or "",
            getattr(profile, "id", profile) or "",
            metadata or SliceMetadata(enabled=enabled),
        )
        job.enabled = bool(enabled)
        self.add_item(job)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, job, "SliceCAMJobReference")
        if profile is not None:
            self.manager.dependency_manager.add_edge(profile, job, "SliceProfileReference")
        return job

    def create_operation(self, slice_job, targets=None, profile=None, name="Slice Operation", metadata=None):
        """Create slice operation metadata without generating layers or paths."""

        operation = SliceOperation(
            name,
            getattr(slice_job, "id", slice_job) or "",
            [getattr(target, "id", target) for target in targets or []],
            getattr(profile, "id", profile) or getattr(slice_job, "profile_id", ""),
            metadata,
        )
        self.add_item(operation)
        for target in targets or []:
            self.manager.dependency_manager.add_edge(target, operation, "SliceTargetReference")
        if slice_job is not None:
            self.manager.dependency_manager.add_edge(slice_job, operation, "SliceJobOperationReference")
        if profile is not None:
            self.manager.dependency_manager.add_edge(profile, operation, "SliceOperationProfileReference")
        return operation

    def set_job_enabled(self, job, enabled=True):
        """Enable or disable a slice job."""

        target = self.job_for(job)
        if target is not None:
            target.enabled = bool(enabled)
            target.metadata.enabled = bool(enabled)
        self.statistics()
        return target

    def job_for(self, job):
        """Return a slice job by object, id or name."""

        if isinstance(job, SliceJob):
            return job if job in self.manager.slice_jobs else None
        return _find_by_id_or_name(self.manager.slice_jobs, job)

    def profile_for(self, profile):
        """Return a slice profile by object, id or name."""

        if isinstance(profile, SliceProfile):
            return profile if profile in self.manager.slice_profiles else None
        return _find_by_id_or_name(self.manager.slice_profiles, profile)

    def jobs_for_cam_job(self, cam_job):
        """Return slice jobs assigned to a CAM job."""

        cam_job_id = getattr(cam_job, "id", cam_job)
        return [job for job in self.manager.slice_jobs if job.cam_job_id == cam_job_id]

    def operations_for_job(self, job):
        """Return slice operations assigned to a slice job."""

        job_id = getattr(job, "id", job)
        return [operation for operation in self.manager.slice_operations if operation.slice_job_id == job_id]

    def visible_objects(self):
        """Return visible slicer metadata records."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.slice_jobs +
                self.manager.slice_operations +
                self.manager.slice_profiles
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return slicer statistics."""

        printer_profiles = [machine for machine in self.manager.machine_definitions if getattr(machine, "is_printer_profile", False)]
        stats = SliceStatistics(
            len(self.manager.slice_jobs),
            len(self.manager.slice_operations),
            len(self.manager.slice_profiles),
            len([job for job in self.manager.slice_jobs if job.enabled]),
            len(printer_profiles),
            len([profile for profile in self.manager.slice_profiles if profile.layer_definition.layer_count]),
            sum(profile.layer_definition.estimated_time.seconds for profile in self.manager.slice_profiles),
            sum(profile.layer_definition.weight_estimate.weight for profile in self.manager.slice_profiles),
        )
        self.manager.slice_statistics = stats
        self.manager.layer_statistics = LayerStatistics(
            sum(profile.layer_definition.layer_count for profile in self.manager.slice_profiles),
            sum(len(profile.layer_definition.preview_reference_ids) for profile in self.manager.slice_profiles),
            sum(len(profile.layer_collection.ranges) for profile in self.manager.slice_profiles),
            stats.estimated_time_seconds,
            stats.estimated_weight,
        )
        return stats

    def _refresh_links(self, item):
        if isinstance(item, SliceJob):
            profile = self.profile_for(item.profile_id)
            if profile is not None:
                item.profile_id = profile.id
        elif isinstance(item, SliceOperation):
            job = self.job_for(item.slice_job_id)
            if job is not None and item.id not in job.operation_ids:
                job.operation_ids.append(item.id)


class SimulationManager:
    """Project-scoped manufacturing simulation metadata helper."""

    PROFILE_CLASSES = {
        "CNC": CNCSimulation,
        "Router": RouterSimulation,
        "Laser": LaserSimulation,
        "Plasma": PlasmaSimulation,
        "Print": PrintSimulation,
        "Generic": GenericSimulation,
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add simulation metadata through ProductManager."""

        if isinstance(item, SimulationJob):
            collection = self.manager.simulation_jobs
        elif isinstance(item, SimulationProfile):
            collection = self.manager.simulation_profiles
        else:
            return None

        if item not in collection:
            collection.append(item)

        self.statistics()
        return item

    def create_profile(self, simulation_type="Generic", name=None, machine_profile=None, tool=None, tool_library=None, setup=None, warnings=None, ready=False, **kwargs):
        """Create simulation profile metadata with relationship hooks only."""

        profile_class = self.PROFILE_CLASSES.get(simulation_type, GenericSimulation)
        profile = profile_class(name or f"{simulation_type} Simulation")
        profile.metadata.simulation_mode = kwargs.get("simulation_mode", "Preview")
        profile.metadata.simulation_quality = kwargs.get("simulation_quality", "Standard")
        profile.metadata.simulation_scope = kwargs.get("simulation_scope", "Job")
        profile.metadata.simulation_status = kwargs.get("simulation_status", "Not Run")
        profile.metadata.simulation_timestamp = kwargs.get("simulation_timestamp", "")
        profile.metadata.simulation_version = kwargs.get("simulation_version", "1.0")
        profile.metadata.background_simulation_placeholder = bool(kwargs.get("background_simulation_placeholder", False))
        profile.validation = SimulationValidation(
            CollisionReference([getattr(item, "id", item) for item in kwargs.get("collision_sources", [])], [getattr(item, "id", item) for item in kwargs.get("collision_targets", [])]),
            LimitReference([getattr(item, "id", item) for item in kwargs.get("limit_references", [])], getattr(machine_profile, "id", machine_profile) or ""),
            ClearanceReference([getattr(item, "id", item) for item in kwargs.get("clearance_references", [])], float(kwargs.get("minimum_clearance", 0.0))),
            MachineReference(getattr(machine_profile, "id", machine_profile) or "", getattr(kwargs.get("machine"), "id", kwargs.get("machine", "")) or "", getattr(kwargs.get("controller"), "id", kwargs.get("controller", "")) or ""),
            ToolReference(getattr(tool, "id", tool) or "", getattr(tool_library, "id", tool_library) or "", getattr(kwargs.get("tool_preset"), "id", kwargs.get("tool_preset", "")) or ""),
            FixtureReference(getattr(setup, "id", setup) or "", [getattr(item, "id", item) for item in kwargs.get("fixtures", [])]),
            StockReference(getattr(setup, "id", setup) or "", [getattr(item, "id", item) for item in kwargs.get("stock_references", [])]),
            warnings or [],
            SimulationReadiness(bool(ready), kwargs.get("readiness_status", "Ready" if ready else "Not Checked"), [getattr(item, "id", item) for item in kwargs.get("missing_references", [])]),
        )
        profile.collision = CollisionMetadata(int(kwargs.get("collision_count", 0)), int(kwargs.get("clearance_warning_count", 0)), kwargs.get("collision_status", "Not Checked"))
        profile.machine_motion = MachineMotionMetadata(int(kwargs.get("estimated_machine_motion", 0)), float(kwargs.get("estimated_axis_travel", 0.0)))
        profile.tool_motion = ToolMotionMetadata(float(kwargs.get("estimated_tool_travel", 0.0)), int(kwargs.get("estimated_tool_changes", 0)))
        profile.head_motion = HeadMotionMetadata(int(kwargs.get("estimated_head_moves", 0)), float(kwargs.get("estimated_head_distance", 0.0)))
        profile.stock_removal = StockRemovalMetadata(float(kwargs.get("estimated_material_removal", 0.0)), getattr(setup, "id", setup) or "")
        profile.layer_simulation = LayerSimulationMetadata(int(kwargs.get("estimated_layer_count", 0)), float(kwargs.get("estimated_material_usage", 0.0)), getattr(kwargs.get("slice_job"), "id", kwargs.get("slice_job", "")) or "")
        profile.travel = TravelMetadata(float(kwargs.get("estimated_travel_distance", 0.0)), float(kwargs.get("rapid_distance", 0.0)), float(kwargs.get("cutting_distance", 0.0)))
        profile.fixture = FixtureMetadata(len(kwargs.get("fixtures", [])), float(kwargs.get("estimated_setup_time", 0.0)))
        profile.safety = SafetyMetadata(kwargs.get("safety_status", "Not Checked"), len(warnings or []), float(kwargs.get("estimated_cooldown_placeholder", 0.0)), float(kwargs.get("estimated_energy_placeholder", 0.0)))
        profile.estimate = SimulationEstimate(
            float(kwargs.get("estimated_runtime", 0.0)),
            profile.travel.estimated_travel_distance,
            profile.stock_removal.estimated_material_removal,
            profile.layer_simulation.estimated_material_usage,
            profile.layer_simulation.estimated_layer_count,
            profile.machine_motion.estimated_motion_count,
            profile.tool_motion.estimated_tool_changes,
            profile.fixture.setup_time_minutes,
            profile.safety.estimated_cooldown_placeholder,
            profile.safety.estimated_energy_placeholder,
        )
        self.add_item(profile)
        for reference, relation in (
            (machine_profile, "SimulationMachineReference"),
            (tool, "SimulationToolReference"),
            (tool_library, "SimulationToolLibraryReference"),
            (setup, "SimulationSetupReference"),
            (kwargs.get("slice_job"), "SimulationSliceReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, profile, relation)
        return profile

    def create_job(self, cam_job=None, slice_job=None, profile=None, name="Simulation Job", enabled=True, **kwargs):
        """Create a simulation job referencing existing CAM and Slice jobs only."""

        result = SimulationResult(
            kwargs.get("result_status", "Not Run"),
            kwargs.get("message", ""),
            SimulationEstimate.from_dict(kwargs.get("estimate", {})),
            kwargs.get("warnings", []),
            dict(kwargs.get("result_properties", {})),
        )
        job = SimulationJob(
            name,
            getattr(cam_job, "id", cam_job) or "",
            getattr(slice_job, "id", slice_job) or "",
            getattr(profile, "id", profile) or "",
            SimulationMetadata(
                kwargs.get("simulation_type", getattr(getattr(profile, "metadata", None), "simulation_type", "Generic")),
                kwargs.get("simulation_mode", "Preview"),
                kwargs.get("simulation_quality", "Standard"),
                kwargs.get("simulation_scope", "Job"),
                kwargs.get("simulation_status", "Not Run"),
                kwargs.get("simulation_timestamp", ""),
                kwargs.get("simulation_version", "1.0"),
                bool(enabled),
                bool(kwargs.get("background_simulation_placeholder", False)),
            ),
            result,
        )
        job.enabled = bool(enabled)
        self.add_item(job)
        for reference, relation in (
            (cam_job, "SimulationCAMJobReference"),
            (slice_job, "SimulationSliceJobReference"),
            (profile, "SimulationProfileReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, job, relation)
        return job

    def set_enabled(self, job, enabled=True):
        """Enable or disable a simulation job."""

        target = self.job_for(job)
        if target is not None:
            target.enabled = bool(enabled)
            target.metadata.enabled = bool(enabled)
        self.statistics()
        return target

    def job_for(self, job):
        """Return a simulation job by object, id or name."""

        if isinstance(job, SimulationJob):
            return job if job in self.manager.simulation_jobs else None
        return _find_by_id_or_name(self.manager.simulation_jobs, job)

    def profile_for(self, profile):
        """Return a simulation profile by object, id or name."""

        if isinstance(profile, SimulationProfile):
            return profile if profile in self.manager.simulation_profiles else None
        return _find_by_id_or_name(self.manager.simulation_profiles, profile)

    def jobs_for_cam_job(self, cam_job):
        """Return simulation jobs assigned to a CAM job."""

        cam_job_id = getattr(cam_job, "id", cam_job)
        return [job for job in self.manager.simulation_jobs if job.cam_job_id == cam_job_id]

    def jobs_for_slice_job(self, slice_job):
        """Return simulation jobs assigned to a slice job."""

        slice_job_id = getattr(slice_job, "id", slice_job)
        return [job for job in self.manager.simulation_jobs if job.slice_job_id == slice_job_id]

    def visible_objects(self):
        """Return visible simulation metadata records."""

        if not self.manager.visible:
            return []
        return [
            item for item in self.manager.simulation_jobs + self.manager.simulation_profiles
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return simulation statistics."""

        warnings = sum(len(profile.validation.warnings) for profile in self.manager.simulation_profiles)
        warnings += sum(len(job.result.warnings) for job in self.manager.simulation_jobs)
        stats = SimulationStatistics(
            len(self.manager.simulation_jobs),
            len(self.manager.simulation_profiles),
            len([job for job in self.manager.simulation_jobs if job.enabled]),
            warnings,
            len([profile for profile in self.manager.simulation_profiles if profile.validation.readiness.ready]),
            len([job for job in self.manager.simulation_jobs if job.cam_job_id]),
            len([job for job in self.manager.simulation_jobs if job.slice_job_id]),
        )
        self.manager.simulation_statistics = stats
        return stats


class NestingManager:
    """Project-scoped nesting, stock, and fabrication metadata helper."""

    STOCK_TYPES = {
        "Sheet Stock", "Plate Stock", "Panel Stock", "Board Stock",
        "Tube placeholder", "Bar placeholder", "Roll Material placeholder",
    }

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add nesting or fabrication metadata through ProductManager."""

        if isinstance(item, NestingJob):
            collection = self.manager.nesting_jobs
        elif isinstance(item, NestingProfile):
            collection = self.manager.nesting_profiles
        elif isinstance(item, StockLibrary):
            collection = self.manager.stock_libraries
        elif isinstance(item, StockProfile):
            collection = self.manager.stock_profiles
        elif isinstance(item, FabricationPlan):
            collection = self.manager.fabrication_plans
        elif isinstance(item, FabricationJob):
            collection = self.manager.fabrication_jobs
        elif isinstance(item, FabricationGroup):
            collection = self.manager.fabrication_groups
        elif isinstance(item, CutList):
            collection = self.manager.cut_lists
        elif isinstance(item, PanelLayout):
            collection = self.manager.panel_layouts
        elif isinstance(item, PartPlacement):
            collection = self.manager.part_placements
        elif isinstance(item, StockAssignment):
            collection = self.manager.stock_assignments
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_stock_library(self, name="Stock Library", metadata=None):
        """Create a reusable stock library."""

        return self.add_item(StockLibrary(name, metadata))

    def create_stock_profile(self, library=None, name="Stock Profile", stock_type="Sheet Stock", length=0.0, width=0.0, thickness=0.0, material=None, quantity=1, grain_direction="", supplier_placeholder="", cost_placeholder=0.0, notes="", properties=None):
        """Create stock profile metadata using existing EngineeringMaterial references."""

        if stock_type not in self.STOCK_TYPES:
            stock_type = "Sheet Stock"
        material_reference = StockMaterialReference(
            getattr(material, "id", material) or "",
            "",
            getattr(material, "name", "") if material is not None else "",
        )
        profile = StockProfile(
            name,
            getattr(library, "id", library) or "",
            length,
            width,
            thickness,
            quantity,
            material_reference,
            StockMetadata(stock_type, grain_direction, supplier_placeholder, float(cost_placeholder), notes, properties or {}),
        )
        self.add_item(profile)
        if library is not None:
            self.manager.dependency_manager.add_edge(library, profile, "StockLibraryProfileReference")
        if material is not None:
            self.manager.dependency_manager.add_edge(material, profile, "StockMaterialReference")
        return profile

    def create_profile(self, name="Nesting Profile", stock_profiles=None, machine_profile=None, metadata=None, estimate=None, **kwargs):
        """Create reusable nesting profile metadata only."""

        profile = NestingProfile(
            name,
            [getattr(profile, "id", profile) for profile in stock_profiles or []],
            getattr(machine_profile, "id", machine_profile) or "",
            metadata or NestingMetadata(
                kwargs.get("description", ""),
                kwargs.get("status", "Not Nested"),
                kwargs.get("priority", "Normal"),
                bool(kwargs.get("enabled", True)),
                bool(kwargs.get("background_nesting_placeholder", False)),
                dict(kwargs.get("properties", {})),
            ),
            estimate or self._estimate_from_kwargs(kwargs),
        )
        self.add_item(profile)
        for stock_profile in stock_profiles or []:
            self.manager.dependency_manager.add_edge(stock_profile, profile, "NestingStockReference")
        if machine_profile is not None:
            self.manager.dependency_manager.add_edge(machine_profile, profile, "NestingMachineReference")
        return profile

    def create_job(self, cam_job, profile=None, name="Nesting Job", enabled=True, metadata=None, result=None, **kwargs):
        """Create a nesting job that references an existing CAMJob only."""

        job = NestingJob(
            name,
            getattr(cam_job, "id", cam_job) or "",
            getattr(profile, "id", profile) or "",
            metadata or NestingMetadata(enabled=enabled, background_nesting_placeholder=bool(kwargs.get("background_nesting_placeholder", False))),
            result or NestingResult(estimate=self._estimate_from_kwargs(kwargs)),
        )
        job.enabled = bool(enabled)
        job.metadata.enabled = bool(enabled)
        self.add_item(job)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, job, "NestingCAMJobReference")
        if profile is not None:
            self.manager.dependency_manager.add_edge(profile, job, "NestingProfileReference")
        return job

    def create_part_placement(self, part=None, stock_profile=None, panel_layout=None, x=0.0, y=0.0, rotation=0.0, quantity=1, properties=None):
        """Store future placement metadata without calculating layout."""

        placement = PartPlacement(
            str(uuid4()),
            getattr(part, "id", part) or "",
            getattr(stock_profile, "id", stock_profile) or "",
            getattr(panel_layout, "id", panel_layout) or "",
            float(x),
            float(y),
            float(rotation),
            int(quantity),
            properties or {},
        )
        self.add_item(placement)
        for reference, relation in (
            (part, "NestingPlacementPartReference"),
            (stock_profile, "NestingPlacementStockReference"),
            (panel_layout, "NestingPlacementPanelReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, placement, relation)
        return placement

    def create_stock_assignment(self, stock_profile=None, parts=None, machine_profile=None, setup=None, quantity=1, properties=None):
        """Store stock assignment relationship metadata only."""

        assignment = StockAssignment(
            str(uuid4()),
            getattr(stock_profile, "id", stock_profile) or "",
            [getattr(part, "id", part) for part in parts or []],
            getattr(machine_profile, "id", machine_profile) or "",
            getattr(setup, "id", setup) or "",
            int(quantity),
            properties or {},
        )
        self.add_item(assignment)
        for reference, relation in (
            (stock_profile, "FabricationAssignmentStockReference"),
            (machine_profile, "FabricationAssignmentMachineReference"),
            (setup, "FabricationAssignmentSetupReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, assignment, relation)
        for part in parts or []:
            self.manager.dependency_manager.add_edge(part, assignment, "FabricationAssignmentPartReference")
        return assignment

    def create_cut_list(self, name="Cut List", parts=None, placements=None, assignments=None, metadata=None):
        """Create fabrication cut list metadata."""

        cut_list = CutList(
            name,
            [getattr(part, "id", part) for part in parts or []],
            [getattr(placement, "id", placement) for placement in placements or []],
            [getattr(assignment, "id", assignment) for assignment in assignments or []],
            metadata,
        )
        self.add_item(cut_list)
        for part in parts or []:
            self.manager.dependency_manager.add_edge(part, cut_list, "CutListPartReference")
        return cut_list

    def create_panel_layout(self, stock_profile=None, placements=None, name="Panel Layout", metadata=None, estimate=None):
        """Create panel layout metadata without previewing or optimizing placement."""

        layout = PanelLayout(
            name,
            getattr(stock_profile, "id", stock_profile) or "",
            [getattr(placement, "id", placement) for placement in placements or []],
            metadata,
            estimate,
        )
        self.add_item(layout)
        if stock_profile is not None:
            self.manager.dependency_manager.add_edge(stock_profile, layout, "PanelLayoutStockReference")
        for placement in placements or []:
            self.manager.dependency_manager.add_edge(placement, layout, "PanelLayoutPlacementReference")
        return layout

    def create_fabrication_group(self, name="Fabrication Group", parts=None, assignments=None, metadata=None):
        """Create a fabrication grouping placeholder."""

        group = FabricationGroup(
            name,
            [getattr(part, "id", part) for part in parts or []],
            [getattr(assignment, "id", assignment) for assignment in assignments or []],
            metadata,
        )
        self.add_item(group)
        return group

    def create_fabrication_plan(self, cam_job=None, name="Fabrication Plan", cut_lists=None, panel_layouts=None, groups=None, assignments=None, metadata=None, estimate=None):
        """Create a fabrication plan that references existing CAM and planning metadata."""

        plan = FabricationPlan(
            name,
            getattr(cam_job, "id", cam_job) or "",
            [getattr(item, "id", item) for item in cut_lists or []],
            [getattr(item, "id", item) for item in panel_layouts or []],
            [getattr(item, "id", item) for item in groups or []],
            [getattr(item, "id", item) for item in assignments or []],
            metadata,
            estimate,
        )
        self.add_item(plan)
        if cam_job is not None:
            self.manager.dependency_manager.add_edge(cam_job, plan, "FabricationPlanCAMReference")
        return plan

    def create_fabrication_job(self, plan=None, cam_job=None, machine_profile=None, name="Fabrication Job", enabled=True, metadata=None):
        """Create fabrication job metadata."""

        job = FabricationJob(
            name,
            getattr(plan, "id", plan) or "",
            getattr(cam_job, "id", cam_job) or getattr(plan, "cam_job_id", ""),
            getattr(machine_profile, "id", machine_profile) or "",
            bool(enabled),
            metadata,
        )
        self.add_item(job)
        for reference, relation in (
            (plan, "FabricationJobPlanReference"),
            (cam_job, "FabricationJobCAMReference"),
            (machine_profile, "FabricationJobMachineReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, job, relation)
        return job

    def set_enabled(self, job, enabled=True):
        """Enable or disable a nesting job."""

        target = self.job_for(job)
        if target is not None:
            target.enabled = bool(enabled)
            target.metadata.enabled = bool(enabled)
        self.statistics()
        return target

    def job_for(self, job):
        """Return a nesting job by object, id, or name."""

        if isinstance(job, NestingJob):
            return job if job in self.manager.nesting_jobs else None
        return _find_by_id_or_name(self.manager.nesting_jobs, job)

    def profile_for(self, profile):
        """Return a nesting profile by object, id, or name."""

        if isinstance(profile, NestingProfile):
            return profile if profile in self.manager.nesting_profiles else None
        return _find_by_id_or_name(self.manager.nesting_profiles, profile)

    def stock_library_for(self, library):
        """Return a stock library by object, id, or name."""

        if isinstance(library, StockLibrary):
            return library if library in self.manager.stock_libraries else None
        return _find_by_id_or_name(self.manager.stock_libraries, library)

    def stock_profile_for(self, profile):
        """Return a stock profile by object, id, or name."""

        if isinstance(profile, StockProfile):
            return profile if profile in self.manager.stock_profiles else None
        return _find_by_id_or_name(self.manager.stock_profiles, profile)

    def jobs_for_cam_job(self, cam_job):
        """Return nesting jobs assigned to a CAM job."""

        cam_job_id = getattr(cam_job, "id", cam_job)
        return [job for job in self.manager.nesting_jobs if job.cam_job_id == cam_job_id]

    def visible_objects(self):
        """Return visible nesting and fabrication records."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.nesting_jobs +
                self.manager.nesting_profiles +
                self.manager.stock_libraries +
                self.manager.stock_profiles +
                self.manager.fabrication_plans +
                self.manager.fabrication_jobs +
                self.manager.fabrication_groups +
                self.manager.cut_lists +
                self.manager.panel_layouts
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return nesting and fabrication statistics."""

        stats = NestingStatistics(
            len(self.manager.nesting_jobs),
            len(self.manager.nesting_profiles),
            len([job for job in self.manager.nesting_jobs if job.enabled]),
            len(self.manager.stock_libraries),
            len(self.manager.stock_profiles),
            len(self.manager.fabrication_plans),
            len(self.manager.cut_lists),
            len(self.manager.panel_layouts),
            len(self.manager.stock_assignments),
        )
        self.manager.nesting_statistics = stats
        return stats

    def _estimate_from_kwargs(self, kwargs):
        return NestingEstimate(
            MaterialUsageEstimate(float(kwargs.get("estimated_material_area", 0.0)), float(kwargs.get("estimated_material_volume", 0.0)), float(kwargs.get("estimated_material_weight", 0.0))),
            WasteEstimate(float(kwargs.get("estimated_waste_area", 0.0)), float(kwargs.get("estimated_waste_percentage", 0.0))),
            YieldEstimate(float(kwargs.get("estimated_yield_percentage", 0.0)), float(kwargs.get("estimated_usable_area", 0.0))),
            PanelStatistics(int(kwargs.get("estimated_panels", 0)), int(kwargs.get("estimated_placed_parts", 0)), int(kwargs.get("estimated_assigned_stock", 0))),
            CutStatistics(int(kwargs.get("estimated_cuts", 0)), int(kwargs.get("estimated_cut_lists", 0)), int(kwargs.get("estimated_machining_sequences", 0))),
            FabricationEstimate(float(kwargs.get("estimated_fabrication_time", 0.0)), float(kwargs.get("estimated_cost_placeholder", 0.0)), int(kwargs.get("batch_count", 0))),
        )

    def _refresh_links(self, item):
        if isinstance(item, StockProfile):
            library = self.stock_library_for(item.library_id)
            if library is not None and item.id not in library.profile_ids:
                library.profile_ids.append(item.id)
        elif isinstance(item, NestingJob):
            profile = self.profile_for(item.profile_id)
            if profile is not None:
                item.profile_id = profile.id
        elif isinstance(item, PanelLayout):
            for placement_id in item.placement_ids:
                placement = _find_by_id_or_name(self.manager.part_placements, placement_id)
                if placement is not None:
                    placement.panel_layout_id = item.id


class ManufacturingJobManager:
    """Project-scoped manufacturing job, setup-sheet, dashboard and report helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add manufacturing job-management metadata through ProductManager."""

        if isinstance(item, ManufacturingJob):
            collection = self.manager.manufacturing_jobs
        elif isinstance(item, ManufacturingJobCollection):
            collection = self.manager.manufacturing_job_collections
        elif isinstance(item, ManufacturingJobProfile):
            collection = self.manager.manufacturing_job_profiles
        elif isinstance(item, SetupSheet):
            collection = self.manager.setup_sheets
        elif isinstance(item, SetupSheetCollection):
            collection = self.manager.setup_sheet_collections
        elif isinstance(item, ManufacturingDashboard):
            collection = self.manager.manufacturing_dashboards
        elif isinstance(item, ManufacturingBrowser):
            collection = self.manager.manufacturing_browsers
        elif isinstance(item, ProductionQueue):
            collection = self.manager.production_queues
        elif isinstance(item, JobQueue):
            collection = self.manager.job_queues
        elif isinstance(item, JobHistory):
            collection = self.manager.job_histories
        elif isinstance(item, (ProductionReport, ShopFloorDocument, ReadinessReport)):
            return self.manager.product_report_manager.add_item(item)
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_profile(self, name="Manufacturing Job Profile", references=None, metadata=None):
        """Create reusable job profile metadata."""

        profile = ManufacturingJobProfile(name, [getattr(item, "id", item) for item in references or []], metadata)
        self.add_item(profile)
        return profile

    def create_job(self, name="Manufacturing Job", cam_job=None, slice_job=None, simulation_job=None, nesting_job=None, profile=None, group="", priority="Normal", status="Pending", enabled=True):
        """Create a manufacturing job referencing existing manufacturing records only."""

        job = ManufacturingJob(
            name,
            getattr(cam_job, "id", cam_job) or "",
            getattr(slice_job, "id", slice_job) or "",
            getattr(simulation_job, "id", simulation_job) or "",
            getattr(nesting_job, "id", nesting_job) or "",
            getattr(profile, "id", profile) or "",
            ManufacturingJobMetadata(group, priority, status, bool(enabled)),
        )
        self.add_item(job)
        for reference, relation in (
            (cam_job, "ManufacturingJobCAMReference"),
            (slice_job, "ManufacturingJobSliceReference"),
            (simulation_job, "ManufacturingJobSimulationReference"),
            (nesting_job, "ManufacturingJobNestingReference"),
            (profile, "ManufacturingJobProfileReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, job, relation)
        return job

    def create_collection(self, name="Manufacturing Job Collection", jobs=None, metadata=None):
        """Create job grouping metadata."""

        collection = ManufacturingJobCollection(name, [getattr(job, "id", job) for job in jobs or []], metadata)
        self.add_item(collection)
        for job in jobs or []:
            self.manager.dependency_manager.add_edge(job, collection, "ManufacturingJobCollectionReference")
        return collection

    def create_setup_sheet(self, job=None, setup=None, machine_profile=None, tools=None, materials=None, fixtures=None, operations=None, instructions=None, name="Setup Sheet", **kwargs):
        """Create setup sheet metadata from existing manufacturing references."""

        sheet = SetupSheet(
            name,
            getattr(job, "id", job) or "",
            getattr(setup, "id", setup) or "",
            instructions or [SetupInstruction(kwargs.get("operator_notes", ""), 0)] if kwargs.get("operator_notes", "") else [],
            ToolList([getattr(tool, "id", tool) for tool in tools or []], [getattr(preset, "id", preset) for preset in kwargs.get("tool_presets", [])]),
            FixtureList([getattr(fixture, "id", fixture) for fixture in fixtures or []], [getattr(setup, "id", setup)] if setup is not None else []),
            MaterialList([getattr(material, "id", material) for material in materials or []], [getattr(stock, "id", stock) for stock in kwargs.get("stock_profiles", [])]),
            MachineSetup(getattr(machine_profile, "id", machine_profile) or "", getattr(kwargs.get("controller_profile"), "id", kwargs.get("controller_profile", "")) or "", getattr(setup, "id", setup) or ""),
            OperationSummary([getattr(operation, "id", operation) for operation in operations or []], float(kwargs.get("estimated_time", 0.0)), kwargs.get("notes", "")),
        )
        sheet.operator_notes = kwargs.get("operator_notes", "")
        sheet.revision_placeholder = kwargs.get("revision_placeholder", "")
        sheet.qr_code_placeholder = kwargs.get("qr_code_placeholder", "")
        sheet.barcode_placeholder = kwargs.get("barcode_placeholder", "")
        self.add_item(sheet)
        for reference, relation in (
            (job, "SetupSheetJobReference"),
            (setup, "SetupSheetSetupReference"),
            (machine_profile, "SetupSheetMachineReference"),
        ):
            if reference is not None:
                self.manager.dependency_manager.add_edge(reference, sheet, relation)
        return sheet

    def create_dashboard(self, name="Manufacturing Dashboard", jobs=None, metrics=None, metadata=None):
        """Create manufacturing dashboard metadata."""

        dashboard = ManufacturingDashboard(name, [getattr(job, "id", job) for job in jobs or []], metrics, metadata)
        self.add_item(dashboard)
        return dashboard

    def create_browser(self, name="Manufacturing Browser", metadata=None):
        """Create manufacturing browser state metadata."""

        return self.add_item(ManufacturingBrowser(name, metadata))

    def create_queue(self, name="Production Queue", queue_type="Production", metadata=None):
        """Create production or job queue metadata."""

        queue_class = JobQueue if queue_type == "Job" else ProductionQueue
        return self.add_item(queue_class(name, metadata))

    def create_history(self, name="Job History", metadata=None):
        """Create job history metadata."""

        return self.add_item(JobHistory(name, metadata))

    def create_report(self, report_type="Production", target=None, sources=None, name=None):
        """Create production, shop-floor or readiness report metadata."""

        report_class = ReadinessReport if report_type == "Readiness" else ShopFloorDocument if report_type == "Shop Floor" else ProductionReport
        report = report_class(name or f"{report_type} Report", getattr(target, "id", target) or "", [getattr(item, "id", item) for item in sources or []])
        return self.add_item(report)

    def set_enabled(self, job, enabled=True):
        """Enable or disable a manufacturing job."""

        target = self.job_for(job)
        if target is not None:
            target.enabled = bool(enabled)
            target.metadata.enabled = bool(enabled)
        self.statistics()
        return target

    def job_for(self, job):
        """Return a manufacturing job by object, id, or name."""

        if isinstance(job, ManufacturingJob):
            return job if job in self.manager.manufacturing_jobs else None
        return _find_by_id_or_name(self.manager.manufacturing_jobs, job)

    def visible_objects(self):
        """Return visible manufacturing job-management records."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.manufacturing_jobs +
                self.manager.manufacturing_job_collections +
                self.manager.manufacturing_job_profiles +
                self.manager.setup_sheets +
                self.manager.setup_sheet_collections +
                self.manager.manufacturing_dashboards +
                self.manager.manufacturing_browsers +
                self.manager.production_queues +
                self.manager.job_queues +
                self.manager.job_histories
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return manufacturing job statistics."""

        stats = ManufacturingJobStatistics(
            len(self.manager.manufacturing_jobs),
            len(self.manager.manufacturing_job_collections),
            len(self.manager.manufacturing_job_profiles),
            len([job for job in self.manager.manufacturing_jobs if job.enabled]),
            len([job for job in self.manager.manufacturing_jobs if job.metadata.status == "Ready"]),
            len([job for job in self.manager.manufacturing_jobs if job.metadata.status == "Warning"]),
            len([job for job in self.manager.manufacturing_jobs if job.metadata.status == "Pending"]),
        )
        self.manager.manufacturing_job_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, ManufacturingJob):
            profile = _find_by_id_or_name(self.manager.manufacturing_job_profiles, item.profile_id)
            if profile is not None and item.id not in profile.reference_ids:
                profile.reference_ids.append(item.id)


class ToolLibraryManager:
    """Project-scoped CAM tool library helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add CAM tool-library metadata."""

        if isinstance(item, ToolLibrary):
            collection = self.manager.tool_libraries
        elif isinstance(item, ToolCategory):
            collection = self.manager.tool_categories
        elif isinstance(item, ToolDefinition):
            collection = self.manager.tool_definitions
        elif isinstance(item, ToolHolder):
            collection = self.manager.tool_holders
        elif isinstance(item, FeedSpeedProfile):
            collection = self.manager.feed_speed_profiles
        elif isinstance(item, ToolPreset):
            collection = self.manager.tool_presets
        elif isinstance(item, ToolOffset):
            collection = self.manager.tool_offsets
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        self.manager.holder_manager.statistics()
        return item

    def create_library(self, name="Tool Library", metadata=None):
        """Create a tool library."""

        return self.add_item(ToolLibrary(name, metadata))

    def create_category(self, library, name="Tool Category", metadata=None):
        """Create a tool category inside a library."""

        return self.add_item(ToolCategory(name, getattr(library, "id", library) or "", metadata))

    def create_tool(self, tool_class=EndMill, library=None, category=None, name=None, **kwargs):
        """Create a cutting tool definition without geometry ownership."""

        if isinstance(tool_class, str):
            tool_class = _tool_class_from_name(tool_class)
        if not issubclass(tool_class, ToolDefinition):
            tool_class = EndMill

        if tool_class is ToolDefinition:
            tool = ToolDefinition(
                name or "Tool",
                kwargs.get("tool_type", "Tool"),
                getattr(library, "id", library) or "",
                getattr(category, "id", category) or "",
                kwargs.get("diameter", 0.0),
                kwargs.get("flute_length", 0.0),
                kwargs.get("overall_length", 0.0),
                kwargs.get("flutes", 0),
                kwargs.get("corner_radius", 0.0),
                kwargs.get("tip_angle", 0.0),
                kwargs.get("metadata"),
            )
        else:
            tool = tool_class(
                name or tool_class.__name__,
                getattr(library, "id", library) or "",
                getattr(category, "id", category) or "",
                kwargs.get("diameter", 0.0),
                kwargs.get("flute_length", 0.0),
                kwargs.get("overall_length", 0.0),
                kwargs.get("flutes", 0),
                kwargs.get("corner_radius", 0.0),
                kwargs.get("tip_angle", 0.0),
                kwargs.get("metadata"),
            )
        return self.add_item(tool)

    def create_feed_speed_profile(self, tool, material=None, name="Feed & Speed Profile", cutting_data=None, metadata=None):
        """Create a feed and speed profile for a tool and optional material."""

        profile = FeedSpeedProfile(
            name,
            getattr(tool, "id", tool) or "",
            getattr(material, "id", material) or "",
            cutting_data,
            metadata,
        )
        self.add_item(profile)
        self.manager.dependency_manager.add_edge(tool, profile, "ToolFeedSpeedReference")
        if material:
            self.manager.dependency_manager.add_edge(material, profile, "ToolMaterialReference")
        return profile

    def create_preset(self, tool, holder=None, profile=None, name="Tool Preset", tool_number=0, length_offset=0, diameter_offset=0, metadata=None):
        """Create a tool preset combining a tool, holder and cutting data."""

        preset = ToolPreset(
            name,
            getattr(tool, "id", tool) or "",
            getattr(holder, "id", holder) or "",
            getattr(profile, "id", profile) or "",
            tool_number,
            length_offset,
            diameter_offset,
            metadata,
        )
        self.add_item(preset)
        self.manager.dependency_manager.add_edge(tool, preset, "ToolPresetReference")
        if holder:
            self.manager.dependency_manager.add_edge(holder, preset, "ToolHolderReference")
        if profile:
            self.manager.dependency_manager.add_edge(profile, preset, "FeedSpeedProfileReference")
        return preset

    def assign_preset_to_operation(self, preset, operation):
        """Reference a tool preset from a CAM operation without machining."""

        target = self.manager.operation_manager.operation_for(operation)
        tool = self.tool_for(getattr(preset, "tool_id", ""))

        if target is not None:
            target.parameters.tool_id = getattr(tool, "id", "") or getattr(preset, "tool_id", "")
            target.metadata.properties["tool_preset_id"] = getattr(preset, "id", preset) or ""
            self.manager.dependency_manager.add_edge(preset, target, "CAMOperationToolPresetReference")

        return target

    def search_tools(self, text):
        """Search tool definitions by name, type, material, coating or standards metadata."""

        query = str(text or "").lower()
        if not query:
            return list(self.manager.tool_definitions)

        def matches(tool):
            metadata = getattr(tool, "metadata", ToolMetadata())
            values = [
                tool.name,
                tool.tool_type,
                metadata.material,
                metadata.coating,
                metadata.iso_id,
                metadata.din_id,
                metadata.ansi_id,
                metadata.supplier_id,
            ]
            return any(query in str(value).lower() for value in values)

        return [tool for tool in self.manager.tool_definitions if matches(tool)]

    def library_for(self, library):
        """Return a tool library by object, id or name."""

        if isinstance(library, ToolLibrary):
            return library if library in self.manager.tool_libraries else None
        return _find_by_id_or_name(self.manager.tool_libraries, library)

    def category_for(self, category):
        """Return a tool category by object, id or name."""

        if isinstance(category, ToolCategory):
            return category if category in self.manager.tool_categories else None
        return _find_by_id_or_name(self.manager.tool_categories, category)

    def tool_for(self, tool):
        """Return a tool definition by object, id or name."""

        if isinstance(tool, ToolDefinition):
            return tool if tool in self.manager.tool_definitions else None
        return _find_by_id_or_name(self.manager.tool_definitions, tool)

    def tools_for_library(self, library):
        """Return tools assigned to a library."""

        library_id = getattr(library, "id", library)
        return [tool for tool in self.manager.tool_definitions if tool.library_id == library_id]

    def tools_for_category(self, category):
        """Return tools assigned to a category."""

        category_id = getattr(category, "id", category)
        return [tool for tool in self.manager.tool_definitions if tool.category_id == category_id]

    def visible_objects(self):
        """Return visible tool-library records for selection and highlighting."""

        if not self.manager.visible:
            return []
        return [
            item for item in (
                self.manager.tool_libraries +
                self.manager.tool_categories +
                self.manager.tool_definitions +
                self.manager.tool_holders +
                self.manager.feed_speed_profiles +
                self.manager.tool_presets
            )
            if getattr(item, "visible", True)
        ]

    def statistics(self):
        """Return tool-library statistics."""

        stats = ToolStatistics(
            len(self.manager.tool_libraries),
            len(self.manager.tool_categories),
            len(self.manager.tool_definitions),
            len(self.manager.tool_holders),
            len(self.manager.feed_speed_profiles),
            len(self.manager.tool_presets),
            len([tool for tool in self.manager.tool_definitions if getattr(getattr(tool, "metadata", None), "favorite", False)]),
        )
        self.manager.tool_statistics = stats
        return stats

    def _refresh_links(self, item):
        if isinstance(item, ToolCategory):
            library = self.library_for(item.library_id)
            if library is not None and item.id not in library.category_ids:
                library.category_ids.append(item.id)
        elif isinstance(item, ToolDefinition):
            library = self.library_for(item.library_id)
            category = self.category_for(item.category_id)
            if library is not None and item.id not in library.tool_ids:
                library.tool_ids.append(item.id)
            if category is not None and item.id not in category.tool_ids:
                category.tool_ids.append(item.id)
        elif isinstance(item, ToolHolder):
            library = self.library_for(item.library_id)
            if library is not None and item.id not in library.holder_ids:
                library.holder_ids.append(item.id)
        elif isinstance(item, ToolPreset):
            tool = self.tool_for(item.tool_id)
            library = self.library_for(getattr(tool, "library_id", ""))
            if tool is not None and item.id not in tool.preset_ids:
                tool.preset_ids.append(item.id)
            if library is not None and item.id not in library.preset_ids:
                library.preset_ids.append(item.id)


class HolderManager:
    """Project-scoped CAM tool-holder helper."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add a tool holder through the tool library manager."""

        if not isinstance(item, ToolHolder):
            return None
        return self.manager.tool_library_manager.add_item(item)

    def create_holder(self, library=None, name="Tool Holder", holder_type="HolderDefinition", length=0.0, gauge_length=0.0, metadata=None):
        """Create a holder or collet definition."""

        holder_class = Collet if holder_type == "Collet" else HolderDefinition
        holder = holder_class(name, getattr(library, "id", library) or "", length, gauge_length, metadata)
        return self.add_item(holder)

    def holder_for(self, holder):
        """Return a holder by object, id or name."""

        if isinstance(holder, ToolHolder):
            return holder if holder in self.manager.tool_holders else None
        return _find_by_id_or_name(self.manager.tool_holders, holder)

    def holders_for_library(self, library):
        """Return holders assigned to a library."""

        library_id = getattr(library, "id", library)
        return [holder for holder in self.manager.tool_holders if holder.library_id == library_id]

    def statistics(self):
        """Return holder statistics."""

        stats = HolderStatistics(
            len(self.manager.tool_holders),
            len([holder for holder in self.manager.tool_holders if isinstance(holder, Collet)]),
            len([holder for holder in self.manager.tool_holders if isinstance(holder, HolderDefinition)]),
        )
        self.manager.holder_statistics = stats
        return stats


class EdgeModificationManager:
    """Project-scoped helper for fillet and chamfer feature metadata."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add edge modification metadata."""

        if isinstance(item, EdgeSelection):
            collection = self.manager.edge_selections
        elif isinstance(item, EdgeChain):
            collection = self.manager.edge_chains
        elif isinstance(item, EdgeModificationMetadata):
            collection = self.manager.edge_modification_metadata
        else:
            return None

        if item not in collection:
            collection.append(item)

        self._refresh_links(item)
        self.statistics()
        return item

    def create_fillet(self, part, body, edge_indices=None, radius=1.0, name="Fillet"):
        """Create a constant-radius fillet feature foundation."""

        return self._create_edge_feature(
            FilletFeature,
            "Fillet",
            part,
            body,
            edge_indices or [],
            EdgeModificationMetadata(
                modification_type="Constant Radius Fillet",
                radius=radius,
            ),
            name,
        )

    def create_chamfer(self, part, body, edge_indices=None, distance=1.0, name="Chamfer"):
        """Create a constant-distance chamfer feature foundation."""

        return self._create_edge_feature(
            ChamferFeature,
            "Chamfer",
            part,
            body,
            edge_indices or [],
            EdgeModificationMetadata(
                modification_type="Constant Distance Chamfer",
                distance=distance,
            ),
            name,
        )

    def selections_for_feature(self, feature):
        """Return edge selections assigned to a feature."""

        feature_id = getattr(feature, "id", feature)
        return [
            selection for selection in self.manager.edge_selections
            if selection.feature_id == feature_id
        ]

    def chains_for_feature(self, feature):
        """Return edge chains assigned to a feature."""

        feature_id = getattr(feature, "id", feature)
        return [
            chain for chain in self.manager.edge_chains
            if chain.feature_id == feature_id
        ]

    def statistics(self):
        """Return edge modification statistics."""

        stats = EdgeModificationStatistics(
            len([feature for feature in self.manager.features if isinstance(feature, FilletFeature)]),
            len([feature for feature in self.manager.features if isinstance(feature, ChamferFeature)]),
            len(self.manager.edge_selections),
            len(self.manager.edge_chains),
        )
        self.manager.edge_modification_statistics = stats
        return stats

    def _create_edge_feature(self, feature_class, feature_type, part, body, edge_indices, metadata, name):
        part_id = getattr(part, "id", part) or ""
        body_id = getattr(body, "id", body) or ""
        mesh_id = getattr(body, "mesh_entity_id", "")
        distance = metadata.radius if feature_type == "Fillet" else metadata.distance
        definition = FeatureDefinition(
            body_id=body_id,
            target_body_ids=[body_id] if body_id else [],
            options=FeatureOptions("Join", distance=distance),
            parameters=metadata.to_dict(),
        )
        feature = feature_class(
            name,
            part_id,
            definition,
            FeatureMetadata(status="Pending"),
            FeatureResult(body_id, mesh_id),
        )
        self.manager.feature_manager.add_item(feature)
        self.manager.edge_modification_metadata.append(metadata)

        for edge_index in edge_indices:
            self.add_item(EdgeSelection(body_id, mesh_id, int(edge_index), feature.id))

        self.manager.dependency_manager.add_edge(feature, body, "FeatureToBody")
        self.statistics()
        return feature

    def _refresh_links(self, item):
        if isinstance(item, EdgeSelection):
            feature = self.manager.feature_manager.feature_for(item.feature_id)
            if feature is not None:
                feature.definition.parameters.setdefault("edge_selection_ids", [])
                if item.id not in feature.definition.parameters["edge_selection_ids"]:
                    feature.definition.parameters["edge_selection_ids"].append(item.id)
        elif isinstance(item, EdgeChain):
            feature = self.manager.feature_manager.feature_for(item.feature_id)
            if feature is not None:
                feature.definition.parameters.setdefault("edge_chain_ids", [])
                if item.id not in feature.definition.parameters["edge_chain_ids"]:
                    feature.definition.parameters["edge_chain_ids"].append(item.id)


class PatternManager:
    """Project-scoped helper for feature and body pattern metadata."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add pattern metadata or pattern instances."""

        if isinstance(item, PatternInstance):
            collection = self.manager.pattern_instances
        elif isinstance(item, PatternDefinition):
            collection = self.manager.pattern_definitions
        elif isinstance(item, PatternMetadata):
            collection = self.manager.pattern_metadata
        else:
            return None

        if item not in collection:
            collection.append(item)

        self.statistics()
        return item

    def create_pattern(self, part, body=None, source_features=None, source_bodies=None, pattern_definition=None, name="Pattern"):
        """Create a pattern feature referencing existing features or bodies."""

        part_id = getattr(part, "id", part) or ""
        source_features = list(source_features or [])
        source_bodies = list(source_bodies or [])
        feature_ids = [getattr(feature, "id", feature) for feature in source_features]
        body_ids = [getattr(source_body, "id", source_body) for source_body in source_bodies]
        target_body_id = getattr(body, "id", body) or (body_ids[0] if body_ids else "")
        mesh_id = getattr(body, "mesh_entity_id", "")
        pattern_definition = pattern_definition or PatternDefinition(
            source_feature_ids=feature_ids,
            source_body_ids=body_ids,
        )
        feature = PatternFeature(
            name,
            part_id,
            FeatureDefinition(
                body_id=target_body_id,
                target_body_ids=[target_body_id] if target_body_id else [],
                options=FeatureOptions("Join", distance=pattern_definition.spacing),
                parameters=pattern_definition.to_dict(),
            ),
            FeatureMetadata(status="Pending"),
            FeatureResult(target_body_id, mesh_id),
            pattern_definition,
            PatternMetadata(pattern_type=pattern_definition.pattern_type),
        )
        self.manager.feature_manager.add_item(feature)
        self.manager.pattern_definitions.append(pattern_definition)
        self.manager.pattern_metadata.append(feature.pattern_metadata)
        self._build_instances(feature)
        self._build_dependencies(feature)
        self.statistics()
        return feature

    def instances_for_feature(self, feature):
        """Return pattern instances assigned to a pattern feature."""

        feature_id = getattr(feature, "id", feature)
        return [
            instance for instance in self.manager.pattern_instances
            if instance.feature_id == feature_id
        ]

    def regenerate_pattern(self, feature, workspace=None):
        """Regenerate pattern metadata and update the existing target MeshEntity."""

        target = self.manager.feature_manager.feature_for(feature)

        if target is None:
            return None

        self.manager.pattern_instances = [
            instance for instance in self.manager.pattern_instances
            if instance.feature_id != target.id
        ]
        self._build_instances(target)
        self.manager.regeneration_manager.mark_dirty(target)
        return self.manager.regeneration_manager.rebuild_feature(target, workspace)

    def statistics(self):
        """Return pattern statistics."""

        pattern_features = [feature for feature in self.manager.features if isinstance(feature, PatternFeature)]
        stats = PatternStatistics(
            len(pattern_features),
            len(self.manager.pattern_instances),
            len([
                feature for feature in pattern_features
                if getattr(feature.pattern_metadata, "source_type", "Feature") == "Feature"
            ]),
            len([
                feature for feature in pattern_features
                if getattr(feature.pattern_metadata, "source_type", "Feature") == "Body"
            ]),
        )
        self.manager.pattern_statistics = stats
        return stats

    def _build_instances(self, feature):
        definition = getattr(feature, "pattern_definition", PatternDefinition())
        direction = definition.direction
        count = max(int(definition.count), 1)
        sources = list(definition.source_feature_ids) or list(definition.source_body_ids)
        source_type = "Feature" if definition.source_feature_ids else "Body"

        for index in range(count):
            for source_id in sources:
                self.manager.pattern_instances.append(
                    PatternInstance(
                        feature.id,
                        source_id,
                        source_type,
                        index,
                        Vector3(
                            direction.x * definition.spacing * index,
                            direction.y * definition.spacing * index,
                            direction.z * definition.spacing * index,
                        ),
                    )
                )

    def _build_dependencies(self, feature):
        definition = getattr(feature, "pattern_definition", PatternDefinition())
        for source_id in definition.source_feature_ids:
            source = self.manager.feature_manager.feature_for(source_id) or source_id
            self.manager.dependency_manager.add_edge(source, feature, "FeaturePattern")
        for body_id in definition.source_body_ids:
            body = self.manager.body_for(body_id) or body_id
            self.manager.dependency_manager.add_edge(body, feature, "BodyPattern")


@dataclass
class FeatureState:
    """Editable state snapshot for a product feature."""

    dirty: bool = False
    visible: bool = True
    suppressed: bool = False
    needs_regeneration: bool = False
    last_result_status: str = "Pending"

    def to_dict(self):
        """Return JSON-safe feature state."""

        return dict(self.__dict__)

    @staticmethod
    def from_dict(data):
        """Create feature state from persisted data."""

        data = data or {}
        return FeatureState(
            bool(data.get("dirty", False)),
            bool(data.get("visible", True)),
            bool(data.get("suppressed", False)),
            bool(data.get("needs_regeneration", False)),
            data.get("last_result_status", "Pending"),
        )


