@dataclass
class DependencyNode:
    """Stored dependency node for future graph compatibility."""

    type_name = "DependencyNode"
    owner_id: str = ""
    node_type: str = "Feature"
    name: str = ""
    metadata: DependencyMetadata = field(default_factory=DependencyMetadata)
    graph_id: str = ""
    parent_ids: list = field(default_factory=list)
    child_ids: list = field(default_factory=list)
    incoming_edge_ids: list = field(default_factory=list)
    outgoing_edge_ids: list = field(default_factory=list)
    dependency_level: int = 0
    graph_group: str = ""
    graph_identifier: str = ""
    traversal_metadata: dict = field(default_factory=dict)
    dirty: bool = False
    pending_evaluation: bool = False
    affected_object_ids: list = field(default_factory=list)
    timestamp_history: list = field(default_factory=list)
    version_metadata: dict = field(default_factory=dict)
    id: str = field(default_factory=lambda: str(uuid4()))
    is_dependency_node: bool = True
    is_product: bool = True
    is_3d: bool = True

    def to_dict(self):
        """Return JSON-safe dependency node data."""

        return {
            "id": self.id,
            "owner_id": self.owner_id,
            "node_type": self.node_type,
            "name": self.name,
            "metadata": self.metadata.to_dict(),
            "graph_id": self.graph_id,
            "parent_ids": list(self.parent_ids),
            "child_ids": list(self.child_ids),
            "incoming_edge_ids": list(self.incoming_edge_ids),
            "outgoing_edge_ids": list(self.outgoing_edge_ids),
            "dependency_level": self.dependency_level,
            "graph_group": self.graph_group,
            "graph_identifier": self.graph_identifier,
            "traversal_metadata": dict(self.traversal_metadata),
            "dirty": self.dirty,
            "pending_evaluation": self.pending_evaluation,
            "affected_object_ids": list(self.affected_object_ids),
            "timestamp_history": list(self.timestamp_history),
            "version_metadata": dict(self.version_metadata),
        }

    def segments(self):
        """Return no geometry segments; dependency nodes own no geometry."""

        return []

    def points(self):
        """Return no geometry points; dependency nodes own no geometry."""

        return []

    @staticmethod
    def from_dict(data):
        """Create dependency node data."""

        data = data or {}
        return DependencyNode(
            data.get("owner_id", ""),
            data.get("node_type", "Feature"),
            data.get("name", ""),
            DependencyMetadata.from_dict(data.get("metadata", {})),
            data.get("graph_id", ""),
            list(data.get("parent_ids", [])),
            list(data.get("child_ids", [])),
            list(data.get("incoming_edge_ids", [])),
            list(data.get("outgoing_edge_ids", [])),
            int(data.get("dependency_level", 0)),
            data.get("graph_group", ""),
            data.get("graph_identifier", ""),
            dict(data.get("traversal_metadata", {})),
            bool(data.get("dirty", False)),
            bool(data.get("pending_evaluation", False)),
            list(data.get("affected_object_ids", [])),
            list(data.get("timestamp_history", [])),
            dict(data.get("version_metadata", {})),
            data.get("id", str(uuid4())),
        )


@dataclass
class DependencyEdge:
    """Stored directed dependency relationship; no solving is performed."""

    type_name = "DependencyEdge"
    source_id: str = ""
