    flags: EvaluationFlags = field(default_factory=EvaluationFlags)
    priority: EvaluationPriority = field(default_factory=EvaluationPriority)
    state: str = "Queued"
    group_id: str = ""
    batch_id: str = ""
    timestamp: str = ""
