    locked: bool = False
    selected: bool = False
    layer_name: str = "0"
    is_evaluation_request: bool = True
    is_product: bool = True
    is_3d: bool = True
    type_name = "EvaluationRequest"

    def to_dict(self):
        """Return JSON-safe evaluation request."""

        return _product_marker_data(self, {
            "change_type": self.change_type,
            "target_id": self.target_id,
            "context": self.context.to_dict(),
            "flags": self.flags.to_dict(),
            "priority": self.priority.to_dict(),
            "state": self.state,
            "group_id": self.group_id,
            "batch_id": self.batch_id,
            "timestamp": self.timestamp,
            "metadata": self.metadata.to_dict(),
        })

    def segments(self):
        """Return no geometry segments; evaluation requests own no geometry."""

        return []

    def points(self):
        """Return no geometry points; evaluation requests own no geometry."""

        return []

    @staticmethod
    def from_dict(data):
        """Create evaluation request from persisted data."""

        data = data or {}
        item = EvaluationRequest(
            data.get("name", "Evaluation Request"),
            data.get("change_type", "Parameter Changed"),
            data.get("target_id", ""),
            EvaluationContext.from_dict(data.get("context", {})),
            EvaluationFlags.from_dict(data.get("flags", {})),
            EvaluationPriority.from_dict(data.get("priority", {})),
            data.get("state", "Queued"),
            data.get("group_id", ""),
            data.get("batch_id", ""),
            data.get("timestamp", ""),
            SolverMetadata.from_dict(data.get("metadata", {})),
            data.get("id", str(uuid4())),
        )
        _restore_marker_state(item, data)
        return item


