class ExecutionScheduler:
    """Sorts execution requests without creating a separate manager."""

    def order_requests(self, requests):
        """Return queued requests ordered by priority."""

        return sorted(requests, key=lambda request: getattr(request, "priority", 0), reverse=True)


class SolverScheduler:
    """Orders dependency nodes for LiveSolver execution without creating SolverManager."""

    def order_nodes(self, nodes, priority=None):
        """Return dependency nodes ordered by priority, dependency level and stable id."""

        priority = priority or {}
        return sorted(
            nodes,
            key=lambda node: (
                -int(priority.get(getattr(node, "owner_id", ""), priority.get(getattr(node, "id", ""), 0))),
                int(getattr(node, "dependency_level", 0)),
                getattr(node, "id", ""),
            ),
        )


