class ExpressionParser:
    """Safe expression parser for arithmetic, functions, variables and parameters."""

    def parse(self, text):
        """Parse expression text into a Python AST expression tree."""

        return ast.parse(str(text or "0"), mode="eval")


class ExpressionEvaluator:
    """Whitelist evaluator for Release 2.0 parameter and expression activation."""

    _binary_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
    }
    _unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
    }
    _comparisons = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }
    _functions = {
        "abs": abs,
        "min": min,
        "max": max,
        "round": round,
        "sqrt": math.sqrt,
        "sin": math.sin,
        "cos": math.cos,
        "tan": math.tan,
        "floor": math.floor,
        "ceil": math.ceil,
    }

    def __init__(self, parser=None):
        self.parser = parser or ExpressionParser()

    def evaluate(self, text, variables=None):
        """Evaluate expression text with a restricted AST and variable map."""

        variables = variables or {}
        tree = self.parser.parse(text)
        return self._evaluate_node(tree.body, variables)

    def _evaluate_node(self, node, variables):
        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, ast.Name):
            if node.id in variables:
                return variables[node.id]
            if node.id in ("pi", "tau", "e"):
                return getattr(math, node.id)
            raise ValueError(f"Unknown variable: {node.id}")
        if isinstance(node, ast.BinOp):
            op = self._binary_ops.get(type(node.op))
            if op is None:
                raise ValueError("Unsupported operator")
            return op(self._evaluate_node(node.left, variables), self._evaluate_node(node.right, variables))
        if isinstance(node, ast.UnaryOp):
            op = self._unary_ops.get(type(node.op))
            if op is None:
                raise ValueError("Unsupported unary operator")
            return op(self._evaluate_node(node.operand, variables))
        if isinstance(node, ast.BoolOp):
            values = [bool(self._evaluate_node(value, variables)) for value in node.values]
            return all(values) if isinstance(node.op, ast.And) else any(values)
        if isinstance(node, ast.Compare):
            left = self._evaluate_node(node.left, variables)
            for op_node, comparator in zip(node.ops, node.comparators):
                right = self._evaluate_node(comparator, variables)
                op = self._comparisons.get(type(op_node))
                if op is None or not op(left, right):
                    return False
                left = right
            return True
        if isinstance(node, ast.IfExp):
            return self._evaluate_node(node.body if self._evaluate_node(node.test, variables) else node.orelse, variables)
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            func = self._functions.get(node.func.id)
            if func is None:
                raise ValueError(f"Unsupported function: {node.func.id}")
            return func(*[self._evaluate_node(arg, variables) for arg in node.args])
        raise ValueError("Unsupported expression")


