class ParametricManager:
    """Project-scoped helper for metadata-only parametric engine records."""

    def __init__(self, manager):

        self.manager = manager

    def add_item(self, item):
        """Add parametric metadata through ProductManager storage."""

        if isinstance(item, ParametricEngine):
            collection = self.manager.parametric_engines
            self.manager.active_parametric_engine_id = item.id
        elif isinstance(item, ParametricDocument):
            collection = self.manager.parametric_documents
            self.manager.active_parametric_document_id = item.id
        elif isinstance(item, ParametricWorkspace):
            collection = self.manager.parametric_workspaces
        elif isinstance(item, ParametricSession):
            collection = self.manager.parametric_sessions
            self.manager.active_parametric_session_id = item.id
        elif isinstance(item, ParametricContext):
            collection = self.manager.parametric_contexts
        elif isinstance(item, LiveSolver):
            collection = self.manager.live_solvers
        elif isinstance(item, SolverSession):
            collection = self.manager.solver_sessions
        elif isinstance(item, SolverContext):
            collection = self.manager.solver_contexts
        elif isinstance(item, SolverQueue):
            collection = self.manager.solver_queues
        elif isinstance(item, SolverHistory):
            collection = self.manager.solver_histories
        elif isinstance(item, EvaluationRequest):
            collection = self.manager.evaluation_requests
        elif isinstance(item, EvaluationBatch):
            collection = self.manager.evaluation_batches
        elif isinstance(item, EvaluationContext):
            collection = self.manager.evaluation_contexts
