    def create_geometry_kernel(self, name="Geometry Kernel", engine=None, execution_engine=None, metadata=None):
        """Create the GeometryKernel subsystem under the existing ParametricEngine."""

        engine = self.engine_for(engine) or self.active_engine() or self.create_engine()
        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine() or self.create_execution_engine(engine=engine)
        kernel = GeometryKernel(name, getattr(engine, "id", "") or "", getattr(execution_engine, "id", "") or "", metadata)
        self.add_item(kernel)
        if not kernel.pipeline_ids:
            self.create_geometry_pipeline("Geometry Pipeline", kernel, engine)
        return kernel

    def create_geometry_pipeline(self, name="Geometry Pipeline", kernel=None, engine=None, metadata=None):
        """Declare the locked feature-to-body-to-MeshEntity geometry pipeline."""

        kernel = self.geometry_kernel_for(kernel) or self.active_geometry_kernel() or self.create_geometry_kernel(engine=engine)
        engine = self.engine_for(engine) or self.engine_for(getattr(kernel, "engine_id", "")) or self.active_engine()
        pipeline = GeometryPipeline(name, getattr(engine, "id", "") or "", getattr(kernel, "id", "") or "", metadata)
        self.add_item(pipeline)
        return pipeline

    def create_geometry_session(self, name="Geometry Session", kernel=None, feature=None, context=None, metadata=None):
        """Create a geometry execution session that references existing feature data."""

        kernel = self.geometry_kernel_for(kernel) or self.active_geometry_kernel() or self.create_geometry_kernel()
        feature = self.manager.feature_manager.feature_for(feature)
        context = context or GeometryContext(
            engine_id=getattr(kernel, "engine_id", "") or "",
            kernel_id=getattr(kernel, "id", "") or "",
            execution_engine_id=getattr(kernel, "execution_engine_id", "") or "",
            feature_id=getattr(feature, "id", "") or "",
            body_id=getattr(getattr(feature, "result", None), "body_id", "") or getattr(getattr(feature, "definition", None), "body_id", ""),
            mesh_entity_id=getattr(getattr(feature, "result", None), "mesh_entity_id", ""),
        )
        session = GeometrySession(name, getattr(kernel, "id", "") or "", getattr(feature, "id", "") or "", context, metadata=metadata)
        self.add_item(session)
        return session

    def generate_feature_geometry(self, feature, workspace=None, kernel=None, session=None):
        """Generate BRep metadata and synchronize MeshEntity through BodyManager."""

        feature = self.manager.feature_manager.feature_for(feature)
        if feature is None or getattr(feature, "suppressed", False):
            return None

        kernel = self.geometry_kernel_for(kernel) or self.active_geometry_kernel() or self.create_geometry_kernel()
        session = self.geometry_session_for(session) or self.create_geometry_session(kernel=kernel, feature=feature)
        self.manager.feature_manager.execute_feature_metadata(feature)

        mesh_data = self.manager.feature_manager._mesh_for_feature(feature)
        body_before = self.manager.body_for(feature.result.body_id or feature.definition.body_id)
        body, mesh_entity, body_created = self.manager.body_manager.create_or_update_from_feature(feature, mesh_data, workspace)
        topology = self._topology_from_mesh(feature, body, mesh_entity, mesh_data)
        self.add_item(topology)

        result = GeometryResult(
            session.id,
            feature.id,
            getattr(body, "id", "") or "",
            getattr(mesh_entity, "id", "") or getattr(mesh_entity, "name", "") or "",
            topology.id,
            "Completed",
            "Geometry generated through FeatureManager -> BodyManager -> MeshEntity.",
            body_created or body_before is None,
            mesh_entity is not None,
            len(getattr(mesh_data, "vertices", [])),
            len(getattr(mesh_data, "edges", [])),
            len(getattr(mesh_data, "faces", [])),
            GeometryMetadata(status="Completed", properties={"feature_type": feature.feature_type}),
        )
        self.add_item(result)
        cache = GeometryCache(feature.id, result.body_id, result.mesh_entity_id, topology.id, f"{feature.id}:{feature.order}:{feature.feature_type}", False, {"result_id": result.id})
        self.add_item(cache)
        history = GeometryHistory(kernel.id, session.id, feature.id, result.body_id, result.mesh_entity_id, "Generate Geometry", "Completed", result.message)
        self.add_item(history)

        session.state = GeometryState("Completed", "Valid", "Updated", "Synchronized", False, False)
        session.diagnostics = GeometryDiagnostics("Completed", [result.message], topology_valid=True, mesh_synchronized=True)
        session.context.body_id = result.body_id
        session.context.mesh_entity_id = result.mesh_entity_id
        session.context.topology_id = topology.id
        session.result = result
        if topology.id not in session.topology_ids:
            session.topology_ids.append(topology.id)
        if history.id not in session.history_ids:
            session.history_ids.append(history.id)

        kernel.state = session.state
        kernel.diagnostics = session.diagnostics
        kernel.cache = cache
        kernel.metadata.status = "Completed"
        kernel.statistics = self._geometry_statistics()
        for attr, value in (("result_ids", result.id), ("topology_ids", topology.id), ("history_ids", history.id)):
            values = getattr(kernel, attr)
            if value not in values:
                values.append(value)

        feature.result.body_id = result.body_id
        feature.result.mesh_entity_id = result.mesh_entity_id
        feature.result.status = "Geometry Generated"
        feature.result.message = result.message
        feature.result.updated = True
        feature.metadata.status = "Geometry Generated"
        feature.metadata.properties["geometry_kernel_id"] = kernel.id
        feature.metadata.properties["topology_id"] = topology.id
        feature.execution_state.status = "Completed"
        feature.execution_state.execution_status = "Completed"
        feature.execution_metadata.pipeline_stage = "Geometry Kernel"
        feature.execution_metadata.properties["geometry_generation"] = "Generated"
        feature.diagnostics = FeatureDiagnostics("Completed", [result.message], [], [], [], False)

        graph = self.manager.dependency_manager.create_graph("Geometry Kernel Dependency Graph")
        self.manager.dependency_manager.add_edge(feature, body, "FeatureToBody", graph=graph)
        self.manager.dependency_manager.add_edge(body, getattr(mesh_entity, "id", "") or getattr(mesh_entity, "name", "") or "", "BodyToMeshEntity", graph=graph)
        self.manager.update_manager.queue_update("Geometry generation", feature.id, "GeometryKernel synchronized BodyManager and MeshEntity")
        self.statistics()
        return result

    def _topology_from_mesh(self, feature, body, mesh_entity, mesh_data):
        """Build BRep topology metadata from generated mesh topology."""

        topology = BRepTopology(
            f"{feature.name} Topology",
            getattr(feature, "id", "") or "",
            getattr(body, "id", "") or "",
            getattr(mesh_entity, "id", "") or getattr(mesh_entity, "name", "") or "",
            GeometryMetadata(status="Valid", properties={"source_feature_type": getattr(feature, "feature_type", ""), "body_manager_owned": True, "mesh_entity_owner": getattr(mesh_entity, "id", "") or getattr(mesh_entity, "name", "") or ""}),
        )
        for element_type, count, attr in (
            ("Vertex", len(getattr(mesh_data, "vertices", [])), "vertex_ids"),
            ("Edge", len(getattr(mesh_data, "edges", [])), "edge_ids"),
            ("Wire", max(1, len(getattr(mesh_data, "edges", [])) // 4), "wire_ids"),
            ("Loop", max(1, len(getattr(mesh_data, "faces", [])) // 2), "loop_ids"),
            ("Face", len(getattr(mesh_data, "faces", [])), "face_ids"),
            ("Shell", 1, "shell_ids"),
            ("Solid", 1, "solid_ids"),
            ("Compound", 1, "compound_ids"),
            ("Body", 1, "body_ids"),
        ):
            ids = []
            for index in range(max(0, count)):
                element = TopologyElement(f"{feature.name} {element_type} {index + 1}", element_type, topology.id, index, GeometryMetadata(status="Valid", properties={"feature_id": feature.id, "body_id": getattr(body, "id", "") or ""}))
                self.add_item(element)
                ids.append(element.id)
            setattr(topology, attr, ids)
        topology.validation_status = "Valid"
        topology.diagnostics = GeometryDiagnostics("Valid", ["Topology metadata generated from feature result."], topology_valid=True, mesh_synchronized=True)
        return topology

    def create_sketch_solver(self, name="Sketch Solver", engine=None, execution_engine=None, live_solver=None, metadata=None):
        """Create a sketch solver subsystem under the existing ParametricEngine."""

        engine = self.engine_for(engine) or self.active_engine() or self.create_engine()
        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine() or self.create_execution_engine(engine=engine)
        live_solver = self.solver_for(live_solver) or self.active_solver() or self.create_solver(engine=engine)
        solver = SketchSolver(
            name,
            getattr(engine, "id", "") or "",
            getattr(execution_engine, "id", "") or "",
            getattr(live_solver, "id", "") or "",
            metadata,
        )
        self.add_item(solver)
        return solver

    def create_sketch_solve_session(self, name="Sketch Solve Session", solver=None, sketch=None, context=None, metadata=None):
        """Create a sketch solve session that references existing sketch data only."""

        solver = self.sketch_solver_for(solver) or self.active_sketch_solver() or self.create_sketch_solver()
        sketch = self.manager.sketch_manager.sketch_for(sketch) or self.manager.sketch_manager.sketch_for(getattr(self.manager, "active_sketch_id", ""))
        context = context or SketchSolveContext(
            solver_id=getattr(solver, "id", "") or "",
            sketch_id=getattr(sketch, "id", "") or "",
            execution_engine_id=getattr(solver, "execution_engine_id", "") or "",
            live_solver_id=getattr(solver, "live_solver_id", "") or "",
        )
        session = SketchSolveSession(
            name,
            getattr(solver, "id", "") or "",
            getattr(sketch, "id", "") or "",
            context,
            metadata=metadata,
        )
        self.add_item(session)
        return session

    def solve_sketch(self, sketch, solver=None, session=None, changed=None, graph=None, execution_engine=None):
        """Solve a sketch through ParametricEngine metadata without creating 3D geometry."""

        solver = self.sketch_solver_for(solver) or self.active_sketch_solver() or self.create_sketch_solver()
        sketch = self.manager.sketch_manager.sketch_for(sketch)
        if sketch is None:
            return None
        session = self.sketch_solve_session_for(session) or self.create_sketch_solve_session(solver=solver, sketch=sketch)
        execution_engine = self.execution_engine_for(execution_engine) or self.execution_engine_for(solver.execution_engine_id) or self.active_execution_engine() or self.create_execution_engine()
        graph = self.manager.dependency_manager.graph_for(graph) or self.manager.dependency_manager.create_graph("Sketch Solver Dependency Graph")
        changed = list(changed or [])
        for item in changed:
            self.propagate_dirty(item, graph)
        self.run_live_solver(solver=solver.live_solver_id, graph=graph, changed=changed, execution_engine=execution_engine)

        geometry = self.manager.sketch_manager.geometry_for(sketch)
        constraints = self.manager.sketch_manager.constraints_for(sketch)
        dimensions = self.manager.sketch_manager.dimensions_for(sketch)
        diagnostics = self.validate_sketch_constraints(sketch, constraints)
        dof = self.calculate_sketch_dof(sketch, constraints, geometry, dimensions)
        status = "Over Constrained" if dof["over_constrained"] else ("Fully Constrained" if dof["remaining_dof"] == 0 else "Under Constrained")

        for index, constraint in enumerate(constraints):
            if constraint.id in diagnostics.conflicting_constraint_ids:
                constraint.metadata.status = "Conflict"
                constraint.display_color = "#ef5350"
            elif constraint.enabled and not constraint.suppressed:
                constraint.metadata.status = "Solved"
                constraint.display_color = "#66bb6a"
            else:
                constraint.metadata.status = "Suppressed"
                constraint.display_color = "#b0bec5"
            constraint.metadata.properties["evaluation_order"] = index
            constraint.metadata.properties["solver_id"] = solver.id

        for item in geometry:
            item.display_color = "#80deea" if getattr(item, "construction", False) else "#ffffff"
            if not hasattr(item, "metadata"):
                item.metadata = {}
            if isinstance(getattr(item, "metadata", None), dict):
                item.metadata["solver_status"] = status

        sketch.metadata.status = status
        sketch.metadata.properties["degrees_of_freedom"] = dof
        sketch.metadata.properties["solver_id"] = solver.id
        sketch.metadata.properties["diagnostics"] = diagnostics.to_dict()

        session.state = SketchSolveState("Completed", "Solved", status, diagnostics.status, False, diagnostics.over_constrained)
        session.diagnostics = diagnostics
        session.context = SketchSolveContext(
            solver.id,
            session.id,
            sketch.id,
            getattr(execution_engine, "id", "") or "",
            solver.live_solver_id,
            getattr(graph, "id", "") or "",
            [getattr(item, "id", item) for item in self.manager.parameters],
            [getattr(item, "id", item) for item in self.manager.expressions],
            [getattr(item, "id", item) for item in changed],
            [item.id for item in geometry],
            [item.id for item in constraints],
        )
        session.metadata = SketchExecutionMetadata(
            "Sketch Solver",
            getattr(execution_engine, "id", "") or "",
            solver.live_solver_id,
            getattr(graph, "id", "") or "",
            "Completed",
            {"degrees_of_freedom": dof, "renderer_overlay": "metadata-only"},
        )
        session.evaluation_order = SketchEvaluationOrder(
            sketch.id,
            [constraint.id for constraint in constraints],
            [item.id for item in geometry],
            [dimension.id for dimension in dimensions],
            list(getattr(graph, "node_ids", [])),
        )
        solver.state = session.state
        solver.diagnostics = diagnostics
        solver.cache.values[sketch.id] = dof
        if sketch.id not in solver.cache.solved_sketch_ids:
            solver.cache.solved_sketch_ids.append(sketch.id)
        if sketch.id in solver.cache.dirty_sketch_ids:
            solver.cache.dirty_sketch_ids.remove(sketch.id)
        history = SketchHistory(
            solver.id,
            session.id,
            sketch.id,
            "Sketch Solve",
            status,
            f"Solved {len(diagnostics.solved_constraint_ids)} constraints; DOF {dof['remaining_dof']}",
            [constraint.id for constraint in constraints],
            [item.id for item in geometry],
        )
        self.add_item(history)
        if history.id not in session.history_ids:
            session.history_ids.append(history.id)
        self._sketch_solver_statistics()
        return session

    def validate_sketch_constraints(self, sketch, constraints=None):
        """Validate supported sketch constraints and report conflicts."""

        constraints = list(constraints or self.manager.sketch_manager.constraints_for(sketch))
        diagnostics = SketchDiagnostics("Solved")
        seen = {}
        supported = {
            "coincident", "horizontal", "vertical", "parallel", "perpendicular", "tangent", "concentric",
            "collinear", "equal", "symmetry", "symmetric", "midpoint", "fix", "fixed", "distance",
            "radius", "diameter", "angle", "offset",
        }
        for constraint in constraints:
            normalized = str(getattr(constraint, "constraint_type", "")).strip().lower()
            if not getattr(constraint, "enabled", True) or getattr(constraint, "suppressed", False):
                continue
            if normalized not in supported:
                diagnostics.unsatisfied_constraint_ids.append(constraint.id)
                diagnostics.messages.append(f"Unsupported constraint metadata: {constraint.constraint_type}")
                continue
            key = tuple(sorted(getattr(constraint, "geometry_ids", [])))
            previous = seen.get(key)
            if previous and {previous, normalized} in ({"horizontal", "vertical"}, {"parallel", "perpendicular"}):
                diagnostics.conflicting_constraint_ids.append(constraint.id)
                diagnostics.conflicting_constraint_ids.append(next(item.id for item in constraints if str(item.constraint_type).strip().lower() == previous and tuple(sorted(item.geometry_ids)) == key))
                diagnostics.messages.append(f"Conflicting constraints on {key}")
                continue
            seen[key] = normalized
            diagnostics.solved_constraint_ids.append(constraint.id)
        diagnostics.conflicting_constraint_ids = list(dict.fromkeys(diagnostics.conflicting_constraint_ids))
        diagnostics.over_constrained = bool(diagnostics.conflicting_constraint_ids)
        diagnostics.status = "Conflict" if diagnostics.over_constrained else "Solved"
        diagnostics.fully_constrained = False
        diagnostics.under_constrained = not diagnostics.over_constrained
        return diagnostics

    def calculate_sketch_dof(self, sketch, constraints=None, geometry=None, dimensions=None):
        """Calculate sketch degrees of freedom using existing sketch-owned records."""

        geometry = list(geometry or self.manager.sketch_manager.geometry_for(sketch))
        constraints = [
            item for item in list(constraints or self.manager.sketch_manager.constraints_for(sketch))
            if getattr(item, "enabled", True) and not getattr(item, "suppressed", False)
        ]
        dimensions = list(dimensions or self.manager.sketch_manager.dimensions_for(sketch))
        base_dof = sum(max(1, len(getattr(item, "points_data", []))) * 2 for item in geometry)
        weights = {
            "coincident": 2, "concentric": 2, "fix": 2, "fixed": 2, "horizontal": 1, "vertical": 1,
            "parallel": 1, "perpendicular": 1, "tangent": 1, "collinear": 1, "equal": 1,
            "symmetry": 2, "symmetric": 2, "midpoint": 2, "distance": 1, "radius": 1,
            "diameter": 1, "angle": 1, "offset": 1,
        }
        reductions = sum(weights.get(str(item.constraint_type).strip().lower(), 0) for item in constraints)
        reductions += len([item for item in dimensions if getattr(getattr(item, "metadata", None), "driving", True)])
        remaining = max(0, base_dof - reductions)
        over = reductions > base_dof or bool(self.validate_sketch_constraints(sketch, constraints).conflicting_constraint_ids)
        return {
            "base_dof": base_dof,
            "constraint_reductions": reductions,
            "remaining_dof": remaining,
            "fully_constrained": remaining == 0 and not over,
            "under_constrained": remaining > 0 and not over,
            "over_constrained": over,
            "constraint_count": len(constraints),
            "dimension_count": len(dimensions),
            "geometry_count": len(geometry),
        }

    def create_execution_engine(self, name="Execution Engine", engine=None, metadata=None):
        """Create the single execution-engine subsystem under ParametricEngine."""

        engine = self.engine_for(engine) or self.active_engine()
        execution = ExecutionEngine(name, getattr(engine, "id", "") or "", metadata)
        self.add_item(execution)
        if not execution.pipeline_ids:
            self.create_execution_pipeline("Execution Pipeline", execution, engine)
        return execution

    def create_execution_session(self, name="Execution Session", execution_engine=None, engine=None, context=None, metadata=None):
        """Create an execution session referencing existing ParametricEngine state."""

        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine()
        engine = self.engine_for(engine) or self.engine_for(getattr(execution_engine, "engine_id", "")) or self.active_engine()
        context = context or ExecutionContext(engine_id=getattr(engine, "id", "") or "")
        session = ExecutionSession(name, getattr(execution_engine, "id", "") or "", context, metadata=metadata)
        self.add_item(session)
        return session

    def create_execution_pipeline(self, name="Execution Pipeline", execution_engine=None, engine=None):
        """Create the locked Release 2.0 execution pipeline declaration."""

        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine()
        engine = self.engine_for(engine) or self.engine_for(getattr(execution_engine, "engine_id", "")) or self.active_engine()
        pipeline = ExecutionPipeline(name, getattr(engine, "id", "") or "")
        self.add_item(pipeline)
        return pipeline

    def queue_execution(self, target, request_type="Evaluate", execution_engine=None, session=None, graph=None, priority=0, metadata=None):
        """Queue execution through the ParametricEngine-owned execution subsystem."""

        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine() or self.create_execution_engine()
        session = self.execution_session_for(session) or (
            self.manager.execution_sessions[-1] if self.manager.execution_sessions else self.create_execution_session(execution_engine=execution_engine)
        )
        target_id = getattr(target, "id", target) or ""
        context = ExecutionContext(
            engine_id=getattr(execution_engine, "engine_id", "") or "",
            session_id=getattr(session, "id", "") or "",
            graph_id=getattr(graph, "id", graph) or "",
            parameter_ids=[target_id] if getattr(target, "is_parametric_parameter", False) or getattr(target, "type_name", "") == "PartParameter" else [],
            expression_ids=[target_id] if getattr(target, "is_expression", False) else [],
            visual_node_ids=[target_id] if getattr(target, "is_visual_node", False) else [],
            object_ids=[target_id],
        )
        request = ExecutionRequest(
            f"{request_type}: {getattr(target, 'name', target_id)}",
            target_id,
            request_type,
            context,
            int(priority),
            ExecutionFlags(queued=True, dirty=True),
            metadata or ExecutionMetadata(status="Queued", pipeline_stage="Execution Engine"),
        )
        self.add_item(request)
        return request

    def execute_request(self, request, variables=None):
        """Execute parameter, expression and basic node requests without geometry generation."""

        request = self.execution_request_for(request)
        if request is None:
            return None
        execution_engine = self.active_execution_engine() or self.create_execution_engine()
        value = None
        status = "Completed"
        message = "Execution completed"
        try:
            target = self._execution_target(request.target_id)
            value = self._execute_target(target, variables or self.parameter_values())
            request.flags.completed = True
            request.flags.running = False
            request.flags.queued = False
            request.metadata.status = "Completed"
            execution_engine.cache.values[request.target_id] = value
            if getattr(target, "is_expression", False):
                execution_engine.expression_cache.values[target.id] = value
                if target.id not in execution_engine.expression_cache.expression_ids:
                    execution_engine.expression_cache.expression_ids.append(target.id)
            if getattr(target, "is_visual_node", False):
                target.flags.execution_status = "Completed"
                target.flags.dirty = False
                target.state.state = "Completed"
                target.state.properties["last_value"] = value
        except Exception as exc:
            status = "Failed"
            message = str(exc)
            request.flags.failed = True
            request.metadata.status = "Failed"
            target = self._execution_target(request.target_id)
            if getattr(target, "is_visual_node", False):
                target.flags.execution_status = "Failed"
                target.state.state = "Failed"
                target.state.message = message
        if getattr(target, "is_expression", False):
            pipeline_stage = "Expression"
        elif getattr(target, "is_visual_node", False):
            pipeline_stage = "Node Execution"
        elif getattr(target, "is_parametric_parameter", False) or getattr(target, "type_name", "") == "PartParameter":
            pipeline_stage = "Parameter"
        else:
            pipeline_stage = "Execution Engine"

        result = ExecutionResult(
            request.id,
            request.target_id,
            status,
            value,
            message,
            [request.target_id],
            ExecutionMetadata(status=status, pipeline_stage=pipeline_stage),
        )
        self.add_item(result)
        history = ExecutionHistory(execution_engine.id, request.id, result.id, status, message, [request.target_id])
        self.add_item(history)
        self.statistics()
        return result

    def execute_batch(self, batch=None, requests=None):
        """Execute a batch of queued requests in priority order."""

        execution_engine = self.active_execution_engine() or self.create_execution_engine()
        requests = list(requests or [self.execution_request_for(request_id) for request_id in getattr(batch, "request_ids", [])])
        requests = [request for request in requests if request is not None]
        ordered = ExecutionScheduler().order_requests(requests)
        results = [self.execute_request(request) for request in ordered]
        if batch is None:
            batch = self.add_item(ExecutionBatch("Execution Batch", [request.id for request in ordered], "Completed"))
        else:
            batch.status = "Completed"
        if batch.id not in execution_engine.batch_ids:
            execution_engine.batch_ids.append(batch.id)
        return results

    def validate_dependency_graph(self, graph=None):
        """Validate dependency references using the existing DependencyManager topology."""

        graph = self.manager.dependency_manager.graph_for(graph) or (self.manager.dependency_graphs[-1] if self.manager.dependency_graphs else None)
        if graph is None:
            return {"valid": True, "cycle_detected": False, "invalid_reference_ids": [], "evaluation_order": []}
        order = self.dependency_order(graph)
        node_ids = set(graph.node_ids)
        invalid = []
        for edge in self.manager.dependency_edges:
            if edge.id in graph.edge_ids and (edge.source_id not in node_ids or edge.target_id not in node_ids):
                invalid.append(edge.id)
        cycle = getattr(graph.flags, "cycle_detection_status", "") == "Cycle Detected"
        diagnostics = {
            "valid": not cycle and not invalid,
            "cycle_detected": cycle,
            "invalid_reference_ids": invalid,
            "evaluation_order": list(order),
            "pending_evaluation_ids": list(getattr(graph, "pending_evaluation_ids", [])),
        }
        graph.metadata.properties["diagnostics"] = diagnostics
        graph.metadata.properties["execution_order"] = list(order)
        graph.metadata.properties["invalid_reference_ids"] = list(invalid)
        return diagnostics

    def run_live_solver(self, solver=None, solver_session=None, graph=None, changed=None, execution_engine=None):
        """Execute dirty dependency graph work through LiveSolver and ExecutionEngine only."""

        solver = self.solver_for(solver) or self.active_solver() or self.create_solver()
        solver_session = self.solver_session_for(solver_session) or (
            self.manager.solver_sessions[-1] if self.manager.solver_sessions else self.create_solver_session(solver=solver)
        )
        execution_engine = self.execution_engine_for(execution_engine) or self.active_execution_engine() or self.create_execution_engine()
        graph = self.manager.dependency_manager.graph_for(graph) or self.manager.dependency_manager.create_graph("Live Solver Dependency Graph")
        changed = list(changed or [])
        changed_ids = [getattr(item, "id", item) for item in changed]
        dirty_ids = []
        for item in changed:
            dirty_ids.extend(self.propagate_dirty(item, graph))
        diagnostics = self.validate_dependency_graph(graph)
        order = list(diagnostics.get("evaluation_order", []))
        context = SolverExecutionContext(
            solver.id,
            solver_session.id,
            execution_engine.id,
            graph.id,
            changed_ids,
            list(dict.fromkeys(dirty_ids)),
            order,
        )
        solver.execution_context = context
        solver.flags.dirty = bool(dirty_ids)
        solver.flags.queued = bool(order)
        solver.state.state = "Evaluating" if order and diagnostics.get("valid", True) else "Blocked"
        solver.state.dependency_state = "Dirty" if dirty_ids else "Clean"
        solver.state.evaluation_state = "Evaluating" if order and diagnostics.get("valid", True) else "Blocked"
        solver.queue.evaluation_queue = list(order)
        solver_session.queue.evaluation_queue = list(order)
        solver_session.state.state = solver.state.state
        if diagnostics.get("cycle_detected") or diagnostics.get("invalid_reference_ids"):
            solver.flags.blocked = True
            solver.diagnostics = SolverDiagnostics(
                "Blocked",
                bool(diagnostics.get("cycle_detected")),
                list(diagnostics.get("invalid_reference_ids", [])),
                context.dirty_node_ids,
                messages=["Dependency graph validation failed"],
            )
            self.add_item(SolverHistory(solver.id, solver_session.id, "Diagnostics", "Blocked", "", "Dependency graph validation failed"))
            self.statistics()
            return []

        results = []
        for node_id in order:
            node = next((item for item in self.manager.dependency_nodes if item.id == node_id), None)
            if node is None:
                continue
            target = self._execution_target(node.owner_id)
            cache_hit = node.owner_id in execution_engine.cache.values and not getattr(node, "dirty", False) and node.owner_id not in dirty_ids and node.owner_id not in changed_ids
            if cache_hit:
                context.skipped_object_ids.append(node.owner_id)
                node.traversal_metadata["execution_status"] = "Skipped"
                continue
            request = self.queue_execution(target, "Reactive Evaluation", execution_engine, None, graph, priority=getattr(node, "dependency_level", 0))
            result = self.execute_request(request)
            results.append(result)
            if result is not None and result.status == "Completed":
                context.executed_object_ids.append(node.owner_id)
                node.dirty = False
                node.pending_evaluation = False
                node.traversal_metadata["execution_status"] = "Completed"
                node.traversal_metadata["execution_result_id"] = result.id
            else:
                context.failed_object_ids.append(node.owner_id)
                node.traversal_metadata["execution_status"] = "Failed"
        solver.flags.dirty = False
        solver.flags.queued = False
        solver.flags.evaluating = False
        solver.flags.blocked = bool(context.failed_object_ids)
        solver.state.state = "Completed" if not context.failed_object_ids else "Failed"
        solver.state.evaluation_state = solver.state.state
        solver.state.dependency_state = "Clean" if not context.failed_object_ids else "Dirty"
        solver.diagnostics = SolverDiagnostics(
            solver.state.state,
            False,
            [],
            context.dirty_node_ids,
            context.skipped_object_ids,
            context.executed_object_ids,
            context.failed_object_ids,
            context.evaluation_order,
        )
        self.add_item(SolverHistory(solver.id, solver_session.id, "Live Solve", solver.state.state, "", f"Executed {len(context.executed_object_ids)}; skipped {len(context.skipped_object_ids)}"))
        self._activate_visual_node_graph_execution(graph, order, context)
        self._activate_data_tree_execution(graph, context)
        self.statistics()
        return results

    def _activate_visual_node_graph_execution(self, graph, order, context):
        """Update visual node execution metadata without graphical redesign."""

        order_index = {node_id: index for index, node_id in enumerate(order)}
        dependency_nodes = {node.id: node for node in self.manager.dependency_nodes}
        for visual_node in self.manager.visual_nodes:
            graph_match = not getattr(visual_node, "graph_id", "") or any(item.id == visual_node.graph_id for item in self.manager.visual_node_graphs)
            if not graph_match:
                continue
            dependency_node = next((node for node in dependency_nodes.values() if node.owner_id == visual_node.id), None)
            if dependency_node is None:
                continue
            visual_node.state.properties["evaluation_order"] = order_index.get(dependency_node.id)
            visual_node.state.properties["execution_graph_id"] = getattr(graph, "id", "")
            if visual_node.id in context.executed_object_ids:
                visual_node.flags.execution_status = "Completed"
                visual_node.flags.dirty = False
                visual_node.state.state = "Completed"
            elif visual_node.id in context.skipped_object_ids:
                visual_node.flags.execution_status = "Skipped"
                visual_node.state.state = "Skipped"
            elif visual_node.id in context.failed_object_ids:
                visual_node.flags.execution_status = "Failed"
                visual_node.state.state = "Failed"
        for visual_graph in self.manager.visual_node_graphs:
            visual_graph.metadata.properties["execution_order"] = list(order)
            visual_graph.metadata.properties["execution_diagnostics"] = context.to_dict()
            visual_graph.flags.execution_status = "Completed" if not context.failed_object_ids else "Failed"

    def _activate_data_tree_execution(self, graph, context):
        """Update data tree branch/path execution metadata without CAD execution."""

        for tree in self.manager.data_trees:
            if getattr(tree, "graph_id", "") not in ("", getattr(graph, "id", "")):
                continue
            tree.metadata.properties["execution_context"] = context.to_dict()
            tree.flags.dirty = False
            for branch in self.manager.data_branches:
                if branch.tree_id != tree.id:
                    continue
                branch.state.state = "Evaluated"
                branch.state.properties["execution_graph_id"] = getattr(graph, "id", "")
                branch.state.properties["dirty_inputs"] = list(context.dirty_node_ids)
                branch.flags.dirty = False
                history = DataTreeHistory(tree.id, branch.id, "", "", "Branch Evaluated", "Branch metadata evaluated")
                self.add_item(history)
            for flow in self.manager.data_flows:
                if flow.tree_id == tree.id:
                    flow.metadata.properties["execution_status"] = "Evaluated"
                    flow.metadata.properties["execution_graph_id"] = getattr(graph, "id", "")

    def evaluate_expression(self, expression, variables=None):
        """Evaluate an expression record or raw text through the safe evaluator."""

        if getattr(expression, "is_expression", False):
            text = expression.text
            variables = variables or self.parameter_values()
            value = ExpressionEvaluator().evaluate(text, variables)
            expression.validation_state = "Valid"
            expression.evaluation_state = "Evaluated"
            return value
        return ExpressionEvaluator().evaluate(expression, variables or self.parameter_values())

    def parameter_values(self):
        """Return parameter values by name and id for expression evaluation."""

        values = {}
        for parameter in self.manager.parameters:
            values[getattr(parameter, "name", "")] = getattr(parameter, "value", None)
            values[getattr(parameter, "id", "")] = getattr(parameter, "value", None)
        return values

    def dependency_order(self, graph=None):
        """Compute dependency order from existing DependencyManager metadata."""

        graph = self.manager.dependency_manager.graph_for(graph) or (self.manager.dependency_graphs[-1] if self.manager.dependency_graphs else None)
        if graph is None:
            return []
        self.manager.dependency_manager._refresh_graph_links()
        node_ids = list(graph.node_ids)
        edges = [edge for edge in self.manager.dependency_edges if edge.id in graph.edge_ids]
        incoming = {node_id: set() for node_id in node_ids}
        outgoing = {node_id: set() for node_id in node_ids}
        for edge in edges:
            if edge.source_id in incoming and edge.target_id in incoming:
                outgoing[edge.source_id].add(edge.target_id)
                incoming[edge.target_id].add(edge.source_id)
        ready = [node_id for node_id, parents in incoming.items() if not parents]
        order = []
        while ready:
            node_id = ready.pop(0)
            order.append(node_id)
            for child_id in list(outgoing[node_id]):
                incoming[child_id].discard(node_id)
                if not incoming[child_id] and child_id not in order and child_id not in ready:
                    ready.append(child_id)
        has_cycle = len(order) != len(node_ids)
        graph.flags.cycle_detection_status = "Cycle Detected" if has_cycle else "Acyclic"
        graph.flags.evaluation_order_status = "Blocked" if has_cycle else "Computed"
        graph.pending_evaluation_ids = [node_id for node_id in node_ids if node_id not in order]
        topology = next((item for item in self.manager.dependency_topologies if item.id == graph.topology_id), None)
        if topology is not None:
            topology.evaluation_order_placeholder = list(order)
            topology.cycle_detection_status = graph.flags.cycle_detection_status
            topology.pending_evaluation_ids = list(graph.pending_evaluation_ids)
            topology.dependency_levels = {node_id: index for index, node_id in enumerate(order)}
        return order

    def propagate_dirty(self, owner, graph=None):
        """Propagate dirty state through existing dependency edges."""

        start = self.manager.dependency_manager.add_node(owner, self.manager.dependency_manager._node_type(owner), graph=graph)
        affected = []
        queue = [start.id]
        seen = set()
        while queue:
            node_id = queue.pop(0)
            if node_id in seen:
                continue
            seen.add(node_id)
            node = next((item for item in self.manager.dependency_nodes if item.id == node_id), None)
            if node is not None:
                node.dirty = True
                node.pending_evaluation = True
                affected.append(node.owner_id)
            for edge in self.manager.dependency_edges:
                if edge.source_id == node_id and edge.target_id not in seen:
                    edge.dirty = True
                    edge.pending_evaluation = True
                    queue.append(edge.target_id)
        graph_obj = self.manager.dependency_manager.graph_for(graph or start.graph_id)
        if graph_obj is not None:
            graph_obj.dirty_reference_ids = list(dict.fromkeys(graph_obj.dirty_reference_ids + affected))
            graph_obj.flags.dirty = True
            graph_obj.flags.pending_evaluation = True
        self.manager.dependency_manager.statistics()
        return affected

    def active_execution_engine(self):
        """Return the active execution engine subsystem."""

        return self.execution_engine_for(getattr(self.manager, "active_execution_engine_id", None)) or (
            self.manager.execution_engines[-1] if self.manager.execution_engines else None
        )

    def active_sketch_solver(self):
        """Return the active sketch solver subsystem."""

        return self.sketch_solver_for(getattr(self.manager, "active_sketch_solver_id", None)) or (
            self.manager.sketch_solvers[-1] if self.manager.sketch_solvers else None
        )

    def active_geometry_kernel(self):
        """Return the active GeometryKernel subsystem."""

        engine = self.active_engine()
        if engine is not None:
            for kernel_id in reversed(getattr(engine, "geometry_kernel_ids", [])):
                kernel = self.geometry_kernel_for(kernel_id)
                if kernel is not None:
                    return kernel
        return self.geometry_kernel_for(getattr(self.manager, "active_geometry_kernel_id", None)) or (
            self.manager.geometry_kernels[-1] if self.manager.geometry_kernels else None
        )

    def execution_engine_for(self, item):
        """Return an execution engine by object, id or name."""

        if isinstance(item, ExecutionEngine):
            return item if item in self.manager.execution_engines else None
        return _find_by_id_or_name(self.manager.execution_engines, item)

    def execution_session_for(self, item):
        """Return an execution session by object, id or name."""

        if isinstance(item, ExecutionSession):
            return item if item in self.manager.execution_sessions else None
        return _find_by_id_or_name(self.manager.execution_sessions, item)

    def execution_request_for(self, item):
        """Return an execution request by object, id or name."""

        if isinstance(item, ExecutionRequest):
            return item if item in self.manager.execution_requests else None
        return _find_by_id_or_name(self.manager.execution_requests, item)

    def sketch_solver_for(self, item):
        """Return a sketch solver by object, id or name."""

        if isinstance(item, SketchSolver):
            return item if item in self.manager.sketch_solvers else None
        return _find_by_id_or_name(self.manager.sketch_solvers, item)

    def sketch_solve_session_for(self, item):
        """Return a sketch solve session by object, id or name."""

        if isinstance(item, SketchSolveSession):
            return item if item in self.manager.sketch_solve_sessions else None
        return _find_by_id_or_name(self.manager.sketch_solve_sessions, item)

    def geometry_kernel_for(self, item):
        """Return a GeometryKernel by object, id or name."""

        if isinstance(item, GeometryKernel):
            return item if item in self.manager.geometry_kernels else None
        return _find_by_id_or_name(self.manager.geometry_kernels, item)

    def geometry_session_for(self, item):
        """Return a GeometrySession by object, id or name."""

        if isinstance(item, GeometrySession):
            return item if item in self.manager.geometry_sessions else None
        return _find_by_id_or_name(self.manager.geometry_sessions, item)

    def geometry_result_for(self, item):
        """Return a GeometryResult by id."""

        item_id = getattr(item, "id", item)
        return next((result for result in self.manager.geometry_results if result.id == item_id), None)

    def brep_topology_for(self, item):
        """Return BRep topology metadata by object, id or name."""

        if isinstance(item, BRepTopology):
            return item if item in self.manager.geometry_topologies else None
        return _find_by_id_or_name(self.manager.geometry_topologies, item)

    def _execution_target(self, target_id):
        collections = (
            self.manager.parameters +
            self.manager.expressions +
            self.manager.visual_nodes +
            self.manager.node_definitions
        )
        return _find_by_id_or_name(collections, target_id) or target_id

    def _execute_target(self, target, variables):
        if getattr(target, "is_expression", False):
            return self.evaluate_expression(target, variables)
        if getattr(target, "is_parametric_parameter", False) or getattr(target, "type_name", "") == "PartParameter":
            if getattr(target, "expression", ""):
                target.value = ExpressionEvaluator().evaluate(target.expression, variables)
            return getattr(target, "value", None)
        if getattr(target, "is_visual_node", False):
            definition = self.node_definition_for(getattr(target, "definition_id", ""))
            return self._execute_basic_node(target, definition, variables)
        if isinstance(target, str):
            return variables.get(target, target)
        return getattr(target, "value", None)

    def _execute_basic_node(self, node, definition, variables):
        operation = (
            getattr(getattr(definition, "metadata", None), "properties", {}).get("operation") or
            getattr(definition, "name", "") or
            getattr(node, "name", "")
        ).lower()
        props = dict(getattr(getattr(node, "metadata", None), "properties", {}))
        if "constant" in operation:
            return props.get("value", 0)
        if "variable" in operation or "parameter" in operation:
            return variables.get(props.get("name", node.name), props.get("value"))
        if "expression" in operation or "math" in operation:
            return ExpressionEvaluator().evaluate(props.get("expression", "0"), variables)
        if "logic" in operation:
            return bool(ExpressionEvaluator().evaluate(props.get("expression", "False"), variables))
        if "comparison" in operation:
            return bool(ExpressionEvaluator().evaluate(props.get("expression", "False"), variables))
        if "conditional" in operation:
            return ExpressionEvaluator().evaluate(props.get("expression", "0"), variables)
        return props.get("value")

    def create_engine(self, name="Parametric Engine", metadata=None):
        """Create a metadata-only parametric engine."""

        return self.add_item(ParametricEngine(name, metadata))

    def create_solver(self, name="Live Solver", engine=None, metadata=None):
        """Create ParametricEngine-owned live solver metadata."""

        engine = self.engine_for(engine) or self.active_engine()
        solver = LiveSolver(name, getattr(engine, "id", "") or "", metadata)
        self.add_item(solver)
        return solver

    def create_document(self, name="Parametric Document", engine=None, context=None, references=None, metadata=None):
        """Create a parametric document referencing existing product objects only."""

        engine = self.engine_for(engine) or self.active_engine()
        document = ParametricDocument(name, getattr(engine, "id", "") or "", context or ParametricContext(), metadata)
        document.reference_ids = [getattr(item, "id", item) for item in references or []]
        self.add_item(document)

        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, document, "ParametricDocumentReference")

        return document

    def create_workspace(self, name="Parametric Workspace", engine=None, document=None, metadata=None):
        """Create a parametric workspace metadata record without duplicating Workspace."""

        engine = self.engine_for(engine) or self.active_engine()
        document = self.document_for(document) or self.active_document()
        return self.add_item(ParametricWorkspace(
            name,
            getattr(engine, "id", "") or "",
            getattr(document, "id", "") or "",
            metadata,
        ))

    def create_session(self, name="Parametric Session", engine=None, document=None, context=None, references=None, metadata=None):
        """Create a parametric session for future solving workflows."""

        engine = self.engine_for(engine) or self.active_engine()
        document = self.document_for(document) or self.active_document()
        session = ParametricSession(
            name,
            getattr(engine, "id", "") or "",
            getattr(document, "id", "") or "",
            context or ParametricContext(),
            metadata,
        )
        session.reference_ids = [getattr(item, "id", item) for item in references or []]
        self.add_item(session)

        for reference in references or []:
            self.manager.dependency_manager.add_edge(reference, session, "ParametricSessionReference")

        return session

    def create_solver_session(self, name="Solver Session", solver=None, engine=None, parametric_session=None, context=None, metadata=None):
        """Create a live solver session metadata record."""

        solver = self.solver_for(solver) or self.active_solver()
        engine = self.engine_for(engine) or self.engine_for(getattr(solver, "engine_id", "")) or self.active_engine()
        parametric_session = self.session_for(parametric_session) or self.active_session()
        context = context or SolverContext(
            getattr(engine, "id", "") or "",
            parametric_session_id=getattr(parametric_session, "id", "") or "",
        )
        session = SolverSession(
            name,
            getattr(solver, "id", "") or "",
            getattr(engine, "id", "") or "",
            getattr(parametric_session, "id", "") or "",
            context,
            metadata,
        )
        self.add_item(session)
        return session

    def queue_evaluation(self, target, change_type="Parameter Changed", solver=None, solver_session=None, context=None, priority=None, group=None, batch=None, metadata=None):
        """Store an evaluation request in solver queues without evaluating it."""

        solver = self.solver_for(solver) or self.active_solver()
        solver_session = self.solver_session_for(solver_session) or (
            self.manager.solver_sessions[-1] if self.manager.solver_sessions else None
        )
        context = context or EvaluationContext(
            getattr(solver, "id", "") or "",
            getattr(solver_session, "id", "") or "",
            getattr(solver, "engine_id", "") or "",
            getattr(solver_session, "parametric_session_id", "") or "",
            parameter_ids=[getattr(target, "id", target)] if getattr(target, "is_parametric_parameter", False) else [],
            object_ids=[getattr(target, "id", target)],
        )
        flags = EvaluationFlags(dirty=True, queued=True, pending=True)
        request = EvaluationRequest(
            f"{change_type}: {getattr(target, 'name', getattr(target, 'id', target))}",
            change_type,
            getattr(target, "id", target),
            context,
            flags,
            priority or EvaluationPriority(),
            "Queued",
            getattr(group, "id", group) or "",
            getattr(batch, "id", batch) or "",
            "",
            metadata or SolverMetadata(status="Queued"),
        )
        self.add_item(request)
        return request

    def add_evaluation_result(self, request, state="Pending", message="", affected=None, metadata=None):
        """Store evaluation result metadata without computing values."""

        request_id = getattr(request, "id", request)
        result = EvaluationResult(
            request_id,
            state,
            message,
            [getattr(item, "id", item) for item in affected or []],
            [],
            [],
            EvaluationFlags(pending=(state == "Pending"), completed=(state == "Completed"), failed=(state == "Failed"), blocked=(state == "Blocked")),
            metadata or SolverMetadata(status=state),
        )
        self.add_item(result)
        return result

