    def create_data_branch(self, tree, name="Data Branch", parent_branch=None, branch_identifier="", metadata=None):
        """Create metadata-only data branch."""

        tree = self.data_tree_for(tree)
        parent = self.data_branch_for(parent_branch)
        branch = DataBranch(name, getattr(tree, "id", "") or "", getattr(parent, "id", "") or "", branch_identifier, metadata)
        if parent is not None:
            branch.depth = getattr(parent, "depth", 0) + 1
            branch.index = len(getattr(parent, "child_branch_ids", []))
        self.add_item(branch)
        return branch

    def create_data_path(self, tree, branch=None, name="Data Path", segments=None, metadata=None):
        """Create metadata-only data path."""

        tree = self.data_tree_for(tree)
        branch = self.data_branch_for(branch)
        path = DataPath(name, getattr(tree, "id", "") or "", getattr(branch, "id", "") or "", segments or [], metadata)
        self.add_item(path)
        return path

    def create_data_item(self, tree, branch=None, path=None, name="Data Item", data_type="Any", references=None, metadata=None):
        """Create metadata-only data item that stores references only."""

        tree = self.data_tree_for(tree)
        branch = self.data_branch_for(branch)
        path = self.data_path_for(path)
        item = DataItem(name, getattr(tree, "id", "") or "", getattr(branch, "id", "") or "", getattr(path, "id", "") or "", "", data_type, metadata)
        for attr, target in (references or {}).items():
            if hasattr(item, attr):
                setattr(item, attr, getattr(target, "id", None) or getattr(target, "name", None) or target or "")
        self.add_item(item)
        return item

