        tree = self.data_tree_for(tree)
        branch = self.data_branch_for(branch)
        container = DataContainer(name, getattr(tree, "id", "") or "", getattr(branch, "id", "") or "", metadata)
        container.item_ids = [getattr(item, "id", item) for item in items or []]
        self.add_item(container)
