    def statistics(self):
        """Return parametric engine foundation statistics."""

        stats = ParametricStatistics(
            len(self.manager.parametric_engines),
            len(self.manager.parametric_documents),
            len(self.manager.parametric_workspaces),
            len(self.manager.parametric_sessions),
            len(self.manager.parametric_contexts),
            sum(len(getattr(item, "reference_ids", [])) for item in self.manager.parametric_documents + self.manager.parametric_sessions),
            len([item for item in self.manager.parametric_sessions if getattr(item.dirty_state, "dirty", False)]),
            len([item for item in self.manager.parametric_sessions if getattr(item.freeze_state, "frozen", False)]),
        )
        self.manager.parametric_statistics = stats
        self._solver_statistics()
        self._evaluation_statistics()
        self._visual_node_graph_statistics()
        self._data_tree_statistics()
        self._cad_node_statistics()
        self._bim_node_statistics()
        self._manufacturing_node_statistics()
        self._ai_node_statistics()
        self._script_node_statistics()
        self._preview_statistics()
        self._execution_statistics()
        self._sketch_solver_statistics()
        self._geometry_statistics()
        return stats

