    def simulation_jobs_for_slice_job(self, slice_job):
        """Return simulation jobs assigned to a slice job."""

        return self.simulation_manager.jobs_for_slice_job(slice_job)

    def tools_for_library(self, library):
        """Return tools assigned to a CAM tool library."""

        return self.tool_library_manager.tools_for_library(library)

    def tools_for_category(self, category):
        """Return tools assigned to a CAM tool category."""

        return self.tool_library_manager.tools_for_category(category)

    def holders_for_library(self, library):
        """Return holders assigned to a CAM tool library."""

        return self.holder_manager.holders_for_library(library)

    def mesh_entity_for_body(self, body, workspace=None):
        """Return the existing MeshEntity referenced by a body."""

        target = self.body_for(body) or self.surface_body_for(body)

        if target is None or workspace is None:
            return None

        scene = getattr(workspace, "scene3d", None)

        if scene is None:
            return None

        for entity in scene.entities():
            entity_id = getattr(entity, "id", None)
            if entity_id and entity_id == target.mesh_entity_id:
                return entity
            if getattr(entity, "name", None) == target.mesh_entity_id:
                return entity

        return None

    def visible_parts(self):
        """Return visible product parts."""

        if not self.visible:
            return []

        return [part for part in self.parts if getattr(part, "visible", True)]

    def visible_components(self):
        """Return visible component metadata."""

        if not self.visible:
            return []

        return [component for component in self.components if getattr(component, "visible", True)]

    def visible_objects(self):
        """Return visible Product Design objects for selection and rendering."""

        return (
            self.visible_parts() +
            self.visible_components() +
            self.parameter_manager.visible_objects() +
            self.sketch_manager.visible_objects() +
            self.feature_manager.visible_objects() +
            self.body_manager.visible_objects() +
            self.dependency_manager.visible_objects() +
            self.surface_manager.visible_objects() +
            self.curve_manager.visible_objects() +
            self.reference_geometry_manager.visible_objects() +
            self.construction_geometry_manager.visible_objects() +
            self.assembly_manager.visible_objects() +
            self.mate_manager.visible_objects() +
            self.exploded_view_manager.visible_objects() +
            self.mechanical_library_manager.visible_objects() +
            self.sheet_metal_manager.visible_objects() +
            self.validation_manager.visible_objects() +
            self.analysis_manager.visible_objects() +
            self.manufacturing_validation_manager.visible_objects() +
            self.product_report_manager.visible_objects() +
            self.cam_manager.visible_objects() +
            self.three_axis_operation_manager.visible_objects() +
            self.laser_plasma_manager.visible_objects() +
            self.router_manager.visible_objects() +
            self.post_processor_manager.visible_objects() +
            self.machine_library_manager.visible_objects() +
            self.slicer_manager.visible_objects() +
            self.simulation_manager.visible_objects() +
            self.nesting_manager.visible_objects() +
            self.manufacturing_job_manager.visible_objects() +
            self.parametric_manager.visible_objects() +
            self.tool_library_manager.visible_objects()
        )

    def statistics(self):
        """Return current product statistics."""

        stats = ProductStatistics(
            len(self.documents),
            len(self.parts),
            len(self.components),
            len(self.component_types),
            len(self.component_categories),
            len(self.parameters),
            len(self.parameter_sets),
            len(self.engineering_materials),
            len(self.material_categories),
            len(self.sketches),
            len(self.sketch_geometry),
            len(self.sketch_constraints),
            len(self.sketch_dimensions),
            len(self.features),
            len(self.bodies),
        )
        self.statistics_data = stats
        self.parameter_manager.statistics()
        self.engineering_material_manager.statistics()
        self.sketch_manager.statistics()
        self.constraint_manager.statistics()
