    def relink_scene_entities(self, entities):
        """Relink product parts to existing scene geometry by persisted ID or name."""

        by_id = {}

        for entity in entities:
            entity_id = getattr(entity, "id", None)

            if entity_id:
                by_id[entity_id] = entity

            by_id[getattr(entity, "name", "")] = entity

        for part in self.parts:
            part.entity = (
                by_id.get(part.mesh_entity_id) or
                by_id.get(part.mesh_entity_name)
            )

