def _sketch_geometry_from_data(data):
    data = data or {}
    points = [_vector_from_data(point) for point in data.get("points", [])]
    class_name = data.get("class", "SketchGeometry")
    sketch_id = data.get("sketch_id", "")
    name = data.get("name", class_name)
    construction = bool(data.get("construction", False))
    geometry_class = {
        "SketchPoint": SketchPoint,
        "SketchLine": SketchLine,
        "SketchArc": SketchArc,
        "SketchCircle": SketchCircle,
        "SketchEllipse": SketchEllipse,
        "SketchSpline": SketchSpline,
        "SketchPolyline": SketchPolyline,
        "SketchRectangle": SketchRectangle,
        "SketchPolygon": SketchPolygon,
        "ConstructionGeometry": ConstructionGeometry,
        "Centerline": Centerline,
        "ConstructionPoint": ConstructionPoint,
        "ConstructionCircle": ConstructionCircle,
        "ConstructionArc": ConstructionArc,
    }.get(class_name, SketchGeometry)

    if geometry_class is SketchPoint:
        item = SketchPoint(name, sketch_id, points[0] if points else None, construction)
    elif geometry_class is SketchLine:
        item = SketchLine(name, sketch_id, points[0] if points else None, points[1] if len(points) > 1 else None, construction)
    elif geometry_class is SketchArc:
        item = SketchArc(
            name,
            sketch_id,
            points[0] if points else None,
            points[1] if len(points) > 1 else None,
            points[2] if len(points) > 2 else None,
            construction,
        )
    elif geometry_class is SketchCircle:
        item = SketchCircle(name, sketch_id, points[0] if points else None, float(data.get("radius", 1.0)), construction)
    elif geometry_class is SketchEllipse:
        item = SketchEllipse(
            name,
            sketch_id,
            points[0] if points else None,
            float(data.get("radius_x", 1.0)),
            float(data.get("radius_y", 0.5)),
            construction,
        )
    elif geometry_class is SketchSpline:
        item = SketchSpline(name, sketch_id, points, construction)
    elif geometry_class is SketchPolyline:
        item = SketchPolyline(name, sketch_id, points, bool(data.get("closed", False)), construction)
    elif geometry_class is SketchRectangle:
        item = SketchRectangle(
            name,
            sketch_id,
            points[0] if points else None,
            points[2] if len(points) > 2 else None,
            construction,
        )
    elif geometry_class is SketchPolygon:
        item = SketchPolygon(name, sketch_id, points, int(data.get("sides", 6)), construction)
    elif geometry_class is ConstructionGeometry:
        item = ConstructionGeometry(name, sketch_id, points)
    elif geometry_class is Centerline:
        item = Centerline(name, sketch_id, points[0] if points else None, points[1] if len(points) > 1 else None)
    elif geometry_class is ConstructionPoint:
        item = ConstructionPoint(name, sketch_id, points[0] if points else None)
    elif geometry_class is ConstructionCircle:
        item = ConstructionCircle(name, sketch_id, points[0] if points else None, float(data.get("radius", 1.0)))
    elif geometry_class is ConstructionArc:
        item = ConstructionArc(
            name,
            sketch_id,
            points[0] if points else None,
            points[1] if len(points) > 1 else None,
            points[2] if len(points) > 2 else None,
        )
    else:
        item = SketchGeometry(name, sketch_id, points, construction)

    _restore_product_marker(item, data)
    item.points_data = points
    item.centerline = bool(data.get("centerline", getattr(item, "centerline", False)))
    item.display_color = data.get("display_color", item.display_color)

    return item


def _feature_from_data(data):
    data = data or {}
    feature_class = {
        "ExtrudeFeature": ExtrudeFeature,
        "RevolveFeature": RevolveFeature,
        "SweepFeature": SweepFeature,
        "LoftFeature": LoftFeature,
        "ThinFeature": ThinFeature,
        "FilletFeature": FilletFeature,
        "ChamferFeature": ChamferFeature,
        "PatternFeature": PatternFeature,
        "SurfaceFeature": SurfaceFeature,
        "LoftSurfaceFeature": LoftSurfaceFeature,
        "SweepSurfaceFeature": SweepSurfaceFeature,
        "BoundarySurfaceFeature": BoundarySurfaceFeature,
        "RuledSurfaceFeature": RuledSurfaceFeature,
        "OffsetSurfaceFeature": OffsetSurfaceFeature,
        "FillSurfaceFeature": FillSurfaceFeature,
        "TrimSurfaceFeature": TrimSurfaceFeature,
        "ExtendSurfaceFeature": ExtendSurfaceFeature,
        "KnitSurfaceFeature": KnitSurfaceFeature,
        "SplitSurfaceFeature": SplitSurfaceFeature,
        "SolidFeature": SolidFeature,
    }.get(data.get("class", "SolidFeature"), SolidFeature)

    args = (
        data.get("name", data.get("feature_type", "Feature")),
        data.get("part_id", ""),
        FeatureDefinition.from_dict(data.get("definition", {})),
        FeatureMetadata.from_dict(data.get("metadata", {})),
        FeatureResult.from_dict(data.get("result", {})),
    )

    if feature_class is PatternFeature:
        feature = feature_class(
            *args,
            PatternDefinition.from_dict(data.get("pattern_definition", {})),
            PatternMetadata.from_dict(data.get("pattern_metadata", {})),
        )
    elif issubclass(feature_class, SurfaceFeature):
        feature = feature_class(
            *args,
            SurfaceFeatureDefinition.from_dict(data.get("surface_definition", {})),
            SurfaceFeatureResult.from_dict(data.get("surface_result", {})),
        )
    else:
        feature = feature_class(*args)
    _restore_product_marker(feature, data)
    feature.suppressed = bool(data.get("suppressed", False))
    feature.order = int(data.get("order", 0))
    feature.execution_state = FeatureExecutionState.from_dict(data.get("execution_state", {}))
    feature.execution_metadata = FeatureExecutionMetadata.from_dict(data.get("execution_metadata", {}))
    feature.diagnostics = FeatureDiagnostics.from_dict(data.get("diagnostics", {}))
    feature.display_color = data.get("display_color", "#ffcc80")
    feature.location = _vector_from_data(data.get("location", {}))

    return feature


def _curve_from_data(data):
    data = data or {}
    curve_class = {
        "ProductCurve": ProductCurve,
        "SplineCurve": SplineCurve,
        "BezierCurve": BezierCurve,
        "NURBSCurve": NURBSCurve,
        "PolylineCurve": PolylineCurve,
        "CompositeCurve": CompositeCurve,
        "HelixCurve": HelixCurve,
        "SpiralCurve": SpiralCurve,
        "IntersectionCurve": IntersectionCurve,
        "ProjectedCurve": ProjectedCurve,
    }.get(data.get("class", "ProductCurve"), ProductCurve)
    curve = curve_class(
        data.get("name", data.get("curve_type", "Curve")),
        data.get("part_id", ""),
        CurveDefinition.from_dict(data.get("definition", {})),
        CurveMetadata.from_dict(data.get("metadata", {})),
        _vector_from_data(data.get("location", {})),
    )
    _restore_product_marker(curve, data)
    curve.display_color = data.get("display_color", "#ce93d8")
    return curve


def _reference_geometry_from_data(data):
    data = data or {}
    reference_class = {
        "ReferenceGeometry": ReferenceGeometry,
        "ReferencePlane": ReferencePlane,
        "ReferenceAxis": ReferenceAxis,
        "ReferencePoint": ReferencePoint,
        "ReferenceCoordinateSystem": ReferenceCoordinateSystem,
        "ReferenceGeometryGroup": ReferenceGeometryGroup,
    }.get(data.get("class", "ReferenceGeometry"), ReferenceGeometry)
    reference = reference_class(
        data.get("name", data.get("reference_type", "Reference Geometry")),
        data.get("part_id", ""),
        list(data.get("target_ids", [])),
        ReferenceGeometryMetadata.from_dict(data.get("metadata", {})),
        _vector_from_data(data.get("location", {})),
        _vector_from_data(data.get("direction", {"x": 1.0})),
    )
    _restore_product_marker(reference, data)
    reference.display_color = data.get("display_color", "#ffe082")
    return reference


def _construction_reference_from_data(data):
    data = data or {}
    construction_class = {
        "ProductConstructionGeometry": ProductConstructionGeometry,
        "ConstructionPlane": ConstructionPlane,
        "ConstructionAxis": ConstructionAxis,
        "ConstructionPoint": ProductConstructionPoint,
        "ProductConstructionPoint": ProductConstructionPoint,
        "ConstructionSketchReference": ConstructionSketchReference,
    }.get(data.get("class", "ProductConstructionGeometry"), ProductConstructionGeometry)
    construction = construction_class(
        data.get("name", data.get("construction_type", "Construction")),
        data.get("part_id", ""),
        list(data.get("reference_ids", [])),
        ConstructionMetadata.from_dict(data.get("metadata", {})),
        _vector_from_data(data.get("location", {})),
        _vector_from_data(data.get("direction", {"x": 1.0})),
    )
    _restore_product_marker(construction, data)
    construction.display_color = data.get("display_color", "#b0bec5")
    return construction


def _restore_product_marker(marker, data):
    marker.id = data.get("id", marker.id)
    marker.visible = bool(data.get("visible", True))
    marker.locked = bool(data.get("locked", False))
    marker.selected = bool(data.get("selected", False))
    marker.layer_name = data.get("layer_name", "0")


def _find_by_id(items, identifier):
    for item in items:
        if getattr(item, "id", None) == identifier:
            return item

    return None


def _find_by_id_or_name(items, identifier):
    for item in items:
        if item is identifier:
            return item
        if getattr(item, "id", None) == identifier or getattr(item, "name", None) == identifier:
            return item

    return None


def _vector_to_data(point):
    return {"x": point.x, "y": point.y, "z": point.z}


def _vector_from_data(data):
    data = data or {}

    return Vector3(
        float(data.get("x", 0.0)),
        float(data.get("y", 0.0)),
        float(data.get("z", 0.0)),
    )
